        /// <summary>
        /// Get case name
        /// </summary>
        /// <returns></returns>
        [AuthLog(Roles = "Firm,User")]
        public ActionResult SaveLimitationCase()
        {
            var token = QueryAES.UrlDecode(Request.Form["token"]);
            try
            {
                token = token.Replace(" ", "+");
                token = QueryAES.DecryptAes(QueryAES.FromBase64StringWithReplace(token));
            }
            catch
            {
            }
            var dname = db1.usp_getcasename(LoggedInUser.FirmId.ToString(), token).FirstOrDefault();
            ViewBag.casename = dname;
            ViewBag.token = token;
            ViewBag.pagesize = System.Configuration.ConfigurationManager.AppSettings["pagesize"];
            return View();
        }
        [AuthLog(Roles = "Firm,User")]
        public ActionResult LimitationCalendar()
        {
