        /// <summary>
        /// Get court year details
        /// </summary>
        /// <param name="crtid"></param>
        /// <returns></returns>
        [FirmControllerAuthorization]
        [HttpPost]
        public JsonResult AddCaseYear(string crtid = "")
        {
            var db = new LawPracticeEntities();
            try
            {
                string caseyr = db.sp_GetCourtYearlawPractice(crtid).FirstOrDefault().ToString();
                var clist = (from ob in caseyr select new { caseyear = caseyr }).Distinct().OrderBy(x => x.caseyear).ToList();
                return Json(clist, JsonRequestBehavior.AllowGet);
            }
            catch (Exception ex)
            {
                db1.usp_AddAudit(Convert.ToInt32(EventType.Contact), Convert.ToInt32(Severity.High), Convert.ToInt32(REQUEST_TYPE.API), Convert.ToString(EventType.Contact), Convert.ToString(Severity.High), Convert.ToString(REQUEST_TYPE.API), null, "Message=" + ex.Message + "@Inner Exception=" + ex.InnerException + "@Stack Trace=" + ex.StackTrace, myIP(), GetMacAddress().ToString(), 1, "");
                return Json(new { Result = "ERROR IN UPDATING STATUS", Message = "ERROR" }, JsonRequestBehavior.AllowGet);
            }
        }
        /// <summary>
        /// Check pack detail by firm code
        /// </summary>
        /// <returns></returns>
        public ActionResult Home()
        {
            var db = new LawPracticeEntities();
            Uri uri = new UriBuilder(Request.Url.AbsoluteUri).Uri;
            var firmcodes = uri.Segments[1];
            ViewBag.firmcodes = firmcodes;
            var ct = db.usp_checkpackhome(firmcodes).FirstOrDefault();
            if (ct != 3)
            {
                return Redirect("~/");
            }
            return View();
        }
