        /// <summary>
        /// Get firm authentication details
        /// </summary>
        /// <returns></returns>
        [AuthLog(Roles = "Firm,User,Client")]
        [OutputCache(Duration = 300, VaryByParam = "name")]
        public ActionResult AuthenticateFirm()
        {
            string firmcode = Request.Url.Segments[1];
            string firmcodes = firmcode.Replace("/", "");
            var dbfirmcode = db.Firms.Where(x => x.FirmCode == firmcodes).Select(x => new { x.FirmCode }).FirstOrDefault();
            if (dbfirmcode != null)
            {
                if (dbfirmcode.FirmCode.ToUpper().ToString() == LoggedInUser.FirmCode.ToUpper().ToString())
                {
                }
                else
                {
                    try
                    {
                        RemoveSession(System.Web.HttpContext.Current);
                        Session.Clear();
                        Session.Abandon();
                        Session["sessionfirmid"] = "";
                        Session["sessionuserid"] = "";
                    }
                    catch (Exception ex)
                    {
                        db1.usp_AddAuditError(Convert.ToInt32(EventType.Logout), Convert.ToInt32(Severity.High), Convert.ToInt32(REQUEST_TYPE.API), Convert.ToString(EventType.Logout), Convert.ToString(Severity.High), Convert.ToString(REQUEST_TYPE.API), null, "Message=" + ex.Message + "@Inner Exception=" + ex.InnerException + "@Stack Trace=" + ex.StackTrace, myIP(), GetMacAddress().ToString(), 1, "");
                    }
                    return RedirectToAction("~/home/NotFound");
                }
            }
            else
            {
                try
                {
                    RemoveSession(System.Web.HttpContext.Current);
                    Session.Clear();
                    Session.Abandon();
                    Session["sessionfirmid"] = "";
                    Session["sessionuserid"] = "";
                }
                catch (Exception ex)
                {
                    db1.usp_AddAuditError(Convert.ToInt32(EventType.Logout), Convert.ToInt32(Severity.High), Convert.ToInt32(REQUEST_TYPE.API), Convert.ToString(EventType.Logout), Convert.ToString(Severity.High), Convert.ToString(REQUEST_TYPE.API), null, "Message=" + ex.Message + "@Inner Exception=" + ex.InnerException + "@Stack Trace=" + ex.StackTrace, myIP(), GetMacAddress().ToString(), 1, "");
                }
                return RedirectToAction("~/home/NotFound");
            }
            return View();
        }
