        /// <summary>
        /// Compose New  Message Full Sreen
        /// </summary>
        /// <returns></returns>
        [AuthLog(Roles = "Firm,User,Client")]
        public ActionResult ComposeNewMessage()
        {
            ViewBag.filesize = ConfigurationManager.AppSettings["filesizemultiple"];
            try
            {
                if (LoggedInUser.RoleId == 3)
                {
                    var user = LoggedInUser.FirmId;
                    var composetolist = db.usp_GetClientComposeToList(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString(), Convert.ToInt32(LoggedInUser.RoleId)).ToList();
                    ViewBag.Fruits = composetolist.OrderBy(x => x.label).ToList();
                }
                else if (LoggedInUser.RoleId == 2)
                {
                    var user = LoggedInUser.FirmId;
                    int pageid = 0;
                    var pagelist = db.usp_GetRightsPageDatabyPagelink(Convert.ToString("ClientMessaging")).FirstOrDefault();
                    if (pagelist != null)
                    {
                        pageid = Convert.ToInt32(pagelist.ParentPage);
                    }
                    var trialList_1 = db.usp_GetMessageUserlist(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString(), pageid.ToString()).ToList();
                    var trialList = (from ob in trialList_1
                                     select new
                                     {
                                         label = ((ob.PartnerId == "" || ob.PartnerId == null || ob.PartnerId == "null") ? ob.UserName + " -(" + ob.RoleName + ")" : (ob.PartnerId.ToString().ToLower() == LoggedInUser.UserId.ToString().ToLower() ? ob.UserName + "-(" + ob.RoleName + ")" : ob.UserName + " - (" + ob.RoleName + " " + ob.PartnerName + ")")),
                                         val = ob.Id,
                                         //roleid = ob.roleid,
                                         role = ob.RoleName,
                                         Partnerid = ob.PartnerId
                                     }).OrderBy(x => x.label).ToList();
                    var firmusers1 = (from c in db.MessageGroups
                                      where c.Firmid.ToString() == user.ToString()
                                      select new
                                      {
                                          label = c.Groupname + "-(Group)",
                                          val = c.Id,
                                          //roleid = 0,
                                          role = "",
                                          Partnerid = ""
                                      }).OrderBy(x => x.label).ToList();
                    var list = trialList.Concat(firmusers1).ToList();
                    ViewBag.Fruits = list;
                }
                else
                {
                    var user = LoggedInUser.FirmId;
                    var trialList_1 = db.usp_GetcomposemeessageUser(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString(), Convert.ToInt32(LoggedInUser.RoleId)).ToList();
                    var firmusers = (from ob in trialList_1
                                     select new
                                     {
                                         label = ((ob.PartnerId == "" || ob.PartnerId == null || ob.PartnerId == "null") ? ob.UserName + " -(" + ob.RoleName + ")" : (ob.PartnerId.ToString().ToLower() == LoggedInUser.UserId.ToString().ToLower() ? ob.UserName + "-(" + ob.RoleName + ")" : ob.UserName + " - (" + ob.RoleName + " " + ob.PartnerName + ")")),
                                         val = ob.id,
                                         //roleid = ob.roleid,
                                         role = ob.RoleName,
                                         Partnerid = ob.PartnerId
                                     }).OrderBy(x => x.label).ToList();
                    var firmusers1 = (from c in db.MessageGroups
                                      where c.Firmid.ToString() == user.ToString()
                                       && c.Groupname.Trim() != ""
                                      select new
                                      {
                                          label = c.Groupname + "-(Group)",
                                          val = c.Id,
                                          //roleid = 0,
                                          role = "",
                                          Partnerid = ""
                                      }).OrderBy(x => x.label).ToList();
                    var list = firmusers.Concat(firmusers1).ToList();
                    ViewBag.Fruits = list;
                }
            }
            catch (Exception ex)
            {
                db1.usp_AddAuditError(Convert.ToInt32(EventType.Firm), Convert.ToInt32(Severity.High), Convert.ToInt32(REQUEST_TYPE.API), Convert.ToString(EventType.Firm), Convert.ToString(Severity.High), Convert.ToString(REQUEST_TYPE.API), null, "Message=" + ex.Message + "@Inner Exception=" + ex.InnerException + "@Stack Trace=" + ex.StackTrace, myIP(), GetMacAddress().ToString(), 1, "");
            }
            return View();
        }

