        /// <summary>
        /// View Timer
        /// </summary>
        /// <returns></returns>
        [AuthLog(Roles = "Firm,User")]
        public ActionResult ViewTimer()
        {
            ViewBag.pagesize = System.Configuration.ConfigurationManager.AppSettings["pagesize"];
            bool isRBI = LoggedInUser.FirmId.ToString().ToUpper() == ConfigurationManager.AppSettings["RBICustomization"].ToUpper();
            ViewBag.RBICustomtype = isRBI ? "RBICustomtype" : "";
            if (LoggedInUser.RoleId == 2 && !isRBI)
            {
                ViewBag.IsCreate = 0;
                ViewBag.IsEdit = 0;
                ViewBag.IsDelete = 0;
                ViewBag.export = 0;
                ViewBag.share = 0;
                ViewBag.enable = 0;
                var data = checkroles();
                string[] values = data.Split(',');
                for (int i = 0; i < values.Length; i++)
                {
                    if (i == 0)
                    {
                        ViewBag.IsCreate = values[i];
                    }
                    if (i == 1)
                    {
                        ViewBag.IsEdit = values[i];
                    }
                    if (i == 2)
                    {
                        ViewBag.IsDelete = values[i];
                    }
                    if (i == 3)
                    {
                        ViewBag.export = values[i];
                    }
                    if (i == 5)
                    {
                        ViewBag.share = values[i];
                    }
                    if (i == 6)
                    {
                        ViewBag.enable = values[i];
                    }
                }
            }
            return View();
        }
        /// <summary>
        /// View message body
        /// </summary>
        /// <returns></returns>
        [AuthLog(Roles = "Firm")]
        public ActionResult ViewMessageBody()
        {
            try
            {
                var id = Request.Url.Segments[3];
                var db = new LawPracticeEntities();
                var data = (from c in db.MessageLists
                            join d in db.FirmUsers on c.userid.ToString() equals d.Id.ToString()
                            where c.mid.ToString() == id.ToString() && c.Firmid.ToString() == LoggedInUser.FirmId.ToString()
                            select new
                            {
                                c.mbody,
                                c.msubject,
                                c.date_time,
                                d.UserName,
                                c.mfile
                            }).FirstOrDefault();
                ViewBag.subject = data.msubject;
                ViewBag.body = HttpUtility.HtmlDecode(data.mbody);
                ViewBag.date = data.date_time;
                ViewBag.from = data.UserName;
                ViewBag.mfile = data.mfile;
            }
            catch (Exception ex)
            {
                db1.usp_AddAuditError(Convert.ToInt32(EventType.Firm), Convert.ToInt32(Severity.High), Convert.ToInt32(REQUEST_TYPE.API), Convert.ToString(EventType.Firm), Convert.ToString(Severity.High), Convert.ToString(REQUEST_TYPE.API), null, "Message=" + ex.Message + "@Inner Exception=" + ex.InnerException + "@Stack Trace=" + ex.StackTrace, myIP(), GetMacAddress().ToString(), 1, "");
            }
            return View();
        }

        /// <summary>
        /// Single view matter
        /// </summary>
        /// <param name="id"></param>
        /// <returns></returns>
        [AuthLog(Roles = "Firm")]
        public ActionResult MatterSingleView(string id)
        {
            try
            {
                var typeid = QueryAES.UrlDecode(Request.Form["token"]);
                ViewBag.token = typeid;
                typeid = QueryAES.DecryptAes(QueryAES.FromBase64StringWithReplace(typeid));
                var db = new LawPracticeEntities();
                var data = db.tbl_notification.Where(x => x.typeid.ToString() == typeid.ToString() && x.Firmid.ToString() == LoggedInUser.FirmId.ToString() && x.auser.ToString() == LoggedInUser.UserId.ToString() && x.nmode == null).FirstOrDefault();
                if (data != null)
                {
                    data.status = 1;
                    db.Entry(data).State = EntityState.Modified;
                    db.SaveChanges();
                }
            }
            catch (Exception ex)
            {
                db1.usp_AddAuditError(Convert.ToInt32(EventType.Firm), Convert.ToInt32(Severity.High), Convert.ToInt32(REQUEST_TYPE.API), Convert.ToString(EventType.Firm), Convert.ToString(Severity.High), Convert.ToString(REQUEST_TYPE.API), null, "Message=" + ex.Message + "@Inner Exception=" + ex.InnerException + "@Stack Trace=" + ex.StackTrace, myIP(), GetMacAddress().ToString(), 1, "");
            }
            ViewBag.aid = id;
            return View(id);
        }
        /// <summary>
        /// Edit single matter by matter id
        /// </summary>
        /// <param name="id"></param>
        /// <returns></returns>
        [AuthLog(Roles = "Firm")]
        public ActionResult MatterSingleEdit(string id)
        {
            var typeid = QueryAES.UrlDecode(Request.Form["token"]);
            ViewBag.token = typeid;
            ViewBag.aid = id;
            ViewBag.filesize = ConfigurationManager.AppSettings["filesize"];
            LawPracticeEntities db = new LawPracticeEntities();
            var checkmodule = db.usp_Getfimpack(LoggedInUser.FirmId.ToString()).FirstOrDefault();
            if (checkmodule != null)
            {
                ViewBag.Module = checkmodule.Value;
            }
            var user = LoggedInUser.FirmId;
            var firmusers = (from c in db.FirmUsers
                             join d in db.Roles on c.RoleId equals d.ID
                             where c.Firmid.ToString() == user.ToString() && c.IsActive == true && (c.RoleId == 1 || c.RoleId == 2)
                             select new
                             {
                                 label = c.UserName + " -( " + d.RoleName + " )",
                                 val = c.Id,
                                 roleid = c.RoleId,
                                 role = d.RoleName
                             }).ToList();
            ViewBag.Users = firmusers;
            var tfind = db.ConfigurationTypes.Where(x => x.Type == "matter").FirstOrDefault();
            if (tfind != null)
            {
                var types = tfind.Id;
                ViewBag.type = types;
                return View(id);
            }
            else
            {
                return View(id);
            }
        }
