        /// <summary>
        /// Get cause list case details
        /// </summary>
        /// <returns></returns>
        [FirmApiAuthorization]
        [ValidateInput(false)]
        public ActionResult CaseCauseList()
        {
            // Get query string parameters (URL-encoded)
            var strdt = Request.QueryString["id"];
            var Isrrara = Request.QueryString["isRera"];
            var courtTypeId = Request.QueryString["courtTypeId"];
            var courtName = Request.QueryString["courtName"];
            var janpadName = Request.QueryString["janpadName"];
            var tahsilName = Request.QueryString["tahsilName"];
            var caseNo = Request.QueryString["caseNo"];
            var vJudCourt = Request.QueryString["vJudCourt"];

            // Decode with UTF-8 encoding to handle Hindi (Devanagari) text properly
            strdt = !string.IsNullOrWhiteSpace(strdt)
                ? HttpUtility.UrlDecode(strdt, System.Text.Encoding.UTF8)
                : string.Empty;

            Isrrara = !string.IsNullOrWhiteSpace(Isrrara)
                ? HttpUtility.UrlDecode(Isrrara, System.Text.Encoding.UTF8)
                : string.Empty;

            courtTypeId = !string.IsNullOrWhiteSpace(courtTypeId)
                ? HttpUtility.UrlDecode(courtTypeId, System.Text.Encoding.UTF8)
                : string.Empty;

            // Decode Hindi text parameters
            courtName = !string.IsNullOrWhiteSpace(courtName)
                ? HttpUtility.UrlDecode(courtName, System.Text.Encoding.UTF8)
                : string.Empty;

            janpadName = !string.IsNullOrWhiteSpace(janpadName)
                ? HttpUtility.UrlDecode(janpadName, System.Text.Encoding.UTF8)
                : string.Empty;

            tahsilName = !string.IsNullOrWhiteSpace(tahsilName)
                ? HttpUtility.UrlDecode(tahsilName, System.Text.Encoding.UTF8)
                : string.Empty;

            caseNo = !string.IsNullOrWhiteSpace(caseNo)
                ? HttpUtility.UrlDecode(caseNo, System.Text.Encoding.UTF8)
                : string.Empty;

            vJudCourt = !string.IsNullOrWhiteSpace(vJudCourt)
                ? HttpUtility.UrlDecode(vJudCourt, System.Text.Encoding.UTF8)
                : string.Empty;

            // Assign to ViewBag
            ViewBag.token = strdt;
            ViewBag.IsRera = Isrrara;
            ViewBag.CourtTypeId = courtTypeId;
            ViewBag.courtName = courtName;
            ViewBag.janpadName = janpadName;
            ViewBag.tahsilName = tahsilName;
            ViewBag.caseNo = caseNo;
            ViewBag.vJudCourt = vJudCourt;

            return View();
        }
        /// <summary>
        /// Get OCR file list details
        /// </summary>
        /// <returns></returns>
        [AuthLog(Roles = "Firm,User,Client")]
        public ActionResult OcrFileList()
        {
            var strdt = QueryAES.UrlDecode(Request.QueryString["token"]);
            var docname = QueryAES.UrlDecode(Request.QueryString["docname"]);
            var userid = "";
            var firmid = LoggedInUser.FirmId;
            var fid = strdt.ToString().Replace(" ", "+");
            fid = QueryAES.DecryptAes(QueryAES.FromBase64StringWithReplace(fid.ToString()));
            var eventpath = "Documents/Ocrdocuments";
            var userids = db.Tbl_OcrFile.Where(x => x.Id.ToString() == fid.ToString()).FirstOrDefault();
            if (userids != null)
            {
                userid = userids.userid.ToString();
            }
            var downloadpath1 = "/" + eventpath + "/" + firmid + "/" + userid + "/" + docname;
            //create temp file 
            var dupeventpath = "TempDocuments/textcontent";
            string downloadpath2 = "/" + dupeventpath + "/" + firmid + "/" + userid + "/";
            string tempflname = "qwsr21ssds" + docname;
            string input = Server.MapPath(downloadpath1);
            string output = Server.MapPath(downloadpath2 + tempflname);
            if (!Directory.Exists(Server.MapPath("~/" + downloadpath2)))
            {
                Directory.CreateDirectory(Server.MapPath("~/" + downloadpath2));
            }
            try
            {
                QueryAES.FileDecrypt(input, output);
            }
            catch (Exception er)
            {
            }
            ViewBag.filepath = downloadpath2 + tempflname;
            ViewBag.token = strdt;
            return View();
        }
