        [AuthLog(Roles = "Firm,User")]
        public ActionResult CreateUser()
        {

            //Check Stf Rights or not
            try
            {
                string firmid = LoggedInUser.FirmId.ToString();
                string roleId = LoggedInUser.RoleId.ToString();
                //var data = db.sp_Get_STF_Permission(firmid).FirstOrDefault();
                //f (data > 0)
                string stfpermission = System.Configuration.ConfigurationManager.AppSettings["StfModulePermission"];
                if (stfpermission.ToLower() == LoggedInUser.FirmId.ToString().ToLower())
                {
                    ViewBag.stfUser = 1;
                    if (roleId.Equals("2"))
                    {
                        ViewBag.stfUserRole = 2;
                    }
                    else
                    {
                        ViewBag.stfUserRole = 0;

                    }

                }
                else
                {
                    ViewBag.stfUser = 0;
                    ViewBag.stfUserRole = 0;


                }
            }
            catch (Exception ex)
            {
            }
            ViewBag.filesize = ConfigurationManager.AppSettings["filesize"];

            // Hierarchy Feature - 6-level (CP/Zonal/Range/District/Sub-District/Police Station)
            if (LoggedInUser.FirmId.ToString().ToUpper() == ConfigurationManager.AppSettings["HierarchyFirmId"].ToUpper())
            {
                ViewBag.HierarchyCustomtype = "HierarchyCustomtype";
                ViewBag.UserLevel = LoggedInUser.UserLevel;
                ViewBag.HierarchyUserName = LoggedInUser.UserFullName ?? LoggedInUser.UserName;
                ViewBag.LoggedInUserId = LoggedInUser.UserId.ToString();
            }

            return View();
        }
