        /// <param name="Prefix"></param>
        /// <returns></returns>
        [HttpPost]
        [AuthLog(Roles = "Firm")]
        public ActionResult LeadUserListlogin(string Prefix)
        {
            var db = new LawPracticeEntities();
            var user = LoggedInUser.FirmId;
            var getclientid = db.RegUsers.Where(c => c.leadid.ToString() == Prefix.ToString() && c.Firmid.ToString() == LoggedInUser.FirmId.ToString() && c.IsAdmin == "3").FirstOrDefault();
            if (getclientid != null)
            {
                var leaduser = (from c in db.FirmUsers
                                where c.clientId == getclientid.Id && c.Firmid.ToString() == LoggedInUser.FirmId.ToString()
                                select new
                                {
                                    username = c.UserName,
                                    password = c.Password
                                }).ToList();
                return Json(leaduser, JsonRequestBehavior.AllowGet);
            }
            else
            {
                var data = "null";
                return Json(data, JsonRequestBehavior.AllowGet);
            }
