                        var fileext = Path.GetExtension(postedFile.FileName);
                        fileName = fileName.Replace(" ", string.Empty);
                        filePath = path + fileName;//HttpContext.Current.Server.MapPath(+ postedFile.FileName);
                        var fileextchk = Path.GetExtension(postedFile.FileName);
                        var is_valid = SaveCommonModulesDocument.chkValidExtension(fileextchk);
                        postedFile.SaveAs(filePath);
                    }
                    string extension = "." + extension1.Split('.')[1];
                    string conString = string.Empty;
                    switch (extension)
                    {
                        case ".xls": //Excel 97-03.
                            conString = ConfigurationManager.ConnectionStrings["Excel03ConString"].ConnectionString;
                            break;
                        case ".xlsx": //Excel 07 and above.
                            conString = ConfigurationManager.ConnectionStrings["Excel07ConString"].ConnectionString;
                            break;
                    }
                    DataTable dt = new DataTable();
                    conString = string.Format(conString, filePath);
                    using (OleDbConnection connExcel = new OleDbConnection(conString))
                    {
                        using (OleDbCommand cmdExcel = new OleDbCommand())
                        {
                            using (OleDbDataAdapter odaExcel = new OleDbDataAdapter())
                            {
                                cmdExcel.Connection = connExcel;
                                //Get the name of First Sheet.
                                connExcel.Open();
                                DataTable dtExcelSchema;
                                dtExcelSchema = connExcel.GetOleDbSchemaTable(OleDbSchemaGuid.Tables, null);
                                string sheetName = dtExcelSchema.Rows[0]["TABLE_NAME"].ToString();
                                connExcel.Close();
                                //Read Data from First Sheet.
                                connExcel.Open();
                                cmdExcel.CommandText = "SELECT * From [" + sheetName + "]";
                                odaExcel.SelectCommand = cmdExcel;
                                odaExcel.Fill(dt);
                                connExcel.Close();
                            }
                        }
                        Guid firmids = LoggedInUser.FirmId;
                        Guid userids = LoggedInUser.UserId;
                        Guid assignto = LoggedInUser.UserId;
                        DateTime date_time = System.DateTime.Now;
                        dt.Columns.Add("Firmid", typeof(System.Guid));
                        dt.Columns.Add("firmuser", typeof(System.Guid));
                        dt.Columns.Add("AssignTo", typeof(System.Guid));
                        dt.Columns.Add("date_time", typeof(System.DateTime));
                        foreach (DataRow row in dt.Rows)
                        {
                            row["Firmid"] = firmids;
                            row["firmuser"] = userids;
                            row["date_time"] = date_time;
                            row["AssignTo"] = assignto;
                        }
                    }
                    //validate the excel sheet with datatable
                    string CaseName = "", CaseStatus = "";
                    string valmsg = "";
                    for (int d = 0; d < dt.Rows.Count; d++)
                    {
                        CaseName = Convert.ToString(dt.Rows[d]["CaseName"]);
                        CaseStatus = Convert.ToString(dt.Rows[d]["CaseStatus"]);
                        if (CaseName == "")
                            valmsg += "CaseName, ";
                        if (CaseStatus == "")
                            valmsg += "CaseStatus, ";
                        valmsg = valmsg.Trim().TrimEnd(',');
                        if (valmsg != "")
                        {
                            result = "Unable to Import, " + valmsg + " fields are mandatory. Please check the excel sheet in Row No: " + (Convert.ToInt32(d) + 2);
                            return Json(result, JsonRequestBehavior.AllowGet);
                        }
                    }
                    if (valmsg == "")
                    {
                        var removetabldata = db.DeleteTempCaseData(Guid.Parse(LoggedInUser.FirmId.ToString()), Guid.Parse(LoggedInUser.UserId.ToString()));
                        conString = ConfigurationManager.ConnectionStrings["ApplicationContext"].ToString();
                        using (SqlConnection con = new SqlConnection(conString))
                        {
                            using (SqlBulkCopy sqlBulkCopy = new SqlBulkCopy(con))
                            {
                                //Set the database table name.
                                sqlBulkCopy.DestinationTableName = "dbo.TblImportToCaseDatas";
                                sqlBulkCopy.ColumnMappings.Add("Notes", "Notes");
                                sqlBulkCopy.ColumnMappings.Add("OpenDate", "OpenDate");
                                sqlBulkCopy.ColumnMappings.Add("CloseDate", "CloseDate");
                                sqlBulkCopy.ColumnMappings.Add("Tags", "Tags");
                                sqlBulkCopy.ColumnMappings.Add("CaseStatus", "CaseStatus");
                                sqlBulkCopy.ColumnMappings.Add("CaseNumber", "CaseNumber");
                                sqlBulkCopy.ColumnMappings.Add("CaseName", "CaseName");
                                sqlBulkCopy.ColumnMappings.Add("CNRNumber", "CNRNumber");
                                sqlBulkCopy.ColumnMappings.Add("AssignTo", "AssignTo");
                                sqlBulkCopy.ColumnMappings.Add("Firmid", "Firmid");
                                sqlBulkCopy.ColumnMappings.Add("firmuser", "firmuser");
                                sqlBulkCopy.ColumnMappings.Add("date_time", "date_time");
                                con.Open();
                                sqlBulkCopy.WriteToServer(dt);
                                con.Close();
                            }
                        }
                        string createdby = LoggedInUser.UserId.ToString();
                        var copytemptooriginaldata = db.CopyDatatoCaselist(Guid.Parse(LoggedInUser.FirmId.ToString()), Guid.Parse(LoggedInUser.UserId.ToString()));
                        result = "Record imported successfully, please check Case Details.";
                        db.saveuseractivity(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString(), LoggedInUser.UserId.ToString(), 1, DateTime.Now.ToString(), "ImportCase", Guid.Empty.ToString(), null, null, DateTime.Now.ToString());
                        return Json(result, JsonRequestBehavior.AllowGet);
                    }
                }
                return Json(result, JsonRequestBehavior.AllowGet);
            }
            catch (Exception ex)
            {
                db1.usp_AddAudit(Convert.ToInt32(EventType.Contact), Convert.ToInt32(Severity.High), Convert.ToInt32(REQUEST_TYPE.API), Convert.ToString(EventType.Contact), Convert.ToString(Severity.High), Convert.ToString(REQUEST_TYPE.API), null, "Message=" + ex.Message + "@Inner Exception=" + ex.InnerException + "@Stack Trace=" + ex.StackTrace, myIP(), GetMacAddress().ToString(), 1, "");
                return Json(ex.Message + "Invalid File Format !", JsonRequestBehavior.AllowGet);
            }
        }
