        /// <summary>
        /// Load case alert details
        /// </summary>
        /// <returns></returns>
        [FirmControllerAuthorization]
        public ActionResult loadcasealerts()
        {
            try
            {
                var db = new LawPracticeEntities();
                string strusername = WebConfigurationManager.AppSettings["matteridname"];
                var apiUrl = ConfigurationManager.AppSettings["savetocasewatchurl"];
                var caseids = QueryAES.UrlDecode(Request.Form["caseid"]);
                var isRerachecks = QueryAES.UrlDecode(Request.Form["Isrerachecks"]);
                var courtCheck = QueryAES.UrlDecode(Request.Form["courttext"]);
                try
                {
                    caseids = caseids.Replace(" ", "+");
                    caseids = QueryAES.DecryptAes(QueryAES.FromBase64StringWithReplace(caseids));
                }
                catch
                {
                }
                var courtflag = "";
                if (isRerachecks == "1")
                {
                    courtflag = "7";
                }
                if (isRerachecks == "RERH")
                {
                    courtflag = isRerachecks;
                }
                if ((courtCheck == "HRRA") || (courtCheck == "MHRERA"))
                {
                    courtflag = "7";
                }

                string AccessTokenDetail = string.Empty;
                string userIdDetail = string.Empty;
                string IsCaseWatchUser = LoggedInUser.IsCaseWatchUser.ToString();
                if (!String.IsNullOrEmpty(IsCaseWatchUser))
                {
                    if (IsCaseWatchUser == "1")
                    {
                        userIdDetail = LoggedInUser.UserName.ToString();
                        AccessTokenDetail = "internal";
                    }
                    else
                    {
                        AccessTokenDetail = "mykase123456789abcdef";
                        userIdDetail = strusername + LoggedInUser.UserId.ToString();
                    }
                }
                else
                {
                    AccessTokenDetail = "mykase123456789abcdef";
                    userIdDetail = strusername + LoggedInUser.UserId.ToString();
                }
                //add login data
                var addfClient = new WebClient();
                object rawfile = new
                {
                    accesstoken = AccessTokenDetail,
                    userid = userIdDetail,
                    firmid = LoggedInUser.FirmId.ToString(),
                    caseid = caseids,
                    Courtflag = courtflag
                };
                addfClient.Encoding = Encoding.UTF8;
                addfClient.Headers.Add(HttpRequestHeader.ContentType, "application/json");
                addfClient.Headers.Add("Accept-Charset", "utf-8");
                string builders = JsonConvert.SerializeObject(rawfile);
                ServicePointManager.SecurityProtocol = SecurityProtocolType.Tls12;
                var resid = addfClient.UploadString(new Uri(apiUrl + "/API/Search/AlertSettingByUserRefIIdLawPractice"), "POST", builders);
                try
                {
                    var db1 = new LawPracticeEntities();
                    var param = apiUrl + "FirmController=>loadcasealert=>/API/Search/AlertSettingByUserRefIIdLawPractice" + "@" + builders;
                    db1.usp_AddAudit(Convert.ToInt32(EventType.Case), Convert.ToInt32(Severity.High), Convert.ToInt32(REQUEST_TYPE.API), Convert.ToString(EventType.Case), Convert.ToString(Severity.High), Convert.ToString(REQUEST_TYPE.API), Guid.Parse(Session["sessionuserid"].ToString()), param, myIP(), GetMacAddress().ToString(), 0, "");
                }
                catch
                {
                }
                JObject jObject = JObject.Parse(resid);
                dynamic data1 = jObject["data"];
                List<CaseAlert> caseAlert = new List<CaseAlert>();
                for (int i = 0; i < data1.Count; i++)
                {
                    dynamic data = JObject.Parse(resid);
                    string status = data.Status;
                    string Message = data.Message;
                    string ID = data.data[i].id;
                    string masterappealno = data.data[i].masterappealno;
                    string Courtname = data.data[i].Courtname;
                    string vCaseName = data.data[i].vCaseName;
                    string firmid = data.data[i].firmid;
                    string vnexthearing = data.data[i].vnexthearing;
                    string vDisposedDate = data.data[i].vDisposedDate;
                    string Mobile = data.data[i].Mobile;
                    string Email = data.data[i].Email;
                    string AlertFor = data.data[i].AlertFor;
                    string AlertType = data.data[i].AlertType;
                    string createdOn = data.data[i].createdOn;
                    string isSent = data.data[i].isSent;
                    string alertDays = data.data[i].alertDays;
                    string alertdate = data.data[i].alertdate;
                    string Manualnexthearing = data.data[i].Manualnexthearing;
                    // Add parts to the list.
                    caseAlert.Add(new CaseAlert { ID = Convert.ToInt32(ID), masterappealno = masterappealno, Courtname = Courtname, vCaseName = vCaseName, firmid = firmid, vnexthearing = vnexthearing, vDisposedDate = vDisposedDate, Mobile = Mobile, Email = Email, AlertFor = AlertFor, AlertType = AlertType, createdOn = createdOn, isSent = isSent, alertDays = alertDays, alertdate = alertdate, Manualnexthearing = Manualnexthearing });
                }
                return Json(caseAlert, JsonRequestBehavior.AllowGet);
            }
            catch (Exception ex)
            {
                var s = "ERROR IN READING DATA";
                return Json(ex.Message, JsonRequestBehavior.AllowGet);
            }
        }
