        [AuthLog(Roles = "Firm,User")]
        [HttpPost]
        public void SendPropsectData()
        {
            System.Text.RegularExpressions.Regex rx = new System.Text.RegularExpressions.Regex("<[^>]*>");
            try
            {
                var email = QueryAES.UrlDecode(Request.Form["email"]);
                var roleid = LoggedInUser.RoleId;
                var db = new LawPracticeEntities();
                var data = db.GetLeadDetails(LoggedInUser.FirmId);
                var trialList = (from ob in data
                                 select new
                                 {
                                     LeadName = ob.ldname,
                                     ContactPerson = ob.ldcperson,
                                     Designation = ob.lddesign,
                                     Organization = ob.ldorg,
                                     Email = ob.ldemail,
                                     Mobile = ob.ldmob,
                                     Address = ob.ldadd,
                                     OfficeNo = ob.ldphn,
                                     Source = ob.ldsource,
                                     Country = ob.ldcountry,
                                     State = ob.ldstate,
                                     City = ob.ldcity
                                 });
                var gv = new GridView();
                gv.DataSource = trialList;
                gv.DataBind();
                StringWriter objStringWriter = new StringWriter();
                HtmlTextWriter objHtmlTextWriter = new HtmlTextWriter(objStringWriter);
                gv.RenderControl(objHtmlTextWriter);
                var path = Server.MapPath("~/Documents/ShareDocs/" + LoggedInUser.FirmId + "/" + LoggedInUser.UserId + "/");
                var date = DateTime.Now;
                string filename = "Prospect" + date.Hour + date.Minute + date.Second + date.Millisecond + ".xls";
                string fullpath = path + filename;
                if (!Directory.Exists(path))
                {
                    Directory.CreateDirectory(path);
                }
                // Write the rendered content to a file.
                string renderedGridView = objStringWriter.ToString();
                System.IO.File.WriteAllText(fullpath, renderedGridView);
