        /// <summary>
        /// Send OTP
        /// </summary>
        /// <returns></returns>
        public JsonResult SendOTP()
        {
            Session["GenerateOTPValue"] = "";
            int otpValue = new Random().Next(100000, 999999);
            var status = "";
            try
            {
                string mobileotp = QueryAES.UrlDecode(Request.Form["mobileotp"]);
                if (mobileotp.Length < 10)
                {
                    return Json("validcontact", JsonRequestBehavior.AllowGet);
                }
                var db = new LawPracticeEntities();
                //validate itp for 1 minute
                var otpdate = db.sp_GetTopOtpDateByMobile(mobileotp).FirstOrDefault();
                if (otpdate != null)
                {
                    var getcurrettime = db.sp_GetCurrentDate().FirstOrDefault();
                    var getcurrettimevalue = getcurrettime.CurrentDate;
                    var otptime = otpdate.date_time;
                    DateTime myDate1 = Convert.ToDateTime(otptime);
                    DateTime myDate2 = getcurrettimevalue;
                    TimeSpan difference = (myDate2 - myDate1);
                    double TotalSeconds = difference.TotalSeconds;
                    if (TotalSeconds < 60)
                    {
                        return Json("waitresendotp", JsonRequestBehavior.AllowGet);
                    }
                }
                if (mobileotp.ToString() != "")
                {
                    var check = db.TblRegOtps.Where(x => x.Mobile == mobileotp).FirstOrDefault();
                    if (check != null)
                    {
                        check.isactive = 0;
                        check.otpvalue = otpValue.ToString();
                        check.Mobile = mobileotp;
                        check.date_time = DateTime.Now;
                        db.SaveChanges();
                        string strURL = System.Configuration.ConfigurationManager.AppSettings["smsauthlink"];
                        strURL = strURL.Replace("#cmobile", mobileotp.ToString()).Replace("#otpvalue", otpValue.ToString());
                        String strResult;
                        WebResponse objResponse;
                        WebRequest objRequest = HttpWebRequest.Create(strURL);
                        objResponse = objRequest.GetResponse();
                        using (StreamReader sr = new StreamReader(objResponse.GetResponseStream()))
                        {
                            strResult = sr.ReadToEnd();
                            sr.Close();
                        }
                        return Json("success", JsonRequestBehavior.AllowGet);
                    }
                    else
                    {
                        TblRegOtp rotp = new TblRegOtp();
                        rotp.isactive = 0;
                        rotp.otpvalue = otpValue.ToString();
                        rotp.Mobile = mobileotp;
                        rotp.date_time = DateTime.Now;
                        db.TblRegOtps.Add(rotp);
                        db.SaveChanges();
                        string strURL = System.Configuration.ConfigurationManager.AppSettings["smsauthlink"];
                        strURL = strURL.Replace("#cmobile", mobileotp.ToString()).Replace("#otpvalue", otpValue.ToString());
                        String strResult;
                        WebResponse objResponse;
                        WebRequest objRequest = HttpWebRequest.Create(strURL);
                        objResponse = objRequest.GetResponse();
                        using (StreamReader sr = new StreamReader(objResponse.GetResponseStream()))
                        {
                            strResult = sr.ReadToEnd();
                            sr.Close();
                        }
                        Session["GenerateOTPValue"] = otpValue;
                        return Json("success", JsonRequestBehavior.AllowGet);
                    }
                }
                else
                {
                    return Json(status, JsonRequestBehavior.AllowGet);
                }
            }
            catch (Exception e)
            {
                throw (e);
            }
        }
        /// <summary>
        /// Verify OTP details
        /// </summary>
        /// <returns></returns>
        public JsonResult VerifyOTP()
        {
            string status = "";
            try
            {
                string otpvalue = QueryAES.UrlDecode(Request.Form["otpvalue"]);
                string mobileotp = QueryAES.UrlDecode(Request.Form["mobileotp"]);
                if (otpvalue.ToString() != "" && mobileotp.ToString() != "")
                {
                    var check = db.TblRegOtps.Where(x => x.Mobile == mobileotp && x.otpvalue == otpvalue).FirstOrDefault();
                    if (check != null)
                    {
                        var sessionotp = check.otpvalue;
                        if (sessionotp.ToString() == otpvalue.ToString())
                        {
                            check.isactive = 1;
                            db.SaveChanges();
                            return Json("success", JsonRequestBehavior.AllowGet);
                        }
                        else
                        {
                            return Json(status, JsonRequestBehavior.AllowGet);
                        }
                    }
                    return Json(status, JsonRequestBehavior.AllowGet);
                }
                else
                {
                    return Json(status, JsonRequestBehavior.AllowGet);
                }
            }
            catch (Exception e)
            {
                throw (e);
            }
        }
        /// <summary>
        /// Create group
        /// </summary>
        /// <returns></returns>
        [AuthLog(Roles = "Firm,User")]
        public ActionResult creategroup()
        {
            try
            {
                var user = LoggedInUser.FirmId;
                var trialList_1 = db.usp_GetUserbyIdwithClient(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString()).ToList();
                var trialList = (from ob in trialList_1
                                 select new
                                 {
                                     label = ((ob.PartnerId == "" || ob.PartnerId == null || ob.PartnerId == "null") ? ob.UserName + " -(" + ob.RoleName + ")" : (ob.PartnerId.ToString().ToLower() == LoggedInUser.UserId.ToString().ToLower() ? ob.UserName + "-(" + ob.RoleName + ")" : ob.UserName + " - (" + ob.RoleName + " " + ob.PartnerName + ")")),
                                     val = ob.id,
                                     roleid = ob.roleid,
                                     role = ob.RoleName,
                                     Partnerid = ob.PartnerId
                                 }).ToList();
                ViewBag.Fruits = trialList;
            }
            catch (Exception ex)
            {
                db1.usp_AddAuditError(Convert.ToInt32(EventType.Firm), Convert.ToInt32(Severity.High), Convert.ToInt32(REQUEST_TYPE.API), Convert.ToString(EventType.Firm), Convert.ToString(Severity.High), Convert.ToString(REQUEST_TYPE.API), null, "Message=" + ex.Message + "@Inner Exception=" + ex.InnerException + "@Stack Trace=" + ex.StackTrace, myIP(), GetMacAddress().ToString(), 1, "");
            }
            return View();
        }
        /// <summary>
        /// Update client user group
        /// </summary>
        /// <returns></returns>
        [AuthLog(Roles = "Firm,User")]
        public ActionResult editgroup()
        {
            try
            {
                string fid = QueryAES.UrlDecode(Request.QueryString["token"]);
                fid = fid.ToString().Replace(" ", "+");
                fid = QueryAES.DecryptStringAES(fid);
                ViewBag.tokenid = fid;
                var user = LoggedInUser.FirmId;
                var trialList_1 = db.usp_GetUserbyIdwithClient(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString()).ToList();
                var trialList = (from ob in trialList_1
                                 select new
                                 {
                                     label = ((ob.PartnerId == "" || ob.PartnerId == null || ob.PartnerId == "null") ? ob.UserName + " -(" + ob.RoleName + ")" : (ob.PartnerId.ToString().ToLower() == LoggedInUser.UserId.ToString().ToLower() ? ob.UserName + "-(" + ob.RoleName + ")" : ob.UserName + " - (" + ob.RoleName + " " + ob.PartnerName + ")")),
                                     val = ob.id,
                                     roleid = ob.roleid,
                                     role = ob.RoleName,
                                     Partnerid = ob.PartnerId
                                 }).ToList();
                ViewBag.Fruits = trialList;
            }
            catch (Exception ex)
            {
                db1.usp_AddAuditError(Convert.ToInt32(EventType.Firm), Convert.ToInt32(Severity.High), Convert.ToInt32(REQUEST_TYPE.API), Convert.ToString(EventType.Firm), Convert.ToString(Severity.High), Convert.ToString(REQUEST_TYPE.API), null, "Message=" + ex.Message + "@Inner Exception=" + ex.InnerException + "@Stack Trace=" + ex.StackTrace, myIP(), GetMacAddress().ToString(), 1, "");
