        /// <summary>
        /// Update client profile dashboard
        /// </summary>
        /// <returns></returns>
        [AuthLog(Roles = "Firm,User")]
        public ActionResult ClientProfileDashboard()
        {
            var typeid = QueryAES.UrlDecode(Request.Form["token"]);
            ViewBag.clientid = typeid;
            if (typeid != null)
            {
                typeid = QueryAES.DecryptAes(QueryAES.FromBase64StringWithReplace(typeid));
                var chkname = db.RegUsers.Where(x => x.Firmid == LoggedInUser.FirmId && x.LoginId.ToString() == typeid).FirstOrDefault();
                if (chkname != null)
                {
                    if (!string.IsNullOrEmpty(chkname.cfname.ToString()))
                    {
                        ViewBag.Clientname = chkname.cfname.ToString();
                    }
                }
            }
            return View();
        }
