        [AuthLog(Roles = "Firm,User")]
        public ActionResult ClientGraph()
        {
            var open = 4;
            var close = 2;
            var chart = new System.Web.Helpers.Chart(width: 300, height: 300)
                 .AddTitle("MyKase client")
                 .AddSeries(
                chartType: "Pie",
                name: "Myakse Client Case Data",
                xValue: new[] { "Open Case", "Close Case" },
                 yValues: new[] { open.ToString(), close.ToString() })
                 .GetBytes("png");
