        public ActionResult EditMailboxserver()
        {
            try
            {
                var token = QueryAES.UrlDecode(Request.QueryString["token"]);
                if (token != "")
                {
                    token = token.ToString().Replace(" ", "+");
                    token = QueryAES.DecryptAes(QueryAES.FromBase64StringWithReplace(token));
                    ViewBag.token = token;
                    var data = db.Tbl_mailboxServer.Where(x => x.Firmid == LoggedInUser.FirmId && x.Id.ToString() == token && x.Userid == LoggedInUser.UserId).FirstOrDefault();
                    if (data != null)
                    {
                        ViewBag.MailServerName = data.MailServerName;
                        ViewBag.SmtpAddress = data.SmtpAddress;
                        ViewBag.SmtpPort = data.SmtpPort;
                        ViewBag.ImapAddress = data.ImapAddress;
                        ViewBag.ImapPort = data.ImapPort;
                        ViewBag.PopAddress = data.PopAddress;
                        ViewBag.PopPort = data.PopPort;
                    }
                }
            }
            catch (Exception ex)
            {
                db.usp_AddAuditError(Convert.ToInt32(EventType.Firm), Convert.ToInt32(Severity.High), Convert.ToInt32(REQUEST_TYPE.API), Convert.ToString(EventType.Firm), Convert.ToString(Severity.High), Convert.ToString(REQUEST_TYPE.API), null, "Message=" + ex.Message + "@Inner Exception=" + ex.InnerException + "@Stack Trace=" + ex.StackTrace, myIP(), GetMacAddress().ToString(), 1, "");
