                GetTimerDetailsByRowIdNew_Result Item = new GetTimerDetailsByRowIdNew_Result();
                int count = trialList_1.Count;
                var trialList = (from ob in trialList_1
                                 select new
                                 {
                                     SlNo = ob.rownum,
                                     MattersName = String.IsNullOrEmpty(ob.mattername) ? ob.mattername : ob.mattername,
                                     Client = String.IsNullOrEmpty(ob.client) ? ob.client : ob.client,
                                     Date = String.Format("{0:dd MMM yyyy}", ob.tdate) + " " + String.Format("{0:HH:mm:ss}", ob.tdate),
                                     Duration = ob.callDura,
                                     CreatedBy = String.IsNullOrEmpty(ob.createdby) ? ob.createdby : ob.createdby,
                                     TaskType = ob.titem,
                                     Notes = Regex.Replace(ob.tdetails, "<.*?>", String.Empty),
                                     TimeEntryType = ob.TimeEntryType
                                 }).ToList();
