                Response.Flush();
                Response.End();
                string notification = "You have Exported Time Entry list Excel";
                db.usp_AddActivity(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString(), notification, "Export Time Entry Excel",
                    null, null);
            }
