        /// <summary>
        /// Create case reminders
        /// </summary>
        /// <returns></returns>
        [AuthLog(Roles = "Firm,User")]
        public ActionResult CreateCaseReminders()
        {
            var typeid = Request.QueryString["token"];
            var caseid = QueryAES.DecryptAes(QueryAES.FromBase64StringWithReplace(typeid.ToString().Replace(" ", "+")));
            ViewBag.token = typeid;
            ViewBag.filesize = ConfigurationManager.AppSettings["filesizemultiple"];
            try
            {
                var user = LoggedInUser.FirmId;
                List<GetAssignUserListforCreateAlert_Result> trialList = new List<GetAssignUserListforCreateAlert_Result>();
                trialList = db.GetAssignUserListforCreateAlert(LoggedInUser.FirmId, LoggedInUser.UserId, caseid).ToList();
                foreach (var data in trialList.ToList())
                {
                    GetAssignUserListforCreateAlert_Result newItem = new GetAssignUserListforCreateAlert_Result();
                    if (!string.IsNullOrEmpty(data.UserName))
                    {
                        newItem.UserName = QueryAES.DecryptAes(QueryAES.FromBase64StringWithReplace(data.UserName.ToString()));
                        trialList[trialList.IndexOf(data)].UserName = newItem.UserName;
                    }
                }
                var list = (from ob in trialList
                            select new
                            {
                                label = ob.UserName + " (" + ob.RoleName + ")",
                                val = ob.Id,
                            }).ToList();
                ViewBag.Fruits = list;
                var trialList21 = db.sp_bindcaseventlist(LoggedInUser.FirmId, LoggedInUser.UserId).ToList();
                var events = (from c in trialList21
                              select new
                              {
                                  label = c.EventName,
                                  val = c.EventName,
                              }).ToList();
                var list1 = events;
                ViewBag.events = list1;
            }
            catch (Exception ex)
            {
                db1.usp_AddAuditError(Convert.ToInt32(EventType.Firm), Convert.ToInt32(Severity.High), Convert.ToInt32(REQUEST_TYPE.API), Convert.ToString(EventType.Firm), Convert.ToString(Severity.High), Convert.ToString(REQUEST_TYPE.API), null, "Message=" + ex.Message + "@Inner Exception=" + ex.InnerException + "@Stack Trace=" + ex.StackTrace, myIP(), GetMacAddress().ToString(), 1, "");
            }
            return View();
        }
