        /// <summary>
        /// Export Fav contact in excel
        /// </summary>
        [AuthLog(Roles = "Firm,User")]
        public void ExportoExcelFavContact()
        {
            try
            {
                var searchdata = QueryAES.UrlDecode(Request.QueryString["searchdata"]);
                var exportfilterdata = QueryAES.UrlDecode(Request.QueryString["exportfilter"]);
                string exlfilename = "FavContactReport_" + DateTime.Now;
                var db = new LawPracticeEntities();
                if (exportfilterdata.ToString() == "true")
                {
                    List<GetSearchFavContactDetailsByRowId_Result> trialList_1 = new List<GetSearchFavContactDetailsByRowId_Result>();
                    trialList_1 = db.GetSearchFavContactDetailsByRowId(LoggedInUser.FirmId, LoggedInUser.UserId, 1, 1, 1, searchdata).ToList();
                    StringBuilder sb = new StringBuilder();
                    foreach (var data in trialList_1.ToList())
                    {
                        sb.Clear();
                        GetSearchFavContactDetailsByRowId_Result newItem = new GetSearchFavContactDetailsByRowId_Result();
                        if (!string.IsNullOrEmpty(data.assignuser))
                        {
                            string[] words = data.assignuser.ToString().Split(',');
                            foreach (string word in words)
                            {
                                string tempuser = QueryAES.DecryptAes(QueryAES.FromBase64StringWithReplace(word.ToString()));
                                sb.Append(tempuser);
                                sb.Append(",");
                            }
                            newItem.assignuser = sb.ToString().TrimEnd(',');
                            trialList_1[trialList_1.IndexOf(data)].assignuser = newItem.assignuser;
                        }
                    }
                    var actionmode = "";
                    var recentlabel = "";
                    GetSearchFavContactDetailsByRowId_Result Item = new GetSearchFavContactDetailsByRowId_Result();
                    int count = trialList_1.Count;
                    string sf = "dsf";
                    var trialList = (from ob in trialList_1
                                     select new
                                     {
                                         SlNo = ob.rownum,
                                         FullName = ob.fname + " " + ob.mname + " " + ob.lname,
                                         Mobile = ob.mobno,
                                         ContactTypes = ob.ContactType,
                                         Email = ob.cemail,
                                         AssignTo = ob.assignuser,
                                         Tags = ob.ctags,
                                         Address = ob.cadd1,
                                         Website = ob.cwebsite,
                                         ob.col1,
                                         ob.col2,
                                         ob.col3,
                                         ob.col4,
                                         ob.col5,
                                         ob.col6,
                                         ob.col7,
                                         ob.col8,
                                         ob.col9,
                                         ob.col10,
                                         ob.col11,
                                         ob.col12,
                                         ob.col13,
                                         ob.col14,
                                         ob.col15
                                     }).ToList();
                    var gv = new GridView();
                    gv.DataSource = trialList;
                    gv.DataBind();
                    var counts = gv.Rows.Count;
