        /// <summary>
        /// Service log
        /// </summary>
        /// <param name="content"></param>
        private void LogService(string content)
        {
            var templogpath = Server.MapPath("//");
            FileStream fs = new FileStream(templogpath + "//CloudMyKaseoffiecSyncLog.txt", FileMode.OpenOrCreate, FileAccess.Write);
            StreamWriter sw = new StreamWriter(fs);
            sw.BaseStream.Seek(0, SeekOrigin.End);
            sw.WriteLine(content);
            sw.Flush();
            sw.Close();
        }
        /// <summary>
        /// Send knowledge file
        /// </summary>
        [AuthLog(Roles = "Firm,User")]
        [HttpPost]
        public void SendKnowledgefile()
        {
            System.Text.RegularExpressions.Regex rx = new System.Text.RegularExpressions.Regex("<[^>]*>");
            try
            {
                LogService("serr");
                var email = QueryAES.UrlDecode(Request.Form["email"]);
                var filepath = QueryAES.UrlDecode(Request.Form["token"]);
                var roleid = LoggedInUser.RoleId;
                var db = new LawPracticeEntities();
                var fileName = "";
                var dfullpathcloud = "";
                if (!String.IsNullOrEmpty(filepath))
                {
                    var getknowdetails = db.usp_CheckfolderKnowledge(LoggedInUser.FirmId.ToString(), filepath).FirstOrDefault();
                    fileName = getknowdetails.tfile;
                    if (getknowdetails.pfile.ToString() == Guid.Empty.ToString())
                    {
                        dfullpathcloud = "Documents/Knowledge/" + getknowdetails.Firmid + "/" + getknowdetails.firmuser;
                    }
                    else
                    {
                        var dirfullpath = db.sp_Getknowfilepaths(Guid.Parse(getknowdetails.Firmid.ToString()), Guid.Parse(getknowdetails.firmuser.ToString()), Guid.Parse(getknowdetails.pfile.ToString())).FirstOrDefault();
                        string dirpathname = dirfullpath.ToString();
                        dfullpathcloud = "Documents/Knowledge/" + getknowdetails.Firmid + "/" + getknowdetails.firmuser + "/" + dirpathname;
                    }
                }
                string fakepathin = Server.MapPath("~/azuredirin/" + LoggedInUser.FirmId + "/" + LoggedInUser.UserId);
                string fakepathout = Server.MapPath("~/azuredirout/" + LoggedInUser.FirmId + "/" + LoggedInUser.UserId);
                if (!Directory.Exists(fakepathin))
                {
                    Directory.CreateDirectory(fakepathin);
                }
                if (!Directory.Exists(fakepathout))
                {
                    Directory.CreateDirectory(fakepathout);
                }
                var source = AzureDocumentself.Dirfilepath(dfullpathcloud, fileName, fakepathin, fakepathout, null, null);
                System.IO.FileInfo fileInfo = new System.IO.FileInfo(source);
                var dfilename = fileInfo.Name;
                int idx = dfilename.LastIndexOf('.');
                string string1 = dfilename.Substring(0, idx);
                string string2 = dfilename.Substring(idx + 1);
                string1 = string1.Substring(0, string1.Length - 10);
                dfilename = string1 + "." + string2;
                var date = DateTime.Now;
                string fromemail = WebConfigurationManager.AppSettings["fromemail"].ToString();
                CommomUtility obj1 = new CommomUtility();
                var username = db.usp_GetUserNameById(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString()).FirstOrDefault();
                string emailsubject = "File Shared By " + username.ToString();
                string emailbody = "Please take attached file shared by " + username.ToString();
                string AssignmentSubmittedMailBody = WebConfigurationManager.AppSettings["basicmailtemplate"].ToString();
                AssignmentSubmittedMailBody = AssignmentSubmittedMailBody.Replace("#CONTENT#", emailbody.ToString());
                obj1.SendEmail(fromemail, email, "", emailsubject, AssignmentSubmittedMailBody, source);
                try
                {
                    System.IO.File.Delete(source);
                }
                catch (Exception er)
                {
                }
                try
                {
                    string notification = "You have Emailed the Document (" + dfilename + ") in knowledge";
                    db.usp_AddActivity(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString(), notification, "Email Document", null, Guid.Empty.ToString());
                }
                catch
                {
                }
            }
            catch (Exception ex)
            {
                LogService("senknoiwlkdgeerror" + ex.Message + "&" + ex.InnerException);
            }
        }
