        /// <summary>
        /// Create esc task details
        /// </summary>
        /// <returns></returns>
        [AuthLog(Roles = "Firm,User")]
        public ActionResult CreateTaskEsc()
        {
            try
            {
                ViewBag.filesize = ConfigurationManager.AppSettings["filesizemultiple"];
                var user = LoggedInUser.FirmId;
                var date = QueryAES.UrlDecode(HttpContext.Request.QueryString["date"]);
                var subject = QueryAES.UrlDecode(HttpContext.Request.QueryString["subject"]);
                ViewBag.date = date;
                ViewBag.subject = subject;
                var taskid = QueryAES.UrlDecode(HttpContext.Request.QueryString["token"]);
                ViewBag.taskid = taskid;
                try
                {
                    taskid = taskid.ToString().Replace(" ", "+");
                    taskid = QueryAES.DecryptAes(QueryAES.FromBase64StringWithReplace(taskid));
                }
                catch (Exception er)
                {
                }
                List<GetAssignUserListforTask_Result> trialList = new List<GetAssignUserListforTask_Result>();
                trialList = db.GetAssignUserListforTask(LoggedInUser.FirmId, LoggedInUser.UserId, taskid, Convert.ToInt32(LoggedInUser.RoleId)).ToList();
                foreach (var data in trialList.ToList())
                {
                    GetAssignUserListforTask_Result newItem = new GetAssignUserListforTask_Result();
                    if (!string.IsNullOrEmpty(data.UserName))
                    {
                        newItem.UserName = QueryAES.DecryptAes(QueryAES.FromBase64StringWithReplace(data.UserName.ToString()));
                        trialList[trialList.IndexOf(data)].UserName = newItem.UserName;
                    }
                }
                var list = (from ob in trialList
                            select new
                            {
                                label = ob.UserName + " (" + ob.RoleName + ")",
                                val = ob.auserid,
                            }).ToList();
                ViewBag.Fruits = list;
            }
            catch (Exception ex)
            {
                db1.usp_AddAuditError(Convert.ToInt32(EventType.Firm), Convert.ToInt32(Severity.High), Convert.ToInt32(REQUEST_TYPE.API), Convert.ToString(EventType.Firm), Convert.ToString(Severity.High), Convert.ToString(REQUEST_TYPE.API), null, "Message=" + ex.Message + "@Inner Exception=" + ex.InnerException + "@Stack Trace=" + ex.StackTrace, myIP(), GetMacAddress().ToString(), 1, "");
            }
            return View();
        }
