        [AuthLog(Roles = "Firm,User,Client")]
        [HttpPost]
        public JsonResult CaseDataCaseWatchBulk(List<CaseWatchBulkRequest> caseList)
        {
            List<CaseBenchDetails> resultList = new List<CaseBenchDetails>();
            List<string> debug = new List<string>();

            try
            {
                if (caseList == null || caseList.Count == 0)
                {
                    return Json(new
                    {
                        Result = resultList,
                        Debug = new List<string> { "Case list empty" }
                    }, JsonRequestBehavior.AllowGet);
                }


                var db = new LawPracticeEntities();


                foreach (var item in caseList)
                {
                    try
                    {
                        debug.Add("Token received : " + item.token);


                        string caseid = "";


                        // Same decrypt logic as CaseDataCaseWatch
                        try
                        {
                            var decodedToken = QueryAES.UrlDecode(item.token);

                            caseid = QueryAES.DecryptAes(
                                QueryAES.FromBase64StringWithReplace(decodedToken)
                            );
                        }
                        catch (Exception ex)
                        {
                            debug.Add("Decrypt failed : " + ex.Message);

                            // fallback
                            caseid = item.token;
                        }


                        debug.Add("CaseId after decrypt : " + caseid);



                        if (string.IsNullOrEmpty(caseid))
                        {
                            debug.Add("CaseId empty, skipping");
                            continue;
                        }



                        var data22 = db.Usp_GetCasewatchCaseMapDetails(
                            LoggedInUser.FirmId.ToString(),
                            caseid
                        ).FirstOrDefault();



                        if (data22 == null)
                        {
                            debug.Add(
                                "No CaseWatch mapping found for CaseId : " + caseid
                            );

                            continue;
                        }


                        debug.Add(
                            "CaseWatch mapping found : " + caseid
                        );

                        var caseDetail = GetCaseBenchDetailFromApi(caseid, data22.UserId);
                        if (caseDetail != null)
                        {
                            resultList.Add(caseDetail);
                        }

                    }
                    catch (Exception ex)
                    {
                        debug.Add(
                            "Case processing error : " + ex.Message
                        );

                        continue;
                    }
                }



                return Json(new
                {
                    type = "CASE_BULK",
                    Result = resultList,
                    Debug = debug
                }, JsonRequestBehavior.AllowGet);


            }
            catch (Exception ex)
            {
                return Json(new
                {
                    type = "ERROR",
                    Result = new List<CaseBenchDetails>(),
                    Error = ex.Message
                }, JsonRequestBehavior.AllowGet);
            }
        }



