        /// <summary>
        /// Get cause list details
        /// </summary>
        /// <returns></returns>
        [AuthLog(Roles = "Firm,User,Client")]
        public JsonResult LoadCauseList()
        {
            string Courtflags = "";
            var IsReracauselist = QueryAES.UrlDecode(Request.Form["IsReracauselist"]);
            var courtTypeId = QueryAES.UrlDecode(Request.Form["courtTypeId"]);
            if (IsReracauselist == "1")
            {
                Courtflags = "7";
            }
            else
            {
                Courtflags = courtTypeId;
            }
            var strdt = QueryAES.UrlDecode(Request.Form["id"]);
            try
            {
                strdt = strdt.Replace(" ", "+");
                strdt = QueryAES.DecryptAes(QueryAES.FromBase64StringWithReplace(strdt));
            }
            catch
            {
                strdt = strdt;
            }
            var apiUrl = ConfigurationManager.AppSettings["savetocasewatchurl"];
            //For CaseWatch User
            string AccessTokenDetail = string.Empty;
            string userIdDetail = string.Empty;
            string IsCaseWatchUser = LoggedInUser.IsCaseWatchUser.ToString();
            if (IsCaseWatchUser == "1")
            {
                userIdDetail = LoggedInUser.UserName.ToString();
                AccessTokenDetail = "internal";
            }
            else
            {
                AccessTokenDetail = "mykase123456789abcdef";
                userIdDetail = WebConfigurationManager.AppSettings["matteridname"] + LoggedInUser.UserId;
            }
            //add login data
            var addfClient = new WebClient();
            //handle the unicode character server to server
            addfClient.Encoding = System.Text.Encoding.UTF8;
            object rawfile;
            if (courtTypeId == "RERH")
            {
                // If QueryAES.UrlDecode handles encryption, decode in two steps:
                var AppealnoEncrypted = Request.Form["AppealNo"];
                var Appealno = !string.IsNullOrWhiteSpace(AppealnoEncrypted)
                    ? QueryAES.UrlDecode(HttpUtility.UrlDecode(AppealnoEncrypted, System.Text.Encoding.UTF8))
                    : string.Empty;

                var tahsilNameEncrypted = Request.Form["tahsilName"];
                var tahsilName = !string.IsNullOrWhiteSpace(tahsilNameEncrypted)
                    ? QueryAES.UrlDecode(HttpUtility.UrlDecode(tahsilNameEncrypted, System.Text.Encoding.UTF8))
                    : string.Empty;

                var districtNameEncrypted = Request.Form["janpadName"];
                var districtName = !string.IsNullOrWhiteSpace(districtNameEncrypted)
                    ? QueryAES.UrlDecode(HttpUtility.UrlDecode(districtNameEncrypted, System.Text.Encoding.UTF8))
                    : string.Empty;

                var courtNameEncrypted = Request.Form["courtName"];
                var courtName = !string.IsNullOrWhiteSpace(courtNameEncrypted)
                    ? QueryAES.UrlDecode(HttpUtility.UrlDecode(courtNameEncrypted, System.Text.Encoding.UTF8))
                    : string.Empty;
                var vJudCourtEncrypted = Request.Form["vJudCourt"];
                var vJudCourt = !string.IsNullOrWhiteSpace(vJudCourtEncrypted)
                    ? QueryAES.UrlDecode(HttpUtility.UrlDecode(vJudCourtEncrypted, System.Text.Encoding.UTF8))
                    : string.Empty;
                rawfile = new
                {
                    accesstoken = AccessTokenDetail,
                    userid = userIdDetail,
                    caseid = strdt,
                    Courtflag = courtTypeId,
                    appealno = Appealno,
                    VJudCourt = vJudCourt,
                    court_type = courtTypeId,
                    District = districtName,
                    TahsilName = tahsilName
                };
            }
            else
            {
                rawfile = new
                {
                    accesstoken = AccessTokenDetail,
                    userid = userIdDetail,
                    caseid = strdt,
                    Courtflag = Courtflags
                };
            }
            addfClient.Headers.Add(HttpRequestHeader.ContentType, "application/json");
            string builders = JsonConvert.SerializeObject(rawfile);
            ServicePointManager.SecurityProtocol = SecurityProtocolType.Tls12;
            var resid = addfClient.UploadString(new Uri(apiUrl + "/API/Search/MykaseCauselistData"), "POST", builders);
            JObject jObject = JObject.Parse(resid);
            dynamic data = jObject;
            dynamic dataArray = data["data"];

            List<CauseList> causeLists = new List<CauseList>();
            List<RevenueCauseList> revenueCauseLists = new List<RevenueCauseList>();
            string status = data.Status;
            string message = data.Message;
            if (courtTypeId == "RERH")  // used for Revenue Court Rajasthan
            {
                foreach (var item in dataArray)
                {
                    revenueCauseLists.Add(new RevenueCauseList
                    {
                        vCaseno = item.vcaseno,
                        Appres = item.Appres,
                        vCourt = item.vcourt,
                        Causelistdate = item.vCauselistDate
                    });
                }
                return Json(revenueCauseLists, JsonRequestBehavior.AllowGet);
            }
            else
            {
                foreach (var item in dataArray) // used for other courts
                {
                    causeLists.Add(new CauseList
                    {
                        Filetext = item.Filetext,
                        Casename = item.Casename,
                        CourtId = item.CourtId,
                        Bench = item.Bench,
                        Causelistdate = item.Causelistdate
                    });
                }
                return Json(causeLists, JsonRequestBehavior.AllowGet);
            }
        }
