        /// <summary>
        /// Send case order file details
        /// </summary>
        [AuthLog(Roles = "Firm,User")]
        [HttpPost]
        [ValidateInput(false)]
        public void Sendcaseorderfile()
        {
            System.Text.RegularExpressions.Regex rx = new System.Text.RegularExpressions.Regex("<[^>]*>");
            try
            {
                var sendfile = "";
                var email = QueryAES.UrlDecode(Request.Form["email"]);
                var token = QueryAES.UrlDecode(Request.Form["ftoken"]);
                token = token.ToString().Replace(" ", "+");
                token = QueryAES.DecryptAes(QueryAES.FromBase64StringWithReplace(token));
                var casetoken = QueryAES.UrlDecode(Request.Form["casetoken"]);
                casetoken = casetoken.ToString().Replace(" ", "+");
                casetoken = QueryAES.DecryptAes(QueryAES.FromBase64StringWithReplace(casetoken));
                var mailfilename = QueryAES.UrlDecode(Request.Form["mailfilename"]);
                var emailbody = QueryAES.UrlDecode(Request.Form["mailbody"]);
                var emailsubject = QueryAES.UrlDecode(Request.Form["mailsubject"]);
                emailsubject = removeSpecialCharacter(emailsubject);
                var roleid = LoggedInUser.RoleId;
                var db = new LawPracticeEntities();
                HttpWebRequest request = (HttpWebRequest)HttpWebRequest.Create(token);
                try
                {
                    var folderPath = Server.MapPath("~/CaseOrders/" + LoggedInUser.FirmId + "/" + LoggedInUser.UserId + "/");
                    if (!Directory.Exists(folderPath))
                    {
                        //If Directory (Folder) does not exists. Create it.
                        Directory.CreateDirectory(folderPath);
                    }
                    string filename = "";
                    using (HttpWebResponse response = (HttpWebResponse)request.GetResponseAsync().Result)
                    {
                        string path = response.Headers["Content-Disposition"];
                        if (string.IsNullOrWhiteSpace(path))
                        {
                            var uri = new Uri(token);
                            filename = Path.GetFileName(uri.LocalPath);
                        }
                        else
                        {
                            System.Net.Mime.ContentDisposition contentDisposition = new System.Net.Mime.ContentDisposition(path);
                            filename = contentDisposition.FileName;
                        }
                        sendfile = Path.Combine(folderPath, filename);
                        using (FileStream fileStream = new FileStream(System.IO.Path.Combine(folderPath, filename), FileMode.OpenOrCreate, FileAccess.ReadWrite, FileShare.ReadWrite))
                        {
                            var responseStream = response.GetResponseStream();
                            responseStream.CopyTo(fileStream);
                            responseStream.Flush();
                            responseStream.Close();
                            response.Close();
                            fileStream.Flush();
                            fileStream.Dispose();
                            fileStream.Close();
                        }
                    }
                }
                catch (Exception er)
                {
                }
                string fromemail = WebConfigurationManager.AppSettings["fromemail"].ToString();
                CommomUtility obj1 = new CommomUtility();
                var username = db.usp_GetUserNameById(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString()).FirstOrDefault();
                string AssignmentSubmittedMailBody = WebConfigurationManager.AppSettings["basicmailtemplate"].ToString();
                AssignmentSubmittedMailBody = AssignmentSubmittedMailBody.Replace("#CONTENT#", emailbody.ToString());
                obj1.SendEmail(fromemail, email, "", emailsubject, AssignmentSubmittedMailBody, sendfile);
                try
                {
                    FileInfo fd = new FileInfo(sendfile);
                    fd.Delete();
                }
                catch (Exception er)
                {
                }
            }
            catch (Exception ex)
            {
            }
        }
