           .Select(e => new { e.Disposeddt, e.EventType }) // Project to an anonymous type
           .Distinct() // Get distinct combinations
           .ToList();
            // Group data by date
            var groupedData = next.Where(t => t.Disposeddt.Month == DateTime.Now.Month & t.Disposeddt.Year == DateTime.Now.Year).GroupBy(item => item.Disposeddt).OrderBy(d => d.Key).ToList();
            //var groupedData = groupedData1.Select(i => new { i.Key}).Distinct().ToList();

            // var groupedData = groupedData1.Select(f => new List<string>() { f.Disposeddt, f.EventType }).SelectMany(item => item).Distinct();
            // Generate calHTML
            string calhtml = "";
            foreach (var group in groupedData)
            {
                string datecss = "selected-date";
                string timecss = "time";
                int c = 0;
                calhtml += " <div class=" + datecss + "><div class=text58>" + Convert.ToDateTime(group.Key).ToString("dddd MMM dd, yyyy") + "</div>";
                calhtml += "<div class=events>";
                foreach (var item in group)
                {
                    string calendareventmonthview = "calendar-eventmonth-view";
                    if (item.EventType == "Order") calendareventmonthview = "calendar-eventmonth-view1";
                    if (item.EventType == "Event") calendareventmonthview = "calendar-eventmonth-view2";
                    if (item.EventType == "Task") calendareventmonthview = "calendar-eventmonth-view3";
                    if (item.EventType == "Court Hearing") calendareventmonthview = "calendar-eventmonth-view4";



                    calhtml += "<div class=" + calendareventmonthview + "><div class=text-and-time><div class=event>" + item.EventType + "<div class=" + timecss + "></div></div></div></div>";

                }
                calhtml += "</div>";
                calhtml += "</div>";
                datecss = datecss + c;
                timecss = timecss + c;
                c = c + 1;
            }
            calhtml += "</div>";
            return calhtml;
        }
