            try
            {
                var data = db.getstartupcode().FirstOrDefault();
                if (data != null)
                {
                    var verify = data.StartUpCode;
                    if (verify.ToString() == scode)
                    {
                        Session["validateStartup"] = "success";
                        return "true";
                    }
                    else
                    {
                        Session["validateStartup"] = null;
                    }
                }
            }
            catch (Exception er)
