            //try
            //{
            //    var list = db.usp_CaseCommuniquelistCount(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString(), "", Convert.ToInt32(1), Convert.ToInt32(1), "", "", "", "", "", Convert.ToInt32(0)).ToList();
            //    ViewBag.commreceivedcount = list[0].totRow;
            //}
            //catch (Exception ex)
            //{
            //}
            try
            {
                var datacount = db.usp_DashboardclientCount(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString(), Convert.ToInt32(0)).FirstOrDefault();
                ViewBag.clientcount = datacount;
            }
            catch (Exception ex)
            {
            }
            try
            {
                ViewBag.livetracking = 0;
                ViewBag.pendingtracking = 0;
                ViewBag.failedtracking = 0;
                string userId = "", firmId = "";
                firmId = LoggedInUser.FirmId.ToString();
                var roleid = Convert.ToInt32(LoggedInUser.RoleId);

                DataTable resid = DataAccessADO.GetMatterTrackingStatus(firmId, LoggedInUser.UserId.ToString(), roleid);
                for (int i = 0; i < resid.Rows.Count; i++)
                {
                    if (Convert.ToString(resid.Rows[i]["MatterStatus"]) == "Live Tracking")
                    {
                        ViewBag.livetracking = Convert.ToString(resid.Rows[i]["mcount"]);
                    }
                    if (Convert.ToString(resid.Rows[i]["MatterStatus"]) == "Pending Tracking")
                    {
                        ViewBag.pendingtracking = Convert.ToString(resid.Rows[i]["mcount"]);
                    }
                    if (Convert.ToString(resid.Rows[i]["MatterStatus"]) == "Failed Tracking")
                    {
                        ViewBag.failedtracking = Convert.ToString(resid.Rows[i]["mcount"]);
                    }
                }

            }
            catch (Exception ex) { }
            ViewBag.firmcode = LoggedInUser.FirmCode;
            ViewBag.pagesize = System.Configuration.ConfigurationManager.AppSettings["pagesize"];
            return View();
        }
