        {
            useridytpe = useridytpe.Replace(@"\", "");
            if (useridytpe == "1" || useridytpe == "2")
            {
                var trialList_1 = db.usp_GetUserbyId(LoggedInUser.FirmId.ToString(), useridytpe).Where(x => x.UserName != null).ToList();
                var trialList = (from ob in trialList_1
                                 select new
                                 {
                                     label = ob.UserName + " -(" + ob.RoleName + ")",
                                     val = ob.id,
                                     roleid = ob.roleid,
                                     role = ob.RoleName,
                                     Partnerid = ob.PartnerId
                                 }).ToList();
                return Json(trialList, JsonRequestBehavior.AllowGet);
            }
            else
            {
                var trialList_1 = db.usp_GetUserbyPartnerId(LoggedInUser.FirmId.ToString(), useridytpe).Where(x => x.UserName != null).ToList();
                var trialList = (from ob in trialList_1
                                 select new
                                 {
                                     label = ((ob.PartnerId == "" || ob.PartnerId == null || ob.PartnerId == "null") ? ob.UserName + " -( " + ob.RoleName + " )" : (ob.PartnerId.ToString().ToLower() == LoggedInUser.UserId.ToString().ToLower() ? ob.UserName + " -( " + ob.RoleName + " )" : ob.UserName + " - (" + ob.RoleName + ")--(" + ob.PartnerName + ")")),
                                     val = ob.id,
                                     roleid = ob.roleid,
                                     role = ob.RoleName,
                                     Partnerid = ob.PartnerId
                                 }).ToList();
                return Json(trialList, JsonRequestBehavior.AllowGet);
            }
        }
        /// <summary>
        /// Create case details
        /// </summary>
        /// <returns></returns>
        [AuthLog(Roles = "Firm,User")]
        public ActionResult CreateCase()
        {
            var NoticeId = QueryAES.UrlDecode(Request.Form["NoticeId"]);
            try
            {
                Guid.Parse(NoticeId);
                ViewBag.NoticeId = NoticeId;
            }
            catch
            {
                ViewBag.NoticeId = "";
            }
            ViewBag.pagesize = System.Configuration.ConfigurationManager.AppSettings["pagesize"];
            ViewBag.filesize = ConfigurationManager.AppSettings["filesize"];
            var db = new LawPracticeEntities();
            var checkmodule = db.usp_Getfimpack(LoggedInUser.FirmId.ToString()).FirstOrDefault();
            if (checkmodule != null)
            {
                ViewBag.Module = checkmodule.Value;
            }
            var user = LoggedInUser.FirmId;
            var chckispartner = db.usp_CheckIsPartner(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString()).FirstOrDefault();
            if (chckispartner == 1)
            {
                var trialList_1 = db.usp_GetUserbyPartnerId(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString()).ToList();
                var trialList = (from ob in trialList_1
                                 select new
                                 {
                                     label = ((ob.PartnerId == "" || ob.PartnerId == null || ob.PartnerId == "null") ? ob.UserName + " -(" + ob.RoleName + ")" : (ob.PartnerId.ToString().ToLower() == LoggedInUser.UserId.ToString().ToLower() ? ob.UserName + " -(" + ob.RoleName + ")" : ob.UserName + " - (" + ob.RoleName + ")--(" + ob.PartnerName + ")")),
                                     val = ob.id,
                                     roleid = ob.roleid,
                                     role = ob.RoleName,
                                     Partnerid = ob.PartnerId
                                 }).ToList();
                ViewBag.Users = trialList;
            }
            else
            {
                var trialList_1 = db.usp_GetUserbyId(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString()).ToList();
                var trialList = (from ob in trialList_1
                                 select new
                                 {
                                     label = ob.UserName + " -(" + ob.RoleName + ")",
                                     val = ob.id,
                                     roleid = ob.roleid,
                                     role = ob.RoleName,
                                     Partnerid = ob.PartnerId
                                 }).ToList();
                ViewBag.Users = trialList;
            }
            try
            {
                var ct = db.sp_DeleteMatterTypeDetailsTemp(null, LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString(), 1);
                var ct1 = db.sp_DeleteCaseFilingDateTemp(null, LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString(), 1);
            }
            catch (Exception rt)
            {
            }
            //customisation for PMRDA
            if (LoggedInUser.FirmId.ToString().ToUpper() == ConfigurationManager.AppSettings["IPRDACustomization"].ToUpper())
            {
                ViewBag.IPRDACustomtype = "IPRDACustomtype";
            }
            //customisation for IOCL
            if (LoggedInUser.FirmId.ToString().ToUpper() == ConfigurationManager.AppSettings["IOCLCustomization"].ToUpper())
            {
                ViewBag.IOCLCustomtype = "IOCLCustomtype";
            }
            //End customisation of IOCL
            //customisation for Indusind
            if (LoggedInUser.FirmId.ToString().ToUpper() == ConfigurationManager.AppSettings["Indusindcustomization"].ToUpper())
            {
                ViewBag.IndusindCustomtype = "Indusindcustomtype";
            }
            //End customisation for Indusind
            return View();
        }
