        /// <summary>
        /// Export new standard cases in excel
        /// </summary>
        [AuthLog(Roles = "Firm,User")]
        public void ExportoExcelNewStandardCases()
        {
            try
            {
                var esearchdata = QueryAES.UrlDecode(Request.QueryString["esearchdata"]);
                var ecasefilterdate = QueryAES.UrlDecode(Request.QueryString["ecasefilterdate"]);
                var ecasefilterclient = QueryAES.UrlDecode(Request.QueryString["ecasefilterclient"]);
                var createdby = QueryAES.UrlDecode(Request.QueryString["createdby"]);
                var exportcolumn = QueryAES.UrlDecode(Request.QueryString["exportcolumn"]);
                var esearchdatanotes = QueryAES.UrlDecode(Request.QueryString["esearchdatanotes"]);
                var CFieldtype = QueryAES.UrlDecode(Request.QueryString["CFieldtype"]);
                try
                {
                    ecasefilterclient = ecasefilterclient.Replace(" ", "+");
                    ecasefilterclient = QueryAES.DecryptAes(QueryAES.FromBase64StringWithReplace(ecasefilterclient));
                }
                catch
                {
                }
                var ecasefiltercourt = QueryAES.UrlDecode(Request.QueryString["ecasefiltercourt"]);
                var ecasefilterstatus = QueryAES.UrlDecode(Request.QueryString["ecasefilterstatus"]);
                var ecasefiltercompanyname = QueryAES.UrlDecode(Request.QueryString["ecasefiltercompanyname"]);
                var ecasefiltermattertype = QueryAES.UrlDecode(Request.QueryString["ecasefiltermattertype"]);
                var ecasefiltersubjecttype = QueryAES.UrlDecode(Request.QueryString["ecasefiltersubjecttype"]);
                var searchuser = QueryAES.UrlDecode(Request.QueryString["eusers"]);
                string exlfilename = "MatterReport_" + DateTime.Now;
                int pagenum = 1;
                int pagesize = 1000;
                var db = new LawPracticeEntities();
                var GetCustomFieldHeaderList = db.usp_GetFirmConfiguredCustomFields(LoggedInUser.FirmId.ToString(), CFieldtype).ToList();
                if (LoggedInUser.RoleId == 1)
                {
                    if (String.IsNullOrEmpty(searchuser))
                    {
                        List<GetNewStandardCaseDetailByRowId_Result> trialList_1 = new List<GetNewStandardCaseDetailByRowId_Result>();
                        trialList_1 = db.GetNewStandardCaseDetailByRowId(LoggedInUser.FirmId, LoggedInUser.UserId, pagenum, pagesize, ecasefilterdate, esearchdata, ecasefilterclient, ecasefiltercourt, ecasefilterstatus, createdby, 0, ecasefiltercompanyname, ecasefiltermattertype, ecasefiltersubjecttype, esearchdatanotes).ToList();
                        StringBuilder sb = new StringBuilder();
                        foreach (var data in trialList_1.ToList())
                        {
                            GetNewStandardCaseDetailByRowId_Result newItem = new GetNewStandardCaseDetailByRowId_Result();
                            sb.Clear();
                            newItem.Id = Convert.ToBase64String(QueryAES.EncryptAes(data.Id.ToString()));
                            trialList_1[trialList_1.IndexOf(data)].Id = newItem.Id;
                            if (data.UserCaseid != null)
                            {
                                newItem.UserCaseid = Convert.ToBase64String(QueryAES.EncryptAes(data.UserCaseid.ToString()));
                                trialList_1[trialList_1.IndexOf(data)].UserCaseid = newItem.UserCaseid;
                            }
                        }
                        var trialList = (from ob in trialList_1
                                         select new
                                         {
                                             StartDate = String.Format("{0:dd MMM yyyy}", ob.odate),
                                             MatterName = ob.mname,
                                             CompanyName = ob.CompanyName,
                                             ClientContact = ob.PrimaryContactName,
                                             MatterType = ob.MatterType,
                                             CreatedBy = ob.assignuserby,
                                             TeamMembers = ob.assignuserto,
                                             EditDate = String.Format("{0:dd MMM yyyy}", ob.LastModifyDate),
                                             Status = ob.cstatus,
                                             Notes = ob.Notes,
                                         }).ToList();
                        var gv = new GridView();
                        gv.DataSource = trialList;
                        gv.DataBind();
                        var chkcvaues = exportcolumn;
                        string[] nums = chkcvaues.Split(',');
                        try
                        {
                            //start change header text
                            int CFieldsstartinxdex = 27;
                            foreach (var data in GetCustomFieldHeaderList)
                            {
                                gv.HeaderRow.Cells[CFieldsstartinxdex].Text = data.FieldName;
                                CFieldsstartinxdex = CFieldsstartinxdex + 1;
                            }
                            //end change header text
                        }
                        catch (Exception ex)
                        {
                        }
                        for (int j = 0; j < gv.HeaderRow.Cells.Count; j++)
                        {
                            gv.HeaderRow.Cells[j].Visible = false;
                            foreach (GridViewRow itemrow in gv.Rows)
                            {
                                var sd = itemrow.Cells[0].Text;
                                itemrow.Cells[j].Visible = false;
                            }
                        }
                        for (int j = 0; j < gv.HeaderRow.Cells.Count; j++)
                        {
                            var cdd = gv.HeaderRow.Cells[j].Text;
                            if (nums.Contains(cdd))
                            {
                                gv.HeaderRow.Cells[j].Visible = true;
                                foreach (GridViewRow itemrow in gv.Rows)
                                {
                                    itemrow.Cells[j].Visible = true;
                                }
                            }
                        }
                        gv.HeaderStyle.BackColor = Color.Gray;
                        gv.HeaderStyle.ForeColor = Color.White;
                        Response.ClearContent();
                        Response.Buffer = true;
                        Response.AddHeader("content-disposition", "attachment; filename=" + exlfilename + ".xls");
                        Response.ContentType = "application/ms-excel";
                        Response.Charset = "";
                        StringWriter objStringWriter = new StringWriter();
                        HtmlTextWriter objHtmlTextWriter = new HtmlTextWriter(objStringWriter);
                        gv.RenderControl(objHtmlTextWriter);
                        Response.Output.Write(objStringWriter.ToString());
                        Response.Flush();
                        Response.End();
                    }
                    else
                    {
                        int pageid = 0;
