        /// <summary>
        /// Link notice to case
        /// </summary>
        /// <returns></returns>
        [AuthLog(Roles = "Firm,User")]
        public ActionResult NoticeLinkCaseList()
        {
            ViewBag.pagesize = System.Configuration.ConfigurationManager.AppSettings["pagesize"];
            ViewBag.filesize = ConfigurationManager.AppSettings["filesize"];
            if (LoggedInUser.RoleId == 2)
            {
                ViewBag.IsCreate = 0;
                ViewBag.IsEdit = 0;
                ViewBag.IsDelete = 0;
                ViewBag.export = 0;
                ViewBag.share = 0;
                ViewBag.enable = 0;
                var data = checkroles();
                // Split authors separated by a comma followed by space  
                string[] values = data.Split(',');
                for (int i = 0; i < values.Length; i++)
                {
                    if (i == 0)
                    {
                        ViewBag.IsCreate = values[i];
                    }
                    if (i == 1)
                    {
                        ViewBag.IsEdit = values[i];
                    }
                    if (i == 2)
                    {
                        ViewBag.IsDelete = values[i];
                    }
                    if (i == 3)
                    {
                        ViewBag.export = values[i];
                    }
                    if (i == 5)
                    {
                        ViewBag.share = values[i];
                    }
                    if (i == 6)
                    {
                        ViewBag.enable = values[i];
                    }
                }
            }
            return View();
        }
        /// <summary>
        /// Check roles
        /// </summary>
        /// <returns></returns>
        public string checkroles()
        {
            var urlsegment = Request.Url.Segments[3];
            urlsegment = urlsegment.Replace("/", "");
            var db = new LawPracticeEntities();
            var foutput = true;
            var frmids = Session["sessionfirmid"].ToString();
            var usrids = Session["sessionuserid"].ToString();
            int rlid = Convert.ToInt32(Session["sessionroleid"].ToString());
            var finalresult = "";
            int pageid = 0;
            var sflag = true;
            if (LoggedInUser.RoleId == 2)
            {
                var pagelist = db.usp_GetRightsPageDatabyPagelink(Convert.ToString(urlsegment)).ToList();
                if (pagelist.Count > 0)
                {
                    foreach (var data in pagelist)
                    {
                        int pwrite = 0, pview = 0, pedit = 0, pdel = 0, pviewall = 0, peditall = 0;
                        pageid = Convert.ToInt32(data.ParentPage);
                        pwrite = Convert.ToInt32(data.Write);
                        pview = Convert.ToInt32(data.View);
                        pedit = Convert.ToInt32(data.Edit);
                        pdel = Convert.ToInt32(data.Delete);
                        pviewall = Convert.ToInt32(data.ViewAll);
                        peditall = Convert.ToInt32(data.EditAll);
                        // dynamic pageaccesslist;
                        DataTable pageaccesslist = new DataTable();
                        if (urlsegment == "caselist" || urlsegment == "NewCaseDashboard" || urlsegment == "Casedetails" || urlsegment == "EditCase" || urlsegment == "CreateCase" || urlsegment == "StandardCaseList")
                        {
                            pageaccesslist = DataAccessADO.GetUserCaseModuleRights(frmids, usrids, usrids, pageid);
                            //  pageaccesslist = 1db.usp_GetUserCaseModuleRights(frmids, usrids, usrids, pageid).ToList();
                        }
                        else
                        {
                            // pageaccesslist = db.usp_GetUserModuleRights(frmids, usrids, usrids, pageid).ToList();
                            pageaccesslist = DataAccessADO.GetUserModuleRights(frmids, usrids, usrids, pageid);
                        }
                        int write = 0, view = 0, edit = 0, del = 0, viewall = 0, editall = 0, share = 0, enable = 0, export = 0, timespecialright = 0;
                        for (int i = 0; i < pageaccesslist.Rows.Count; i++)
                        {
                            write = Convert.ToInt32(pageaccesslist.Rows[i]["Write"]);
                            view = Convert.ToInt32(pageaccesslist.Rows[i]["View"]);
                            edit = Convert.ToInt32(pageaccesslist.Rows[i]["Edit"]);
                            del = Convert.ToInt32(pageaccesslist.Rows[i]["Delete"]);
                            viewall = Convert.ToInt32(pageaccesslist.Rows[i]["ViewAll"]);
                            editall = Convert.ToInt32(pageaccesslist.Rows[i]["EditAll"]);
                            timespecialright = Convert.ToInt32(pageaccesslist.Rows[i]["TimeEntrySpecialRights"]);
                            ViewBag.IsViewAll = viewall;
                            ViewBag.share = 0;
                            ViewBag.enable = 0;
                            ViewBag.export = 0;
                            try
                            {
                                ViewBag.share = Convert.ToInt32(pageaccesslist.Rows[i]["Share"]);
                                ViewBag.enable = Convert.ToInt32(pageaccesslist.Rows[i]["Enable"]);
                                ViewBag.export = Convert.ToInt32(pageaccesslist.Rows[i]["Export"]);
                                ViewBag.Create = Convert.ToInt32(pageaccesslist.Rows[i]["Share"]);
                                ViewBag.TimeEntrySpecial = Convert.ToInt32(pageaccesslist.Rows[i]["TimeEntrySpecialRights"]);
                            }
                            catch
                            {
                            }
                            if (viewall > 0 || editall > 0)
                            {
                                foutput = false;
                                ViewBag.IsDelete = del;
                                ViewBag.IsCreate = write;
                                ViewBag.IsEdit = edit;
                                if (write == 1)
                                {
                                    foutput = false;
                                }
                                if (pedit == 1)
                                {
                                    if (edit == 1 || editall == 1)
                                    {
                                        foutput = false;
                                    }
                                    else
                                    {
                                        foutput = true;
                                    }
                                }
                            }
                            else
                            {
                                // logic for write(create)
                                if (sflag == true)
                                {
                                    if (write > 0)
                                    {
                                        ViewBag.IsCreate = write;
                                        if (pwrite == write)
                                        {
                                            foutput = false;
                                            sflag = false;
                                        }
                                    }
                                    else
                                    {
                                        ViewBag.IsCreate = 0;
                                        foutput = true;
                                    }
                                }
                                //logic for view
                                if (sflag == true)
                                {
                                    if (view > 0)
                                    {
                                        if (pview == view)
                                        {
                                            foutput = false;
                                            sflag = false;
                                        }
                                    }
                                    else
                                    {
                                        foutput = true;
                                    }
                                }
                                //logic for edit(
                                if (sflag == true)
                                {
                                    if (edit > 0)
                                    {
                                        if (pedit == edit)
                                        {
                                            foutput = false;
                                            sflag = false;
                                            ViewBag.IsEdit = edit;
                                        }
                                    }
                                    else
                                    {
                                        foutput = true;
                                    }
                                }
                                //logic for delete
                                ViewBag.IsDelete = 0;
                                if (del > 0)
                                {
                                    ViewBag.IsDelete = 1;
                                }
                                else
                                {
                                    ViewBag.IsDeletes = 0;
                                }
                                ViewBag.TimeEntrySpecial = 0;
                                if (timespecialright > 0)
                                {
                                    ViewBag.TimeEntrySpecial = 1;
                                }
                                else
                                {
                                    ViewBag.TimeEntrySpecial = 0;
                                }
                            }
                        }
                    }
                }
                finalresult = ViewBag.IsCreate + "," + ViewBag.IsEdit + "," + ViewBag.IsDelete + "," + ViewBag.export + "," + ViewBag.share + "," + ViewBag.enable + "," + ViewBag.TimeEntrySpecial;
            }
            return finalresult.ToString();
        }
        /// <summary>
        /// Get client caselist
        /// </summary>
        /// <returns></returns>
        [AuthLog(Roles = "Firm,User")]
        public ActionResult ClientCaseList()
        {
            var clientid = QueryAES.UrlDecode(Request.Form["clienttoken"]);
            try
            {
                clientid = clientid.Replace(" ", "+");
                clientid = QueryAES.DecryptAes(QueryAES.FromBase64StringWithReplace(clientid));
            }
            catch
            {
            }
            if (String.IsNullOrEmpty(clientid))
            {
                return RedirectToAction("Unauthorise", "home");
