        public HearingWithCase HearingWithCaseList()
        {
            ///List<HearingWithCase> Nh = new List<HearingWithCase>();
            LawPracticeEntities db = new LawPracticeEntities();
            string strusername = WebConfigurationManager.AppSettings["matteridname"];
            Guid user = LoggedInUser.UserId;
            Guid firmids = LoggedInUser.FirmId;
            string joined = "";
            string matteridlist = "";
            var rolesuser = LoggedInUser.RoleId;
            joined = joined.TrimEnd(',');
            joined = joined.Replace(",", "','");
            joined = db.usp_GetUnderUserListById(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString(), strusername).FirstOrDefault();
            matteridlist = joined.ToString();
            string strapiuser = matteridlist;
            var apiUrl = WebConfigurationManager.AppSettings["savetocasewatchurl"];
            var addfClient = new WebClient();
            object rawfile = new
            {
                Accesstoken = "mykase123456789abcdef",
                UserId = strapiuser,
            };
            addfClient.Headers.Add(HttpRequestHeader.ContentType, "application/json");
            string builders = JsonConvert.SerializeObject(rawfile);
            ServicePointManager.SecurityProtocol = SecurityProtocolType.Tls12;
            var resid = addfClient.UploadString(new Uri(apiUrl + "/API/Search/NextHearingIfidByUserId"), "POST", builders);
            try
            {
                var db1 = new LawPracticeEntities();
                var param = apiUrl + "FirmController=>HearingWithCaseList=>/API/Search/NextHearingIfidByUserId" + "@" + builders;
                db1.usp_AddAudit(Convert.ToInt32(EventType.Case), Convert.ToInt32(Severity.High), Convert.ToInt32(REQUEST_TYPE.API), Convert.ToString(EventType.Case), Convert.ToString(Severity.High), Convert.ToString(REQUEST_TYPE.API), Guid.Parse(Session["sessionuserid"].ToString()), param, myIP(), GetMacAddress().ToString(), 0, "");
            }
            catch
            {
            }
            dynamic Nh1 = JsonConvert.DeserializeObject<HearingWithCase>(resid);
            return Nh1;
        }
