        /// <summary>
        /// Export client communication in excel
        /// </summary>
        [AuthLog(Roles = "Client")]
        public void ExportoExcelClientCommunication()
        {
            try
            {
                var status = QueryAES.UrlDecode(Request.QueryString["status"]);
                var filtertype = QueryAES.UrlDecode(Request.QueryString["cdcfiltertype"]);
                var filtercreatedby = QueryAES.UrlDecode(Request.QueryString["cdcfiltercreateby"]);
                var brieffilter = QueryAES.UrlDecode(Request.QueryString["commuberiefsearch"]);
                string firmid = LoggedInUser.FirmId.ToString();
                string userid = LoggedInUser.UserId.ToString();
                string exlfilename = "ClientCommunication_Report" + DateTime.Now;
                int pagenum = 1;
                int pagesize = 1000;
                var db = new LawPracticeEntities();
                if (status == "true")
                {
                    List<usp_ClientCommuniquelistExport1_Result> trialList_1 = new List<usp_ClientCommuniquelistExport1_Result>();
                    trialList_1 = db.usp_ClientCommuniquelistExport1(firmid, userid, filtertype, filtercreatedby, brieffilter).ToList();
                    StringBuilder sb = new StringBuilder();
                    foreach (var data in trialList_1.ToList())
                    {
                        if (data.TotalcaseUser == data.TotalCommuUser)
                        {
                            trialList_1[trialList_1.IndexOf(data)].assignuserto = "ALL TEAM";
                        }
                        usp_ClientCommuniquelistExport1_Result newItem = new usp_ClientCommuniquelistExport1_Result();
                        sb.Clear();
                    }
                    var trialList = (from ob in trialList_1
                                     select new
                                     {
                                         Date = String.Format("{0:dd MMM yyyy}", ob.CreateDate),
                                         //Type = ob.InformationType,
                                         Brief = ob.Brief,
                                         Createdby = ob.Createdby,
                                         assignuser = ob.assignuserto,
                                         DocsCount = ob.DocsCount,
                                     }).ToList();
                    var gv = new GridView();
                    gv.DataSource = trialList;
                    gv.DataBind();
                    gv.HeaderStyle.BackColor = Color.Gray;
                    gv.HeaderStyle.ForeColor = Color.White;
                    Response.ClearContent();
                    Response.Buffer = true;
                    Response.AddHeader("content-disposition", "attachment; filename=" + exlfilename + ".xls");
                    Response.ContentType = "application/ms-excel";
                    Response.Charset = "";
                    StringWriter objStringWriter = new StringWriter();
                    HtmlTextWriter objHtmlTextWriter = new HtmlTextWriter(objStringWriter);
                    gv.RenderControl(objHtmlTextWriter);
                    Response.Output.Write(objStringWriter.ToString());
                    Response.Flush();
                    Response.End();
                }
            }
            catch (Exception ex)
            {
                Response.Redirect("/home/Error");
            }
        }
