                            strtemplate += "<tr><td height = '20' align = 'left' valign ='top'  style='padding:0 5px;' >" + String.Format("{0:dd MMM yyyy}", idata.CreateDate) + " </td>";
                            strtemplate += "<td height = '20' align = 'left' valign ='top' style='padding:0 5px;'> " + idata.InformationType + "  </td>";
