                            strtemplate += "<td height = '20' align = 'left' valign ='top' style='padding:0 5px;'> " + idata.assignuserto + " </td>";
                            strtemplate += "<td height = '20' align = 'left' valign ='top' style='padding:0 5px;'> " + idata.DocsCount + " </td>";
