                        }
                        strtemplate += "</tbody></table>";
                    }
                    else
                    {
                    }
                }
                string folderPath = Server.MapPath("~/Documents/ExportData/Pdf/" + firmid + "/" + userid + "/");
                if (!Directory.Exists(folderPath))
                {
                    Directory.CreateDirectory(folderPath);
