        /// <summary>
        /// Get user task list
        /// </summary>
        /// <returns></returns>
        [AuthLog(Roles = "Firm,User")]
        public ActionResult UserTask()
        {
            ViewBag.token = "";
            var token = QueryAES.UrlDecode(Request.Form["token"]);
            var Tid = QueryAES.UrlDecode(Request.Form["Tidss"]);
            var newtoken = token;
            //check type of task
            var db = new LawPracticeEntities();
            try
            {
                newtoken = newtoken.Replace(" ", "+");
                newtoken = QueryAES.DecryptAes(QueryAES.FromBase64StringWithReplace(newtoken));
            }
            catch
            {
            }
            var typeflag = "";
            var checkcaseornot = db.usp_gettaskdetailsbyid(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString(), newtoken).FirstOrDefault();
            if (checkcaseornot != null)
            {
                if (checkcaseornot.Isarchive == 1)
                {
                    typeflag = "Archive";
                }
                else if (checkcaseornot.AssignTaskStatus == null && checkcaseornot.UserId == LoggedInUser.UserId)
                {
                    typeflag = "Outbox";
                }
                else if (checkcaseornot.AssignTaskStatus == null && checkcaseornot.AssignUser == LoggedInUser.UserId)
                {
                    typeflag = "Inbox";
                }
                else
                {
                    typeflag = "";
                }
            }
            ViewBag.pagesize = System.Configuration.ConfigurationManager.AppSettings["pagesize"];
            ViewBag.filesize = ConfigurationManager.AppSettings["filesize"];
            ViewBag.token = token;
            ViewBag.tdate = Tid;
            ViewBag.modulename = typeflag;
            return View();
        }
        /// <summary>
        /// Export all standard contact list in excel
        /// </summary>
        [AuthLog(Roles = "Firm,User")]
        public void ExportoExcelAllStandardContactList()
        {
            try
            {
                var searchdata = QueryAES.UrlDecode(Request.QueryString["searchdata"]);
                var iscomorindv = QueryAES.UrlDecode(Request.QueryString["category"]);
                var pagetype = QueryAES.UrlDecode(Request.QueryString["pagetype"]);
                var type = QueryAES.UrlDecode(Request.QueryString["TYPE"]);

                string exlfilename = "ContactsList_" + DateTime.Now;

                var db = new LawPracticeEntities();



                int pageid = 0;

                var profiletype = "";




                var pagelist = db.usp_GetRightsPageDatabyPagelink(Convert.ToString("ContactsList")).FirstOrDefault();
                if (pagelist != null)
                {
                    pageid = Convert.ToInt32(pagelist.ParentPage);
                }

                if (type.ToString().ToUpper() == "ALL" || type.ToString().ToUpper() == "CLIENT")
                {

                    if (type.ToLower() == "all")
                    {
                        profiletype = "";
                    }
                    else
                    {
                        var clientprofiletype = db.usp_getcontacttypebyname().FirstOrDefault();
                        profiletype = clientprofiletype.ToString();
                    }
                    StringBuilder sb = new StringBuilder();

                    List<GetAllStandardContactsDetailsByRowId_Result> list = new List<GetAllStandardContactsDetailsByRowId_Result>();

                    //list = db.GetContactDetails(Guid.Parse(uid)).ToList();
                    list = db.GetAllStandardContactsDetailsByRowId(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString(), 1, int.MaxValue, 0, searchdata, profiletype, pageid, iscomorindv).ToList();



                    foreach (var data in list.ToList())
                    {
                        sb.Clear();
                        GetAllContactsDetailsByRowId_Result newItem = new GetAllContactsDetailsByRowId_Result();

                        newItem.cid = Convert.ToBase64String(QueryAES.EncryptAes(data.cid.ToString()));

                        list[list.IndexOf(data)].cid = newItem.cid;


                    }


                    var trialList = (from ob in list
                                     select new
                                     {
                                         SlNo = ob.rownum,
                                         FullName = ReplaceString(String.IsNullOrEmpty(ob.fname) ? ob.fname : ob.fname + " " + (ob.mname == null ? " " : ob.mname) + " " + (ob.lname == null ? " " : ob.lname)),
                                         CompanyName = ReplaceString(String.IsNullOrEmpty(ob.CompanyName) ? ob.CompanyName : ob.CompanyName),
                                         Type = ReplaceString(ob.ProfileType),
                                         Email = ReplaceString(ob.cemail),
                                         Mobile = String.IsNullOrEmpty(ob.mobno) ? ob.mobno : ob.mobno,
                                         Address = ReplaceString((String.IsNullOrEmpty(ob.cadd1) ? ob.cadd1 : ob.cadd1)),
                                         State = ReplaceString(ob.State),
                                         City = ReplaceString(ob.City),
                                         Country = ReplaceString(ob.Country),
                                         Date = String.Format("{0:dd MMM yyyy}", ob.date_time) + " " + String.Format("{0:HH:mm:ss}", ob.date_time)

                                     }).ToList();


                    var gv = new GridView();
                    gv.DataSource = trialList;
                    gv.DataBind();
                    if (iscomorindv == "0")
                    {
                        var chkcvaues = "SlNo,FullName,Type,Email,Mobile,Address,State,City,Country,Date";
                        string[] nums = chkcvaues.Split(',');


                        for (int j = 0; j < gv.HeaderRow.Cells.Count; j++)
                        {

                            gv.HeaderRow.Cells[j].Visible = false;

                            foreach (GridViewRow itemrow in gv.Rows)
                            {
                                var sd = itemrow.Cells[0].Text;
                                itemrow.Cells[j].Visible = false;

                            }
                        }
