        /// <summary>
        /// Export all clint in excel
        /// </summary>
        [AuthLog(Roles = "Firm,User")]
        public void ExportoExcelAllClientList()
        {
            try
            {
                var category = QueryAES.UrlDecode(Request.QueryString["category"]);
                var searchdata = QueryAES.UrlDecode(Request.QueryString["searchdata"]);
                var exportfilterdata = QueryAES.UrlDecode(Request.QueryString["exportfilter"]);
                var pagetype = QueryAES.UrlDecode(Request.QueryString["pagetype"]);
                var CFieldtype = QueryAES.UrlDecode(Request.QueryString["CFieldtype"]);
                var exportcolumn = QueryAES.UrlDecode(Request.QueryString["exportcolumn"]);
                string exlfilename = "AllContactsList_" + DateTime.Now;
                var db = new LawPracticeEntities();
                int pageid = 0;
                var profiletype = "";
                var GetCustomFieldHeaderList = db.usp_GetFirmConfiguredCustomFields(LoggedInUser.FirmId.ToString(), CFieldtype).ToList();
                var pagelist = db.usp_GetRightsPageDatabyPagelink(Convert.ToString("ContactsList")).FirstOrDefault();
                if (pagelist != null)
                {
                    pageid = Convert.ToInt32(pagelist.ParentPage);
                }
                List<GetAllContactsDetailsByRowId_Result> trialList_1 = new List<GetAllContactsDetailsByRowId_Result>();
                trialList_1 = db.GetAllContactsDetailsByRowId(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString(), 1, int.MaxValue, 0, searchdata, profiletype, pageid, category).OrderBy(x => x.rownum).ToList();
                var actionmode = "";
                var recentlabel = "";
                GetAllContactsDetailsByRowId_Result Item = new GetAllContactsDetailsByRowId_Result();
                int count = trialList_1.Count;
                var trialList = (from ob in trialList_1
                                 select new
                                 {
                                     ProfileType = ob.ProfileType,
                                     CompanyName = ReplaceString(ob.CompanyName),
                                     ClientType = ob.IsCompany,
                                     FirstName = ReplaceString(String.IsNullOrEmpty(ob.fname) ? ob.fname : ob.fname),
                                     LastName = ReplaceString(String.IsNullOrEmpty(ob.lname) ? ob.lname : ob.lname),
                                     Mobile = String.IsNullOrEmpty(ob.mobno) ? ob.mobno : ob.mobno,
                                     Email = ReplaceString(ob.cemail),
                                     CreatedBy = ReplaceString(ob.CreatedBy),
                                     UserName = ReplaceString(ob.Username),
                                     Address = ReplaceString(String.IsNullOrEmpty(ob.cadd1) ? ob.cadd1 : ob.cadd1),
                                     Website = ReplaceString(ob.cwebsite),
                                     Designation = ReplaceString(ob.Designation),
                                     AddInfo = ReplaceString(ob.cnotes),
                                     Pin = ob.Pin,
                                     Country = ReplaceString(ob.Country),
                                     State = ReplaceString(ob.State),
                                     City = ReplaceString(ob.City),
                                     col1 = ob.col1,
                                     col2 = ob.col2,
                                     col3 = ob.col3,
                                     col4 = ob.col4,
                                     col5 = ob.col5,
                                     col6 = ob.col6,
                                     col7 = ob.col7,
                                     col8 = ob.col8,
                                     col9 = ob.col9,
                                     col10 = ob.col10,
                                     col11 = ob.col11,
                                     col12 = ob.col12,
                                     col13 = ob.col13,
                                     col14 = ob.col14,
                                     col15 = ob.col15,
                                 }).ToList();
                var gv = new GridView();
                gv.DataSource = trialList;
                gv.DataBind();
                var chkcvaues = exportcolumn;
                string[] nums = chkcvaues.Split(',');
                try
                {
                    //start change header text
                    int CFieldsstartinxdex = 17;
                    foreach (var data in GetCustomFieldHeaderList)
                    {
                        gv.HeaderRow.Cells[CFieldsstartinxdex].Text = data.FieldName;
                        CFieldsstartinxdex = CFieldsstartinxdex + 1;
                    }
                    //end change header text
                }
                catch (Exception ex)
                {
                }
                for (int j = 0; j < gv.HeaderRow.Cells.Count; j++)
                {
                    gv.HeaderRow.Cells[j].Visible = false;
                    foreach (GridViewRow itemrow in gv.Rows)
                    {
                        var sd = itemrow.Cells[0].Text;
                        itemrow.Cells[j].Visible = false;
                    }
                }
                for (int j = 0; j < gv.HeaderRow.Cells.Count; j++)
                {
                    var cdd = gv.HeaderRow.Cells[j].Text;
                    if (nums.Contains(cdd))
                    {
                        gv.HeaderRow.Cells[j].Visible = true;
                        foreach (GridViewRow itemrow in gv.Rows)
                        {
                            itemrow.Cells[j].Visible = true;
                        }
                    }
                }
                gv.HeaderStyle.BackColor = Color.Gray;
                gv.HeaderStyle.ForeColor = Color.White;
                Response.ClearContent();
                Response.Buffer = true;
                Response.AddHeader("content-disposition", "attachment; filename=" + exlfilename + ".xls");
                Response.ContentType = "application/ms-excel";
                Response.Charset = "";
                StringWriter objStringWriter = new StringWriter();
                HtmlTextWriter objHtmlTextWriter = new HtmlTextWriter(objStringWriter);
                gv.RenderControl(objHtmlTextWriter);
                Response.Output.Write(objStringWriter.ToString());
                Response.Flush();
                Response.End();
            }
            catch (Exception ex)
            {
                Response.Redirect("/home/Error");
            }
        }
