        /// <summary>
        /// Get new gant date
        /// </summary>
        /// <returns></returns>
        [AuthLog(Roles = "Firm,User,Client")]
        [HttpPost]
        public string LoadGanttDataNew()
        {
            var firstDay = QueryAES.UrlDecode(Request.Form["firstDay"]);
            var lastDay = QueryAES.UrlDecode(Request.Form["lastDay"]);
            try
            {
                int id = 0;
                var db = new LawPracticeEntities();
                String sb = "", sbjson = "";
                var gmaster = db.usp_GetGanttChartTaskData(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString(), firstDay, lastDay).ToList();
                string[] colors = { "#99FF33", "#00FFFF", "#00FF80", "#0080FF", "#999900", "#CC6600", "#6666FF", "#66FFFF", "#99FF99" };
                List<GaintParent> GPList = new List<GaintParent>();
                List<GaintChildeSeries> GP1List = new List<GaintChildeSeries>();
                if (gmaster.Count > 0)
                {
                    int i = 0;
                    int colori = 0;
                    for (int j = 0; j < gmaster.Count; j++)
                    {
                        GP1List = new List<GaintChildeSeries>();
                        GaintParent GP = new GaintParent();
                        i = i + 1;
                        GP.id = i;
                        GaintChildeSeries GP1 = new GaintChildeSeries();
                        GP1.name = gmaster[j].TaskName;
                        DateTime startdate = new DateTime(Convert.ToDateTime(gmaster[j].TaskStartDate).Year, Convert.ToDateTime(gmaster[j].TaskStartDate).Month, Convert.ToDateTime(gmaster[j].TaskStartDate).Day);
                        //new DateTime(2010, 01, 01);
                        DateTime enddate = new DateTime(Convert.ToDateTime(gmaster[j].TaskendDate).Year, Convert.ToDateTime(gmaster[j].TaskendDate).Month, Convert.ToDateTime(gmaster[j].TaskendDate).Day);//new DateTime(2010, 01, 04);
                                                                                                                                                                                                           //startdate = Convert.ToDateTime("Mon Jan 11 2010 00:00:00 GMT + 0530(India Standard Time)");
                                                                                                                                                                                                           //enddate = Convert.ToDateTime("Wed Feb 03 2010 00:00:00 GMT + 0530(India Standard Time)");
                        GP1.start = startdate;
                        GP1.end = enddate;
                        if (colori > 8)
                        {
                            colori = 0;
                        }
                        GP1.color = colors[colori];
                        GP1List.Add(GP1);
                        colori = colori + 1;
                        GP.series = GP1List;
                        GPList.Add(GP);
                    }
                }
                var result = JsonConvert.SerializeObject(GPList);
                return result;
            }
            catch (Exception ex)
            {
                return "";
            }
        }
        /// <summary>
        /// Download knowledge pdf
        /// </summary>
        /// <returns></returns>
        [AuthLog(Roles = "Firm,User,Client")]
        public ActionResult DownloadPdf()
        {
            var db = new LawPracticeEntities();
            string filepaths = QueryAES.UrlDecode(Request.Form["filepath"]);
            var downloadpathnew = "";
            var fileName = "";
            if (!String.IsNullOrEmpty(filepaths))
            {
                var getknowdetails = db.usp_CheckfolderKnowledge(LoggedInUser.FirmId.ToString(), filepaths).FirstOrDefault();
                fileName = getknowdetails.tfile;
                if (getknowdetails.pfile.ToString() == Guid.Empty.ToString())
                {
                    downloadpathnew = "Documents/Knowledge/" + getknowdetails.Firmid + "/" + getknowdetails.firmuser;
                }
                else
                {
                    var dirfullpath = db.sp_Getknowfilepaths(Guid.Parse(getknowdetails.Firmid.ToString()), Guid.Parse(getknowdetails.firmuser.ToString()), Guid.Parse(getknowdetails.pfile.ToString())).FirstOrDefault();
                    string dirpathname = dirfullpath.ToString();
                    downloadpathnew = "Documents/Knowledge/" + getknowdetails.Firmid + "/" + getknowdetails.firmuser + "/" + dirpathname;
                }
            }
            string fakepathin = Server.MapPath("~/azuredirin/" + LoggedInUser.FirmId + "/" + LoggedInUser.UserId);
            string fakepathout = Server.MapPath("~/azuredirout/" + LoggedInUser.FirmId + "/" + LoggedInUser.UserId);
            if (!Directory.Exists(fakepathin))
            {
                Directory.CreateDirectory(fakepathin);
            }
            if (!Directory.Exists(fakepathout))
            {
                Directory.CreateDirectory(fakepathout);
            }
            var source = AzureDocumentself.Dirfilepath(downloadpathnew, fileName, fakepathin, fakepathout, null, null);
            string[] tokens = source.Split('.');
            if (tokens[1] == "pdf")
            {
                Response.ContentType = "application/pdf";
            }
            else
            {
                Response.ContentType = "application/octet-stream";
            }
            Response.AddHeader("Content-Disposition", "inline; filename=" + source + "");
            Response.Clear();
            Response.WriteFile(source);
            Response.Flush();
            return View();
        }
