                            Type = "Manual Next Hearing",
                            AdvocateName = StripHTML(data.Advname),
                            MatterName = StripHTML(data.Casename),
                            Task_EventName = "",
                            MatterType = data.Casetype,
                            CourtName = data.Court,
                            MatterNo = data.CaseNo + "/" + data.Caseyear,
                        });
                    }
                    else
                    {
                        calendarexport.Add(new CalendarExport
                        {
                            Date = Convert.ToDateTime(String.Format("{0:dd MMM yyyy}", Convert.ToDateTime(data.Disposeddt))),
                            Type = "Next Hearing",
                            AdvocateName = StripHTML(data.Advname),
                            MatterName = StripHTML(data.Casename),
                            Task_EventName = "",
                            MatterType = data.Casetype,
                            CourtName = data.Court,
                            MatterNo = data.CaseNo + "/" + data.Caseyear,
                        });
                    }
                }
            }
            var exlfilename = "CalendarExcelFile";
            var gv = new GridView();
            gv.DataSource = calendarexport.OrderByDescending(x => x.Date).ToList();
            gv.DataBind();
            gv.HeaderStyle.BackColor = Color.Gray;
            gv.HeaderStyle.ForeColor = Color.White;
            Response.ClearContent();
            Response.Buffer = true;
            Response.AddHeader("content-disposition", "attachment; filename=" + exlfilename + ".xls");
            Response.ContentType = "application/ms-excel";
            Response.Charset = "";
            StringWriter objStringWriter = new StringWriter();
            HtmlTextWriter objHtmlTextWriter = new HtmlTextWriter(objStringWriter);
            gv.RenderControl(objHtmlTextWriter);
            Response.Output.Write(objStringWriter.ToString());
            Response.Flush();
            Response.End();
            return View();
        }
        public static string StripHTML(string input)
        {
            if (!String.IsNullOrEmpty(input))
            {
                return Regex.Replace(input, "<.*?>", String.Empty + " ");
            }
            return "";
        }
