            Response.AddHeader("content-disposition", "attachment;filename=" + filename + "");
            Response.Buffer = true;
            ms.WriteTo(Response.OutputStream);
            Response.End();
            return View();
        }
        /// <summary>
        /// Get standard contact list details
        /// </summary>
        /// <returns></returns>
        [AuthLog(Roles = "Firm,User")]
        public ActionResult StandardContactsList()
        {
            ViewBag.pagesize = System.Configuration.ConfigurationManager.AppSettings["pagesize"];
            ViewBag.filesize = ConfigurationManager.AppSettings["filesize"];
            var iscompanyind = QueryAES.UrlDecode(Request.QueryString["c"]);
            ViewBag.iscompanyindv = iscompanyind;
            if (LoggedInUser.RoleId == 2)
            {
                ViewBag.IsCreate = 0;
                ViewBag.IsEdit = 0;
                ViewBag.IsDelete = 0;
                ViewBag.export = 0;
                ViewBag.share = 0;
                ViewBag.enable = 0;
                var data = checkroles();
                // Split authors separated by a comma followed by space  
                string[] values = data.Split(',');
                for (int i = 0; i < values.Length; i++)
                {
                    if (i == 0)
                    {
                        ViewBag.IsCreate = values[i];
                    }
                    if (i == 1)
                    {
                        ViewBag.IsEdit = values[i];
                    }
                    if (i == 2)
                    {
                        ViewBag.IsDelete = values[i];
                    }
                    if (i == 3)
                    {
                        ViewBag.export = values[i];
                    }
                    if (i == 5)
                    {
                        ViewBag.share = values[i];
                    }
                    if (i == 6)
                    {
                        ViewBag.enable = values[i];
                    }
                }
            }
            return View();
        }
        /// <summary>
        /// Import client contact details
        /// </summary>
        /// <returns></returns>
        [FirmControllerAuthorization]
        [HttpPost]
        public JsonResult ImportClientData()
        {
            var db = new LawPracticeEntities();
            var result = "";
            try
            {
                if (Request.Files.Count > 0)
                {
                    string filePath = string.Empty;
                    string extension1 = string.Empty;
                    string path = Server.MapPath("~/Documents/ImportData/ClientData/" + LoggedInUser.FirmId + "/" + LoggedInUser.UserId + "/");
                    if (!Directory.Exists(path))
                    {
                        //If Directory (Folder) does not exists. Create it.
                        Directory.CreateDirectory(path);
                    }
                    for (int i = 0; i < Request.Files.Count; i++)
                    {
                        var postedFile = Request.Files[i];
                        extension1 = postedFile.FileName;
                        var fileName = Path.GetFileName(postedFile.FileName);
                        var fileext = Path.GetExtension(postedFile.FileName);
                        fileName = fileName.Replace(" ", string.Empty);
                        filePath = path + fileName;//HttpContext.Current.Server.MapPath(+ postedFile.FileName);
                        var fileextchk = Path.GetExtension(postedFile.FileName);
                        var is_valid = SaveCommonModulesDocument.chkValidExtension(fileextchk);
                        postedFile.SaveAs(filePath);
                    }
                    string extension = "." + extension1.Split('.')[1];
                    string conString = string.Empty;
                    switch (extension)
                    {
                        case ".xls": //Excel 97-03.
                            conString = ConfigurationManager.ConnectionStrings["Excel03ConString"].ConnectionString;
                            break;
                        case ".xlsx": //Excel 07 and above.
                            conString = ConfigurationManager.ConnectionStrings["Excel07ConString"].ConnectionString;
                            break;
                    }
                    DataTable dt = new DataTable();
                    conString = string.Format(conString, filePath);
                    using (OleDbConnection connExcel = new OleDbConnection(conString))
                    {
                        using (OleDbCommand cmdExcel = new OleDbCommand())
                        {
                            using (OleDbDataAdapter odaExcel = new OleDbDataAdapter())
                            {
                                cmdExcel.Connection = connExcel;
                                //Get the name of First Sheet.
                                connExcel.Open();
                                DataTable dtExcelSchema;
                                dtExcelSchema = connExcel.GetOleDbSchemaTable(OleDbSchemaGuid.Tables, null);
                                string sheetName = dtExcelSchema.Rows[0]["TABLE_NAME"].ToString();
                                connExcel.Close();
                                //Read Data from First Sheet.
                                connExcel.Open();
                                cmdExcel.CommandText = "SELECT * From [" + sheetName + "]";
                                odaExcel.SelectCommand = cmdExcel;
                                odaExcel.Fill(dt);
                                connExcel.Close();
                            }
                        }
                        Guid firmids = LoggedInUser.FirmId;
                        Guid userids = LoggedInUser.UserId;
                        Guid assignto = LoggedInUser.UserId;
                        DateTime date_time = System.DateTime.Now;
                        dt.Columns.Add("Firmid", typeof(System.Guid));
                        dt.Columns.Add("firmuser", typeof(System.Guid));
                        dt.Columns.Add("Assignto", typeof(System.Guid));
                        dt.Columns.Add("date_time", typeof(System.DateTime));
                        foreach (DataRow row in dt.Rows)
                        {
                            row["Firmid"] = firmids;
                            row["firmuser"] = userids;
                            row["date_time"] = date_time;
                            row["Assignto"] = assignto;
                        }
                    }
                    //validate the excel sheet with datatable
                    string FirstName = "", email = "", mobileno = "";
                    string valmsg = "";
                    string valmsg2 = "";
                    for (int d = 0; d < dt.Rows.Count; d++)
                    {
                        FirstName = Convert.ToString(dt.Rows[d]["FirstName"]);
                        email = Convert.ToString(dt.Rows[d]["Email"]);
                        mobileno = Convert.ToString(dt.Rows[d]["MobileNo"]);
                        if (FirstName == "")
                            valmsg += "FirstName ";
                        valmsg = valmsg.Trim().TrimEnd(',');
                        if (email == "")
                            valmsg += ",Email ";
                        if (mobileno == "")
                            valmsg += ",MobileNo ";
                        valmsg = valmsg.Trim().TrimEnd(',');
                        if (valmsg != "")
                        {
                            result = "Unable to Import, " + valmsg + " fields are mandatory. Please check the excel sheet in Row No: " + (Convert.ToInt32(d) + 2);
                            return Json(result, JsonRequestBehavior.AllowGet);
                        }
                        if (valmsg == "")
                        {
                            if (mobileno != "")
                            {
                                // string pattern3 = 
                                if (Regex.IsMatch(mobileno, "^[0-9]{10}$"))
                                {
                                }
                                else
                                {
                                    result = "Unable to Import, Mobile no Should be  Numeric and 10 digits. Please check the excel sheet in Row No: " + (Convert.ToInt32(d) + 2);
                                    return Json(result, JsonRequestBehavior.AllowGet);
                                }
                                var lfirmusercontact = db.ValidateMobileContactWithType(mobileno, "0").FirstOrDefault();
                                if (lfirmusercontact != null)
                                {
                                    result = "Unable to Import,Already Exists Mobile Please Try Another Mobile!. Please check the excel sheet in Row No: " + (Convert.ToInt32(d) + 2);
                                    return Json(result, JsonRequestBehavior.AllowGet);
                                }
                                else
                                {
                                }
                            }
                            if (email != "")
                            {
                                string pattern = null;
                                pattern = "^([0-9a-zA-Z]([-\\.\\w]*[0-9a-zA-Z])*@([0-9a-zA-Z][-\\w]*[0-9a-zA-Z]\\.)+[a-zA-Z]{2,9})$";
                                if (Regex.IsMatch(email, pattern))
                                {
                                }
                                else
                                {
                                    result = "Unable to Import, Email is not valid ! . Please check the excel sheet in Row No: " + (Convert.ToInt32(d) + 2);
                                    return Json(result, JsonRequestBehavior.AllowGet);
                                }
                                var firmuseremail = db.ValidateEmail(email, Guid.Empty.ToString()).FirstOrDefault();
                                if (firmuseremail != null)
                                {
                                    result = "Unable to Import,Email id is already exists. Please try with different Id!. Please check the excel sheet in Row No: " + (Convert.ToInt32(d) + 2);
                                    return Json(result, JsonRequestBehavior.AllowGet);
                                }
                                else
                                {
                                }
                            }
                        }
                    }
                    if (valmsg == "")
                    {
                        for (int d = 0; d < dt.Rows.Count; d++)
                        {
                            using (var transaction = db.Database.BeginTransaction())
                            {
                                try
                                {
                                    var clientprofiletype = db.usp_getcontacttypebyname().FirstOrDefault();
                                    FirstName = Convert.ToString(dt.Rows[d]["FirstName"]);
                                    var MiddleName = Convert.ToString(dt.Rows[d]["MiddleName"]);
                                    var LastName = Convert.ToString(dt.Rows[d]["LastName"]);
                                    email = Convert.ToString(dt.Rows[d]["Email"]);
                                    mobileno = Convert.ToString(dt.Rows[d]["MobileNo"]);
                                    var LandLineNo = Convert.ToString(dt.Rows[d]["LandLineNo"]);
                                    var Address = Convert.ToString(dt.Rows[d]["Address"]);
                                    //save in contact table
                                    string ids = "";
                                    ObjectParameter IDParameter1;
                                    IDParameter1 = new ObjectParameter("id", ids);
                                    var rs1 = db.Usp_SaveContactsData(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString(), FirstName, MiddleName, LastName.ToString(), null, Guid.Empty.ToString(), mobileno, email, null, Address, null, null, null, null, null, null, Guid.Empty.ToString(), clientprofiletype.ToString(), null, null, IDParameter1, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, 0, null, null);
                                    ids = Convert.ToString(IDParameter1.Value);
                                    string id = "";
                                    ObjectParameter IDParameter2;
                                    IDParameter2 = new ObjectParameter("id", id);
                                    var rs2 = db.Usp_SaveFirmUserData(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString(), "Client", false, false, false, null, null, 3, "deshboard", email, IDParameter2, Guid.Empty.ToString());
                                    id = Convert.ToString(IDParameter2.Value);
                                    var fullname = FirstName + " " + MiddleName + " " + LastName;
                                    //insert in regusers
                                    var rs3 = db.Usp_SaveRegUserClientData(LoggedInUser.FirmId.ToString(), LoggedInUser.FirmId.ToString(), id, fullname, mobileno, Address, null, null, null, "3", LandLineNo, Guid.Empty.ToString(), null, ids, FirstName, MiddleName, LastName, null, 0);
                                    // upload documents
                                    transaction.Commit();
                                }
                                catch (Exception e)
                                {
                                    transaction.Rollback();
                                }
                            }
                        }
                        result = "Record imported successfully, please check Contact Details.";
                        db.saveuseractivity(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString(), LoggedInUser.UserId.ToString(), 1, DateTime.Now.ToString(), "ImportContact", Guid.Empty.ToString(), null, null, DateTime.Now.ToString());
                        return Json(result, JsonRequestBehavior.AllowGet);
                    }
                }
                return Json(result, JsonRequestBehavior.AllowGet);
            }
            catch (Exception ex)
            {
                db1.usp_AddAudit(Convert.ToInt32(EventType.Contact), Convert.ToInt32(Severity.High), Convert.ToInt32(REQUEST_TYPE.API), Convert.ToString(EventType.Contact), Convert.ToString(Severity.High), Convert.ToString(REQUEST_TYPE.API), null, "Message=" + ex.Message + "@Inner Exception=" + ex.InnerException + "@Stack Trace=" + ex.StackTrace, myIP(), GetMacAddress().ToString(), 1, "");
                return Json(ex.Message + "Invalid File Format !", JsonRequestBehavior.AllowGet);
            }
        }
