        /// <summary>
        /// Export issue report in excel
        /// </summary>
        [AuthLog(Roles = "Firm,User")]
        public void ExportoExcelIssueReport()
        {
            try
            {
                var db = new LawPracticeEntities();
                var firmid = LoggedInUser.FirmId.ToString();
                var userid = LoggedInUser.UserId.ToString();
                int pagenum = Convert.ToInt32(QueryAES.UrlDecode(Request.QueryString["pagenum"]));
                int pagesize = Convert.ToInt32(QueryAES.UrlDecode(Request.QueryString["pagesize"]));
                var cnamefilter = QueryAES.UrlDecode(Request.QueryString["cnamefilter"]);
                var fromfilter = QueryAES.UrlDecode(Request.QueryString["fromfilter"]);
                var tofilter = QueryAES.UrlDecode(Request.QueryString["tofilter"]);
                var filterinvoietype = QueryAES.UrlDecode(Request.QueryString["filterinvoietype"]);
                var FilterInvoiceStatus = QueryAES.UrlDecode(Request.QueryString["FilterInvoiceStatus"]);
                //add for matterfield
                var materfilter = QueryAES.UrlDecode(Request.QueryString["matterid"]).ToString();
                if (cnamefilter == "null" || cnamefilter == null || cnamefilter == "undefined")
                { cnamefilter = ""; }
                var amountfilter = QueryAES.UrlDecode(Request.QueryString["amountfilter"]);
                var filter = QueryAES.UrlDecode(Request.QueryString["searchflag"]);
                if (amountfilter == "null" || amountfilter == null || amountfilter == "undefined")
                { amountfilter = ""; }
                if (fromfilter == "" || fromfilter == "null" || fromfilter == null || fromfilter == "undefined")
                { fromfilter = Convert.ToDateTime("1900-01-01").ToString("dd MMM yyyy"); }
                if (tofilter == "" || tofilter == "null" || tofilter == null || tofilter == "undefined")
                { tofilter = DateTime.Now.ToString("dd MMM yyyy"); }
                if (filter == "null" || filter == null || filter == "undefined")
                { filter = ""; }
                int pageid = 0;
                var pagelist = db.usp_GetRightsPageDatabyPagelink(Convert.ToString("caselist")).FirstOrDefault();
                if (pagelist != null)
                {
                    pageid = Convert.ToInt32(pagelist.ParentPage);
                }
                string exlfilename = "IssueReport_" + DateTime.Now;
                List<usp_InvoiceReport_Result> list = new List<usp_InvoiceReport_Result>();
                list = db.usp_InvoiceReport(firmid.ToString(), userid.ToString(), Convert.ToInt32(LoggedInUser.RoleId),
                    cnamefilter, fromfilter, tofilter, amountfilter, pagenum, pagesize, materfilter, filterinvoietype, FilterInvoiceStatus).ToList();
                StringBuilder sb = new StringBuilder();
                var trialList = (from ob in list
                                 select new
                                 {
                                     InvoiceNumber = ob.InvoiceNo,
                                     ClientName = ob.ClientName,
                                     InvoiceDate = String.Format("{0:dd MMM yyyy}", ob.invdate),
                                     Amount = ob.TotAmt,
                                     DueAmount = (Convert.ToDouble(ob.TotAmt) - Convert.ToDouble(ob.PaidAmt)).ToString(),
                                     CreatedBy = ob.CreatedBy,
                                     Date = String.Format("{0:dd MMM yyyy}", ob.Inovicedate),
                                     InvoiceType = ob.Invoicetype,
                                     InvoiceStatus = ob.InvoiceStatus,
                                     PaymentReceived = ob.PaidAmt
                                 }).ToList();
                var gv = new GridView();
                gv.DataSource = trialList;
                gv.DataBind();
                gv.HeaderStyle.BackColor = Color.Gray;
                gv.HeaderStyle.ForeColor = Color.White;
                Response.ClearContent();
                Response.Buffer = true;
                Response.AddHeader("content-disposition", "attachment; filename=" + exlfilename + ".xls");
                Response.ContentType = "application/ms-excel";
                Response.Charset = "";
                StringWriter objStringWriter = new StringWriter();
                HtmlTextWriter objHtmlTextWriter = new HtmlTextWriter(objStringWriter);
                gv.RenderControl(objHtmlTextWriter);
                Response.Output.Write(objStringWriter.ToString());
                Response.Flush();
                Response.End();
            }
            catch (Exception ex)
            {
                Response.Redirect("/home/Error");
            }
        }
