                var branch = QueryAES.UrlDecode(Request.QueryString["branch"]);
                var department = QueryAES.UrlDecode(Request.QueryString["department"]);
                var status = QueryAES.UrlDecode(Request.QueryString["status"]);
                var datefrom = QueryAES.UrlDecode(Request.QueryString["datefrom"]);
                var dateto = QueryAES.UrlDecode(Request.QueryString["dateto"]);
                if (search == "null" || search == null || search == "undefined")
                { search = ""; }
                if (usertype == "null" || usertype == null || usertype == "undefined")
                { usertype = ""; }
                if (designation == "null" || designation == null || designation == "undefined")
                { designation = ""; }
                if (branch == "null" || branch == null || branch == "undefined")
                { branch = ""; }
                if (department == "null" || department == null || department == "undefined")
                { department = ""; }
                if (status == "null" || status == null || status == "undefined")
                { status = ""; }
                if (datefrom == "" || datefrom == "null" || datefrom == null || datefrom == "undefined")
                { datefrom = "01-01-1900"; }
                if (dateto == "" || dateto == "null" || dateto == null || dateto == "undefined")
                { dateto = DateTime.Now.ToString(); }
                LawPracticeEntities db = new LawPracticeEntities();
                List<usp_GetUserReports_Result> list = new List<usp_GetUserReports_Result>();
                int pageid = 0;
                var pagelist = db.usp_GetRightsPageDatabyPagelink(Convert.ToString("userlist")).FirstOrDefault();
                if (pagelist != null)
                {
                    pageid = Convert.ToInt32(pagelist.ParentPage);
                }
                list = db.usp_GetUserReports(Guid.Parse(firmid), userid, pagenum, pagesize, 0, search, pageid, usertype, designation, branch,
                    department, status, datefrom, dateto).ToList();
                var trialList = (from ob in list
                                 select new
                                 {
                                     SlNo = ob.rownum,
                                     UserName = String.IsNullOrEmpty(ob.cfname) ? ob.cfname : ob.cfname,
                                     LoginUserName = ob.Username,
                                     Email = ob.cemail,
                                     Mobile = String.IsNullOrEmpty(ob.cmobile) ? ob.cmobile : ob.cmobile,
                                     Address = String.IsNullOrEmpty(ob.caddress) ? ob.caddress : ob.caddress,
                                     State = ob.cstate,
                                     City = ob.ccity,
                                     Country = ob.country,
                                     LandLine = String.IsNullOrEmpty(ob.clandline) ? ob.clandline : ob.clandline,
                                     Date = String.Format("{0:dd MMM yyyy}", ob.date_time) + " " + String.Format("{0:HH:mm:ss}", ob.date_time),
                                     OtherDetails = ob.OtherDetails,
                                     CreatedBy = String.IsNullOrEmpty(ob.CreatedBy) ? ob.CreatedBy : ob.CreatedBy,
                                     Designation = String.IsNullOrEmpty(ob.Designation) ? ob.Designation : ob.Designation,
                                     Department = String.IsNullOrEmpty(ob.Department) ? ob.Department : ob.Department,
                                     Qualification = ob.Qualification,
                                     PQE = ob.PQE,
                                     FirmExperience = ob.FirmExperience,
                                     AreaOfExpertise = ob.AreaOfExpertise,
                                     Status = ob.IsActive == true ? "Enabled" : "Disabled",
                                     BarNo = ob.BARNo,
                                     Branch = ob.Branch,
                                     UserType = ob.IsPartner == 1 ? "Partner" : "User",
                                     ReportingManager = ob.ReportManagerName,
                                     ParentPartner = ob.PartnerName,
                                     Ratehour = ob.HRate,
                                     EmployeeCode = ob.EmployeeCode,
                                     Extension = ob.Extention
                                 }).ToList();
                var gv = new GridView();
                gv.DataSource = trialList;
                gv.DataBind();
                gv.HeaderStyle.BackColor = Color.Gray;
                gv.HeaderStyle.ForeColor = Color.White;
                Response.ClearContent();
                Response.Buffer = true;
                Response.AddHeader("content-disposition", "attachment; filename=" + exlfilename + ".xls");
                Response.ContentType = "application/ms-excel";
                Response.Charset = "";
                StringWriter objStringWriter = new StringWriter();
                HtmlTextWriter objHtmlTextWriter = new HtmlTextWriter(objStringWriter);
                gv.RenderControl(objHtmlTextWriter);
                Response.Output.Write(objStringWriter.ToString());
                Response.Flush();
                Response.End();
                string notification = "You have Exported Excel of User List";
                db.usp_AddActivity(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString(), notification, "Export User Excel", null, null);
            }
            catch (Exception ex)
            {
                Response.Redirect("/home/Error");
            }
        }
