        /// <summary>
        /// Convert doc to pdf
        /// </summary>
        /// <returns></returns>
        [AuthLog(Roles = "Firm,User")]
        public ActionResult PdfDocConverter()
        {
            ViewBag.filesize = ConfigurationManager.AppSettings["filesize"];
            return View();
        }
        /// <summary>
        /// Process doc to pdf convertor
        /// </summary>
        /// <returns></returns>
        [AuthLog(Roles = "Firm,User")]
        public string ProcessPdfDocConverter()
        {
            try
            {
                var filepath = "";
                var fullfilename = "";
                var fileName = "";
                var fileext = "";
                var contentntype = "";
                var converter = QueryAES.UrlDecode(Request.Form["convertertype"]);
                string backfolder1 = Server.MapPath("~/azuredirin/" + LoggedInUser.FirmId.ToString() + "/" + LoggedInUser.UserId.ToString());
                string backfolder2 = Server.MapPath("~/azuredirout/" + LoggedInUser.FirmId.ToString() + "/" + LoggedInUser.UserId.ToString());
                if (!Directory.Exists(backfolder1))
                {
                    Directory.CreateDirectory(backfolder1);
                }
                if (!Directory.Exists(backfolder2))
                {
                    Directory.CreateDirectory(backfolder2);
                }
                var httpRequest = HttpContext.Request;
                for (int i = 0; i < httpRequest.Files.Count; i++)
                {
                    var postedFile = httpRequest.Files[i];
                    fullfilename = postedFile.FileName;
                    fileName = Path.GetFileNameWithoutExtension(postedFile.FileName);
                    fileext = Path.GetExtension(postedFile.FileName);
                    var filePath = backfolder1 + "\\" + Path.GetFileName(postedFile.FileName); //HttpContext.Current.Server.MapPath(+ postedFile.FileName); postedFile.SaveAs(filePath);
                    var fileextchk = Path.GetExtension(postedFile.FileName);
                    var is_valid = SaveCommonModulesDocument.chkValidExtension(fileextchk);
                    postedFile.SaveAs(filePath);
                }
                if (converter == "WTOPDF")
                {
                }
                else if (converter == "PDFTOW")
                {
                    contentntype = "application/ms-word";
                    string strFileName = fullfilename;
                    string FromLocation = backfolder1 + "\\" + strFileName;
                    byte[] docx = Freeware.Pdf2Docx.Convert(new FileStream(FromLocation, FileMode.Open, FileAccess.Read));
                    System.IO.File.WriteAllBytes(backfolder2 + "\\" + fileName + ".docx", docx);
                    filepath = backfolder2 + "\\" + fileName + ".docx";
                }
                else
                {
                }
                System.IO.FileInfo fileInfo = new System.IO.FileInfo(filepath);
                var dfilename = fileInfo.Name;
                return "/azuredirout/" + LoggedInUser.FirmId.ToString() + "/" + LoggedInUser.UserId.ToString() + "/" + fileInfo.Name;
            }
            catch (Exception ex)
            {
                LogService(ex.Message + "@" + ex.InnerException + "@" + ex.StackTrace);
                return "";
            }
        }
        /// <summary>
        /// Export matter custom field in excel
        /// </summary>
        [AuthLog(Roles = "Firm,User")]
        public void ExportoExcelCustomFieldMatter()
        {
            try
            {
                var vdate = QueryAES.UrlDecode(Request.QueryString["vdate"]);
                var type = QueryAES.UrlDecode(Request.QueryString["type"]);
                var exportcolumn = QueryAES.UrlDecode(Request.QueryString["exportcolumn"]);
                string exlfilename = "CustomFieldMatter_" + DateTime.Now;
                var db = new LawPracticeEntities();
                var GetCustomFieldHeaderList = db.usp_GetCustomFieldColumnHistory(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString(), type, vdate).ToList();
                if (LoggedInUser.RoleId == 1)
                {
                    List<usp_GetCustomFieldDataHistory_Result> trialList_1 = new List<usp_GetCustomFieldDataHistory_Result>();
                    trialList_1 = db.usp_GetCustomFieldDataHistory(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString(), type, vdate, 1, int.MaxValue).ToList();
                    StringBuilder sb = new StringBuilder();
                    var trialList = (from ob in trialList_1
                                     select new
                                     {
                                         MatterName = ob.MatterName,
                                         col1 = ob.col1,
                                         col2 = ob.col2,
                                         col3 = ob.col3,
                                         col4 = ob.col4,
                                         col5 = ob.col5,
                                         col6 = ob.col6,
                                         col7 = ob.col7,
                                         col8 = ob.col8,
                                         col9 = ob.col9,
                                         col10 = ob.col10,
                                         col11 = ob.col11,
                                         col12 = ob.col12,
                                         col13 = ob.col13,
                                         col14 = ob.col14,
                                         col15 = ob.col15,
                                     }).ToList();
                    var gv = new GridView();
                    gv.DataSource = trialList;
                    gv.DataBind();
                    var chkcvaues = exportcolumn;
                    string[] nums = chkcvaues.Split(',');
                    try
                    {
                        //start change header text
                        int CFieldsstartinxdex = 1;
                        foreach (var data in GetCustomFieldHeaderList)
                        {
                            gv.HeaderRow.Cells[CFieldsstartinxdex].Text = data.column_name;
                            CFieldsstartinxdex = CFieldsstartinxdex + 1;
                        }
                        //end change header text
                    }
                    catch (Exception ex)
                    {
                    }
                    for (int j = 0; j < gv.HeaderRow.Cells.Count; j++)
                    {
                        gv.HeaderRow.Cells[j].Visible = false;
                        foreach (GridViewRow itemrow in gv.Rows)
