        /// <summary>
        /// Export Work Transfer in excel
        /// </summary>
        [AuthLog(Roles = "Firm,User")]
        public void ExportoExcelWorkTransfer()
        {
            try
            {
                string exlfilename = "WorkTransferReport_" + DateTime.Now;
                var firmid = LoggedInUser.FirmId.ToString();
                var userid = LoggedInUser.UserId.ToString();
                int pagenum = Convert.ToInt32(QueryAES.UrlDecode(Request.QueryString["pagenum"]));
                int pagesize = Convert.ToInt32(QueryAES.UrlDecode(Request.QueryString["pagesize"]));
                var fromuser = QueryAES.UrlDecode(Request.QueryString["fromuser"]);
                var touser = QueryAES.UrlDecode(Request.QueryString["touser"]);
                var casename = QueryAES.UrlDecode(Request.QueryString["casename"]);
                LawPracticeEntities db = new LawPracticeEntities();
                List<usp_SwitchWorkUserMapList_Result> list = new List<usp_SwitchWorkUserMapList_Result>();
                list = db.usp_SwitchWorkUserMapList(firmid, userid, 1, int.MaxValue, fromuser, touser, casename).ToList();
                var trialList = (from ob in list
                                 select new
                                 {
                                     SlNo = ob.rownum,
                                     FromUserName = String.IsNullOrEmpty(ob.FromUserName) ? ob.FromUserName : ob.FromUserName,
                                     ToUserName = String.IsNullOrEmpty(ob.ToUserName) ? ob.ToUserName : ob.ToUserName,
                                     MatterName = String.IsNullOrEmpty(ob.MatterName) ? ob.MatterName : ob.MatterName,
                                     Createdby = String.IsNullOrEmpty(ob.Createdby) ? ob.Createdby : ob.Createdby,
                                     TransferDate = String.Format("{0:dd MMM yyyy}", Convert.ToDateTime(ob.CreateDate))
                                 }).ToList();
                var gv = new GridView();
                gv.DataSource = trialList;
                gv.DataBind();
                gv.HeaderStyle.BackColor = Color.Gray;
                gv.HeaderStyle.ForeColor = Color.White;
                Response.ClearContent();
                Response.Buffer = true;
                Response.AddHeader("content-disposition", "attachment; filename=" + exlfilename + ".xls");
                Response.ContentType = "application/ms-excel";
                Response.Charset = "";
                StringWriter objStringWriter = new StringWriter();
                HtmlTextWriter objHtmlTextWriter = new HtmlTextWriter(objStringWriter);
                gv.RenderControl(objHtmlTextWriter);
                Response.Output.Write(objStringWriter.ToString());
                Response.Flush();
                Response.End();
                string notification = "You have Exported Excel of WorkTransfer List";
                db.usp_AddActivity(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString(), notification, "Export WorkTransfer Excel", null, null);
            }
            catch (Exception ex)
            {
                Response.Redirect("/home/Error");
            }
        }
