        /// <summary>
        /// Get Notice pack details
        /// </summary>
        /// <returns></returns>
        [AuthLog(Roles = "Firm,User,Client")]
        public ActionResult IsNoticePack()
        {
            dynamic rasult = "";
            try
            {
                var firmpackmodulelist = db.Usp_CheckNoticePackByFirmId(LoggedInUser.FirmId.ToString()).ToList();
                if (firmpackmodulelist.Count > 0)
                {
                    var Islitigationpack = firmpackmodulelist
                    .Where(x => x.FullModulename == "Matter Management" || x.FullModulename == "Dashboard Fixed")
                    .Select(x => x.FullModulename).ToList();
                    //For Individual IPR Login
                    var IsIPR1 = firmpackmodulelist
                    .Where(x => x.FullModulename == "IPR Management")
                    .Select(x => x.FullModulename).ToList();
                    if (Islitigationpack.Count > 0)
                    {
                        rasult = "All";
                    }
                    else
                    {
                        if (IsIPR1.Count > 0)
                        {
                            rasult = "IPR";
                        }
                        else
                        {
                            rasult = "MkLitigation";
                        }
                    }
                    //rasult = "All";
                }
                else
                {
                    rasult = "Notice";
                }
            }
            catch (Exception) { }
            return Json(rasult);
        }
        /// <summary>
        /// Replace string special character
        /// </summary>
        /// <param name="input"></param>
        /// <returns></returns>
        public string ReplaceString(string input)
        {
            string result = "";
            if (input != null)
            {
                input = Regex.Replace(input, "(=|\\*|\\/|\\+|\\-|\\@)", "");
                result = input;
            }
            return input;
        }
