        /// <summary>
        /// Remove special character and HTML tag from text
        /// </summary>
        /// <param name="textDetail"></param>
        /// <returns></returns>
        public string removeSpecialCharacter(string textDetail)
        {
            string noHTML = "";
            if (!string.IsNullOrEmpty(textDetail))
            {
                noHTML = Regex.Replace(textDetail, @"<pre>", "").Trim();
                noHTML = Regex.Replace(noHTML, @"<\/pre>", "");
                noHTML = Regex.Replace(noHTML, @"<br>", "");
                noHTML = Regex.Replace(noHTML, @"<font size=1>", "");
                noHTML = Regex.Replace(noHTML, @"</font>", "");
                noHTML = Regex.Replace(noHTML, @"<br />", "");
                noHTML = Regex.Replace(noHTML, @"\r\n?|\n", "");

            }
            return noHTML;
        }
        public static DateTime ParseDateString(string dateString)
        {
            dateString = dateString.Trim();
            string[] dateFormats = {
            "dd-MM-yyyy", "yyyy-MM-dd", "d MMMM yyyy", "dd-MMM-yyyy", "MMM dd yyyy"
        };

            foreach (string format in dateFormats)
            {
                if (DateTime.TryParseExact(dateString, format, CultureInfo.InvariantCulture, DateTimeStyles.None, out DateTime parsedDate))
                {
                    return parsedDate;
                }
            }

            return DateTime.MinValue; // Indicate that parsing failed
        }
        [AuthLog(Roles = "Firm,User")]
        [HttpPost]
        public JsonResult BindIPRRenewalData()
        {
            var PageNum = 1;
            var PageSize = 10;
            var firmid = LoggedInUser.FirmId.ToString();
            var userid = LoggedInUser.UserId.ToString();
            List<GetRenewalCalenderDataModel> lstRenewal = new List<GetRenewalCalenderDataModel>();
            var list = db.usp_GetRenewalTradeForCalender(userid, firmid, PageNum, PageSize).ToList();
            int renewalCount = 0;
            foreach (var result in list)
            {
                lstRenewal.Add(new GetRenewalCalenderDataModel
                {
                    AppNo = result.vApplNo,
                    Trademark = result.vWordMark,
                    Proprietor = result.vProprietor,
                    AppDate = result.dApplDate,//Convert.ToDateTime(result.dApplDate).ToString("MM/dd/yyyy"),
                    RenewalCount = result.TotalRecord,
                    RowId = Convert.ToInt32(result.RowId),
                    RenewalDate = result.RenewalDate,
                    Datetype = "Renewal"
                });
            }

            var hearingResult = DataAccessIPRADO.Usp_GetApplicationHearingDate(firmid, userid);
            for (int i = 0; i < hearingResult.Rows.Count; i++)
            {
                GetRenewalCalenderDataModel model = new GetRenewalCalenderDataModel();
                model.AppNo = hearingResult.Rows[i]["vApplNo"].ToString();
                model.Trademark = hearingResult.Rows[i]["vWordMark"].ToString();
                model.Proprietor = hearingResult.Rows[i]["vProprietor"].ToString();
                model.AppDate = hearingResult.Rows[i]["dApplDate"].ToString();
                model.RenewalCount = Convert.ToInt32(hearingResult.Rows[i]["TotalRecord"].ToString());
                model.RowId = Convert.ToInt32(hearingResult.Rows[i]["RowId"].ToString());
                model.RenewalDate = Convert.ToDateTime(hearingResult.Rows[i]["HearingDate"]).ToString("MM/dd/yyyy");
                model.Datetype = "Hearing";
                lstRenewal.Add(model);
            }

