            PageSize = Convert.ToInt32(HttpContext.Request.Form["pagesize"]);
            var cDate = HttpContext.Request.Form["getDataByDate"];

            List<GetRenewalCalenderDataModel> lstRenewal = new List<GetRenewalCalenderDataModel>();
            var list = db.usp_GetRenewalTradeForCalenderPopup(userid, firmid, PageNum, PageSize, cDate).ToList();
