                    RenewalDate = result.RenewalDate,
                    vClass = result.vClass
                });
            }
            ServicePointManager.SecurityProtocol = SecurityProtocolType.Tls12;
            return Json(lstRenewal.Distinct().ToList(), JsonRequestBehavior.AllowGet);
        }
