                    fromdate = "",
                    todate = "",
                    istype = "1",
                    Taggedname = "",
                    bench = "",
                    caseno = "",
                    advocatename = "",
                    flagManualdtrange = "0",
                    casename = MatterName,
                    courtdistrict = "",
                    diaryno = "",
                    cnrno = "",
                    caseyear = "",
                    assigneduserid = "",
                    applicant = "",
                    respondent = ""
                };
                addfClient.Encoding = System.Text.Encoding.UTF8;
                addfClient.Headers.Add(HttpRequestHeader.ContentType, "application/json");
                string builders = JsonConvert.SerializeObject(rawfile);
                ServicePointManager.SecurityProtocol = SecurityProtocolType.Tls12;
                string resid = addfClient.UploadString(new Uri(apiUrl + "/API/Search/MyCasesV1"), "POST", builders);
                var param = apiUrl + "CWController=>MyCasesV1=>/API/Search/MyCasesV1" + "@" + builders;
                db1.usp_AddAudit(Convert.ToInt32(EventType.Case), Convert.ToInt32(Severity.High), Convert.ToInt32(REQUEST_TYPE.API), Convert.ToString(EventType.Case), Convert.ToString(Severity.High), Convert.ToString(REQUEST_TYPE.API), Guid.Parse(Session["sessionuserid"].ToString()), param, AuditData.myIP(), AuditData.GetMacAddress().ToString(), 0, "");
                dynamic jObject = JObject.Parse(resid);
                dynamic data1 = jObject["data"];
                dt.Columns.Add("TotalRecord");
                dt.Columns.Add("sno");
                dt.Columns.Add("mname");
                dt.Columns.Add("Id");
                dt.Columns.Add("UserCaseId");
                dt.Columns.Add("CourtName");
                dt.Columns.Add("OtherCourtName");
                dt.Columns.Add("mtrno");
                if (data1 != null)
                {
                    for (int i = 0; i < data1.Count; i++)
                    {

                        dynamic data = JObject.Parse(resid);
                        int tempusercaseid = Convert.ToInt32(data.data[i]["UserCaseId"]);
                        var matterIDCase = db.Usp_MattersDetilsForCW(LoggedInUser.FirmId.ToString(), UserID, tempusercaseid.ToString()).FirstOrDefault();

                        DataRow dtrow = dt.NewRow();
                        dtrow["TotalRecord"] = Convert.ToString(data.data[i]["TotalRecord"]);
                        dtrow["sno"] = Convert.ToString(data.data[i]["RowId"]);
                        dtrow["mname"] = Convert.ToString(data.data[i]["Case Name"]);
                        dtrow["Id"] = Convert.ToString(matterIDCase == null ? "" : matterIDCase.Id.ToString());
                        if (!string.IsNullOrEmpty(Convert.ToString(data.data[i]["UserCaseId"])))
                            dtrow["UserCaseId"] = Convert.ToBase64String(QueryAES.EncryptAes(Convert.ToString(data.data[i]["UserCaseId"])));
                        else
                            dtrow["UserCaseId"] = "";
                        dtrow["CourtName"] = Convert.ToString((data.data[i]["CourtType"] == "1" ? "Supreme Court" : data.data[i]["CourtType"] == "2" ? "High Court" : data.data[i]["CourtType"] == "3" ? "District Court" : data.data[i]["CourtType"] == "4" ? "Tribunals" : data.data[i]["CourtType"] == "5" ? "Add a Court" : data.data[i]["CourtType"]));
                        dtrow["OtherCourtName"] = Convert.ToString(data.data[i]["CourtName"]);
                        dtrow["mtrno"] = Convert.ToString(data.data[i]["Case/Diary"]);
                        dt.Rows.Add(dtrow);
                    }
                }
            }
            else
            {
                dt = DataAccessADO.usp_GetMatterByFirmAndUserID(LoggedInUser.FirmId, Guid.Parse(UserID), MatterName, CourtType, Convert.ToInt16(PageSize), Convert.ToInt16(PageNo), CourtTypeName);
                if (dt.Rows.Count > 0)
                {
                    foreach (DataRow row in dt.Rows)
                    {
                        if (!string.IsNullOrEmpty(Convert.ToString(row["UserCaseId"])))
                            row["UserCaseId"] = Convert.ToBase64String(QueryAES.EncryptAes(Convert.ToString(row["UserCaseId"])));
                        else
                            row["UserCaseId"] = "";
                    }
                }
            }
            var a = JsonConvert.SerializeObject(dt);
            return a;
        }

