        [AuthLog(Roles = "Firm,User,Client")]
        public ActionResult ViewSebiFileById()
        {
            try
            {
                var fileName = Request.Form["fileName"];

                if (string.IsNullOrEmpty(fileName))
                {
                    return new HttpStatusCodeResult(HttpStatusCode.BadRequest, "File name is missing.");
                }
                var filePath = Server.MapPath("~/SebiHtmlFile/" + fileName);
                if (!System.IO.File.Exists(filePath))
                {
                    return new HttpStatusCodeResult(HttpStatusCode.NotFound, "File not found.");
                }
                var fileContents = System.IO.File.ReadAllText(filePath);
                return Content(fileContents, "text/html");
            }
            catch (Exception ex)
            {
                return new HttpStatusCodeResult(HttpStatusCode.InternalServerError, "An error occurred while processing your request.");
            }
        }
        [AuthLog(Roles = "Firm")]
        public void ExportoSebiJudgeMentPdf()
        {
            try
            {
                var fileName = Request.Form["filename"];
                var filePath = Server.MapPath("~/SebiHtmlFile/" + fileName);
                var fileContents = System.IO.File.ReadAllText(filePath);
                var htmlToPdf = new NReco.PdfGenerator.HtmlToPdfConverter
                {
                    Orientation = NReco.PdfGenerator.PageOrientation.Landscape,
                    Margins = new NReco.PdfGenerator.PageMargins { Bottom = 10, Left = 5, Right = 5, Top = 5 },
                    PageFooterHtml = "<div style='width:50%;float:left'><img style='padding:0 0 0 5px;' src='" + Server.MapPath("~\\Manupanel\\img\\powerby-logo.png") + "' width='140px' height='30px;'></img></div>" +
                                    "<div style='width:50%;float:left;padding:5px 0 0 0;'>  Page <span class='page'></span> of  <span class='topage'></span></div>"
                };

                var pdfBytes = htmlToPdf.GeneratePdf(fileContents);

                // Modify the filename to replace the extension with ".pdf"
                var newFileName = System.IO.Path.GetFileNameWithoutExtension(fileName) + ".pdf";
                Response.Clear();
                using (var ms = new System.IO.MemoryStream(pdfBytes))
                {
                    Response.ContentType = "application/pdf";
                    Response.AddHeader("content-disposition", "attachment;filename=" + newFileName);
                    Response.Buffer = true;
                    ms.WriteTo(Response.OutputStream);
                }
                Response.End();
            }
            catch (Exception ex)
            {
                Response.Redirect("/home/Error");
            }
        }
