        /// <summary>
        /// Export new cases in pdf For Sebi
        /// </summary>
        [AuthLog(Roles = "Firm,User")]
        public void ExportoPDFSebiNewCases()
        {
            try
            {
                var esearchdata = QueryAES.UrlDecode(Request.Form["esearchdata"]);
                var ecasefilterdate = QueryAES.UrlDecode(Request.Form["ecasefilterdate"]);
                var ecasefilterclient = QueryAES.UrlDecode(Request.Form["ecasefilterclient"]);
                var createdby = QueryAES.UrlDecode(Request.Form["createdby"]);
                var esearchdatanotes = QueryAES.UrlDecode(Request.Form["esearchdatanotes"]);
                var ecasefiltercourtname = QueryAES.UrlDecode(Request.QueryString["ecasefiltercourtname"]);
                try
                {
                    ecasefilterclient = ecasefilterclient.Replace(" ", "+");
                    ecasefilterclient = QueryAES.DecryptAes(QueryAES.FromBase64StringWithReplace(ecasefilterclient));
                }
                catch
                {

                }

                var ecasefiltercourt = QueryAES.UrlDecode(Request.Form["ecasefiltercourt"]);
                var ecasefilterstatus = QueryAES.UrlDecode(Request.Form["ecasefilterstatus"]);
                var searchuser = QueryAES.UrlDecode(Request.Form["eusers"]);
                if (searchuser == "undefined")
                {
                    searchuser = "";
                }
                var ecasefiltercompanyname = QueryAES.UrlDecode(Request.Form["ecasefiltercompanyname"]);
