            var hearingResult = DataAccessIPRADO.Usp_GetTrademarkHearingDetail(firmid, userid, PageNum, PageSize, cDate);
            int renewalCount = 0;
            //foreach (var result in list)
            //{
            //    lstRenewal.Add(new GetRenewalCalenderDataModel
            //    {
            //        AppNo = result.vApplNo,
            //        Trademark = result.vWordMark,
            //        Proprietor = result.vProprietor,
            //        AppDate = result.dApplDate,//Convert.ToDateTime(result.dApplDate).ToString("MM/dd/yyyy"),
            //        RenewalCount = result.TotalRecord,
            //        RowId = Convert.ToInt32(result.RowId),
            //        RenewalDate = result.RenewalDate,
            //        vClass = result.vClass
            //    });
            //}
            for (int i = 0; i < hearingResult.Rows.Count; i++)
            {
                GetRenewalCalenderDataModel model = new GetRenewalCalenderDataModel();
                model.AppNo = hearingResult.Rows[i]["vApplNo"].ToString();
                model.Trademark = hearingResult.Rows[i]["vWordMark"].ToString();
                model.Proprietor = hearingResult.Rows[i]["vProprietor"].ToString();
                model.AppDate = hearingResult.Rows[i]["dApplDate"].ToString();
                model.RenewalCount = Convert.ToInt32(hearingResult.Rows[i]["TotalRecord"].ToString());
                model.RowId = Convert.ToInt32(hearingResult.Rows[i]["RowId"].ToString());
                model.vClass = hearingResult.Rows[i]["vClass"].ToString();
                //model.RenewalDate = Convert.ToDateTime(hearingResult.Rows[i]["HearingDate"]).ToShortDateString();
                model.Datetype = "Hearing";
                lstRenewal.Add(model);
            }
            ServicePointManager.SecurityProtocol = SecurityProtocolType.Tls12;
            return Json(lstRenewal.Distinct().ToList(), JsonRequestBehavior.AllowGet);
        }
