        /// <summary>
        /// Check Matter Rights
        /// </summary>
        /// <param name="action"></param>
        /// <returns></returns>
        public string checkmatterroles(string action = "")
        {
            var urlsegment = "";
            if (string.IsNullOrEmpty(action))
            {
                urlsegment = Request.Url.Segments[3];
                urlsegment = urlsegment.Replace("/", "");
            }
            else
            {
                urlsegment = action;
            }
            var db = new LawPracticeEntities();
            var foutput = true;
            var frmids = Session["sessionfirmid"].ToString();
            var usrids = Session["sessionuserid"].ToString();
            int rlid = Convert.ToInt32(Session["sessionroleid"].ToString());
            var finalresult = "";
            int pageid = 0;
            var sflag = true;
            if (LoggedInUser.RoleId == 2)
            {
                var pagelist = db.usp_GetRightsPageDatabyPagelink(Convert.ToString(urlsegment)).ToList();
                if (pagelist.Count > 0)
                {
                    foreach (var data in pagelist)
                    {
                        int pwrite = 0, pview = 0, pedit = 0, pdel = 0, pviewall = 0, peditall = 0;
                        pageid = Convert.ToInt32(data.ParentPage);
                        pwrite = Convert.ToInt32(data.Write);
                        pview = Convert.ToInt32(data.View);
                        pedit = Convert.ToInt32(data.Edit);
                        pdel = Convert.ToInt32(data.Delete);
                        pviewall = Convert.ToInt32(data.ViewAll);
                        peditall = Convert.ToInt32(data.EditAll);
                        // dynamic pageaccesslist;
                        DataTable pageaccesslist = new DataTable();
                        //if (urlsegment == "caselist" || urlsegment == "NewCaseDashboard" || urlsegment == "Casedetails" || urlsegment == "EditCase" || urlsegment == "CreateCase" || urlsegment == "StandardCaseList")
                        //{
                        //    pageaccesslist = DataAccessADO.GetUserCaseModuleRights(frmids, usrids, usrids, pageid);
                        //}
                        //else
                        //{
                        //    pageaccesslist = DataAccessADO.GetUserModuleRights(frmids, usrids, usrids, pageid);
                        //}
                        //var chckispartner = db.usp_CheckIsPartner(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString()).FirstOrDefault();
                        //if (chckispartner == 1)
                        //{
                        //    pageaccesslist = DataAccessADO.GetUserCaseModuleRights(frmids, usrids, usrids, pageid);
                        //}
                        //else
                        //{
                        //    pageaccesslist = DataAccessADO.GetUserModuleRights(frmids, usrids, usrids, pageid);
                        //}
                        pageaccesslist = DataAccessADO.GetUserCaseModuleRightsCustom(frmids, usrids, usrids, pageid);
                        int write = 0, view = 0, edit = 0, del = 0, viewall = 0, editall = 0, share = 0, enable = 0, export = 0, timespecialright = 0;
                        for (int i = 0; i < pageaccesslist.Rows.Count; i++)
                        {
                            write = Convert.ToInt32(pageaccesslist.Rows[i]["Write"]);
                            view = Convert.ToInt32(pageaccesslist.Rows[i]["View"]);
                            edit = Convert.ToInt32(pageaccesslist.Rows[i]["Edit"]);
                            del = Convert.ToInt32(pageaccesslist.Rows[i]["Delete"]);
                            viewall = Convert.ToInt32(pageaccesslist.Rows[i]["ViewAll"]);
                            editall = Convert.ToInt32(pageaccesslist.Rows[i]["EditAll"]);
                            export = Convert.ToInt32(pageaccesslist.Rows[i]["Export"]);

                            ViewBag.IsViewAll = viewall;
                            ViewBag.export = 0;

                            if (export > 0)
                            {
                                ViewBag.export = export;
                            }
                            if (viewall > 0 || editall > 0)
                            {
                                foutput = false;
                                ViewBag.IsDelete = del;
                                ViewBag.IsCreate = write;
                                ViewBag.IsEdit = edit;
                                if (write == 1)
                                {
                                    foutput = false;
                                }
                                if (pedit == 1)
                                {
                                    if (edit == 1 || editall == 1)
                                    {
                                        foutput = false;
                                    }
                                    else
                                    {
                                        foutput = true;
                                    }
                                }
                            }
                            else
                            {
                                // logic for write(create)
                                if (sflag == true)
                                {
                                    if (write > 0)
                                    {
                                        ViewBag.IsCreate = write;
                                        if (pwrite == write)
                                        {
                                            foutput = true;
                                            sflag = true;
                                        }
                                    }
                                    else
                                    {
                                        ViewBag.IsCreate = 0;
                                        foutput = true;
                                    }
                                }
                                //logic for edit(
                                if (sflag == true)
                                {
                                    if (edit > 0)
                                    {
                                        //if (pedit == edit)
                                        //{
                                        //    foutput = false;
                                        //    sflag = false;
                                        //    ViewBag.IsEdit = edit;
                                        //}
                                        ViewBag.IsEdit = edit;
                                    }
                                    else
                                    {
                                        foutput = true;
                                    }
                                }
                                //logic for delete
                                ViewBag.IsDelete = 0;
                                if (del > 0)
                                {
                                    ViewBag.IsDelete = 1;
                                }
                                else
                                {
                                    ViewBag.IsDeletes = 0;
                                }

                            }
                        }
                    }
                }
                finalresult = ViewBag.IsCreate + "," + ViewBag.IsEdit + "," + ViewBag.IsDelete + "," + ViewBag.export;
            }
            return finalresult.ToString();
        }
        /// <summary>
        /// validatepage
        /// </summary>
        /// <returns></returns>
        [AuthLog(Roles = "Firm,User")]
        public bool validatepage(string PageValue, string ActionName)
        {
            // IsCreate,IsEdit,IsDelete,export,share,enable,TimeEntrySpecial

            if (LoggedInUser.RoleId == 1)
            {
                return true; ;
            }
            else if (LoggedInUser.RoleId == 2)
            {
                var data = checkmatterroles(PageValue);
                var rights = data.Split(',');
                var IsCreate = rights[0];
                var IsEdit = rights[1];
                var IsDelete = rights[2];
                var export = rights[3];
                if ((ActionName == "CreateCase" && IsCreate == "1") ||
                    (ActionName == "EditCase" && IsEdit == "1") ||
                    (ActionName == "Delete" && IsDelete == "1") ||
                    (ActionName == "Export" && export == "1"))
                {
                    return true;
                }

                else
                {
                    return false;
                }
            }
            else
            {
                return false;
            }
        }
