        [AuthLog(Roles = "Firm,User")]
        public void ExportoExcelBOMCustomReport()
        {
            try
            {
                var db = new LawPracticeEntities();
                var firmid = LoggedInUser.FirmId.ToString();
                var userid = LoggedInUser.UserId.ToString();
                string AssignUserId = QueryAES.UrlDecode(Request.QueryString["AssignUserId"]);
                string SubCourtName = QueryAES.UrlDecode(Request.QueryString["SubCourtName"]);
                string zonenameexpo = QueryAES.UrlDecode(Request.QueryString["zonenameexpo"]);
                string CourtNameexp = QueryAES.UrlDecode(Request.QueryString["CourtNameexp"]);
                string Satatusexp = QueryAES.UrlDecode(Request.QueryString["Satatusexp"]);
                string nexthearingdatefrmexpo = QueryAES.UrlDecode(Request.QueryString["nexthearingdatefrmexpo"]);
                string nexthearingdateToexp = QueryAES.UrlDecode(Request.QueryString["nexthearingdateToexp"]);
                string pagenumber = QueryAES.UrlDecode(Request.QueryString["pagenum"]);
                string pagesize = QueryAES.UrlDecode(Request.QueryString["pagesize"]);
                string Againstpartyname = QueryAES.UrlDecode(Request.QueryString["Againstpartyname"]);
                string type = QueryAES.UrlDecode(Request.QueryString["type"]);
                if (string.IsNullOrEmpty(type))
                {
                    type = "0";
                }

                if (AssignUserId == "null" || AssignUserId == null || AssignUserId == "undefined")
                { AssignUserId = ""; }
                if (SubCourtName == "null" || SubCourtName == null || SubCourtName == "undefined")
                { SubCourtName = ""; }
                if (zonenameexpo == "null" || zonenameexpo == null || zonenameexpo == "undefined")
                { zonenameexpo = ""; }
                if (CourtNameexp == "null" || CourtNameexp == null || CourtNameexp == "undefined")
                { CourtNameexp = ""; }
                if (Satatusexp == "null" || Satatusexp == null || Satatusexp == "undefined")
                { Satatusexp = ""; }
                if (nexthearingdatefrmexpo == "null" || nexthearingdatefrmexpo == null || nexthearingdatefrmexpo == "undefined")
                { nexthearingdatefrmexpo = ""; }
                if (nexthearingdateToexp == "null" || nexthearingdateToexp == null || nexthearingdateToexp == "undefined")
                { nexthearingdateToexp = ""; }

                string exlfilename = "MatterReport_" + DateTime.Now;
                var trialList_1 = DataAccessADO.GeMatterNewGraphExport(LoggedInUser.FirmId.ToString(), LoggedInUser.UserId.ToString(), AssignUserId, zonenameexpo,
                    CourtNameexp, Satatusexp, null, nexthearingdatefrmexpo, nexthearingdateToexp, SubCourtName, Convert.ToInt32(pagenumber), Convert.ToInt32(pagesize), Againstpartyname, Convert.ToInt32(type));


                List<CustomMatterReport> lstModelPDF = new List<CustomMatterReport>();
                CustomMatterReport modelPDF = new CustomMatterReport();
                lstModelPDF = JsonConvert.DeserializeObject<List<CustomMatterReport>>(trialList_1);
                var trialList = (from data in lstModelPDF
                                 select new
                                 {
                                     MatterName = data.MatterName,
                                     Court = data.Court,
                                     CourtName = data.CourtName,
                                     PetitionerName = data.PetitionerName,
                                     RespondentName = data.RespondentName,
                                     CourtStatus = data.VStatus,
                                     Nexthearingdate = data.Nexthearingdate,
                                     CourtCaseNo = data.CaseNo,
                                     //OtherCourtName = data.OtherCourtName,
                                     CourtComplex = data.CourtComplex,
                                     CasenumberInternal = data.CasenumberInternal,
                                     ZoneName = data.ZoneName,
                                     MatterFilingDate = (data.dFilingDate == null || data.dFilingDate == "") ? "" : (Convert.ToDateTime(data.dFilingDate).Year == 1900 ? "" : Convert.ToDateTime(data.dFilingDate).ToString("dd/MM/yyyy"))
                                 }).ToList();
                var gv = new GridView();
                gv.DataSource = trialList;
                gv.DataBind();
                gv.HeaderStyle.BackColor = Color.Gray;
                gv.HeaderStyle.ForeColor = Color.White;
                Response.ClearContent();
                Response.Buffer = true;
                Response.AddHeader("content-disposition", "attachment; filename=" + exlfilename + ".xls");
                Response.ContentType = "application/ms-excel";
                Response.Charset = "";
                StringWriter objStringWriter = new StringWriter();
                HtmlTextWriter objHtmlTextWriter = new HtmlTextWriter(objStringWriter);
                gv.RenderControl(objHtmlTextWriter);
                Response.Output.Write(objStringWriter.ToString());
                Response.Flush();
                Response.End();
            }
            catch (Exception ex)
            {
                Response.Redirect("/home/Error");
            }
        }

