        //Function created to get the JobId for selected orders
        [AuthLog(Roles = "Firm,User")]
        [HttpPost]
        public string UploadOrderUrls()
        {
            string apiBaseUrlForAI = System.Configuration.ConfigurationManager.AppSettings["ApiBaseUrlForAI"];
            try
            {
                using (var reader = new StreamReader(Request.InputStream))
                {
                    var json = reader.ReadToEnd();
                    var jsonObj = JsonConvert.DeserializeObject<JObject>(json);
                    var urls = jsonObj["urls"]?.ToObject<string[]>();

                    if (urls == null || urls.Length == 0)
                    {
                        return JsonConvert.SerializeObject(new { error = "No URLs provided." });
                    }

                    var rawfile = new
                    {
                        urls = urls
                    };

                    string fullUrl = apiBaseUrlForAI?.TrimEnd('/') + "/upload-urls/";

                    if (!Uri.TryCreate(fullUrl, UriKind.Absolute, out Uri apiUri))
                    {
                        return JsonConvert.SerializeObject(new { error = "Invalid API base URL: " + fullUrl });
                    }

                    using (var addfClient = new WebClient())
                    {
                        addfClient.Headers.Add(HttpRequestHeader.ContentType, "application/json");
                        ServicePointManager.SecurityProtocol = SecurityProtocolType.Tls12;

                        string requestBody = JsonConvert.SerializeObject(rawfile);
                        string response = addfClient.UploadString(apiUri, "POST", requestBody);

                        return response;
                    }
                }
            }
            catch (Exception ex)
            {
                return JsonConvert.SerializeObject(new { error = ex.ToString() });
            }
        }

        //Function created to get the JobId for selected orders using file 
        [AuthLog(Roles = "Firm,User")]
        [HttpPost]
        public string UploadOrderFiles()
        {
            string apiBaseUrlForAI = ConfigurationManager.AppSettings["ApiBaseUrlForAI"];

            try
            {
                using (var reader = new StreamReader(Request.InputStream))
                {
                    var json = reader.ReadToEnd();
                    var jsonObj = JsonConvert.DeserializeObject<JObject>(json);
                    var urls = jsonObj["urls"]?.ToObject<string[]>();

                    if (urls == null || urls.Length == 0)
                    {
                        return JsonConvert.SerializeObject(new { error = "No URLs provided." });
                    }

                    var pdfFiles = new List<(byte[] bytes, string name)>();

                    var htmlToPdf = new NReco.PdfGenerator.HtmlToPdfConverter
                    {
                        Orientation = NReco.PdfGenerator.PageOrientation.Landscape
                    };

                    foreach (var url in urls)
                    {
                        if (url.EndsWith(".html", StringComparison.OrdinalIgnoreCase))
                        {
                            byte[] pdfBytes = htmlToPdf.GeneratePdfFromFile(url, null);

                            pdfFiles.Add((
                                pdfBytes,
                                Guid.NewGuid().ToString() + ".pdf"
                            ));
                        }
                    }

                    if (!pdfFiles.Any())
                    {
                        return JsonConvert.SerializeObject(new { error = "No HTML files to convert." });
                    }

                    string fullUrl = apiBaseUrlForAI.TrimEnd('/') + "/upload-files/";

                    using (var client = new HttpClient())
                    using (var form = new MultipartFormDataContent())
                    {
                        foreach (var pdf in pdfFiles)
                        {
                            var content = new ByteArrayContent(pdf.bytes);
                            content.Headers.ContentType =
                                System.Net.Http.Headers.MediaTypeHeaderValue.Parse("application/pdf");

                            form.Add(content, "files", pdf.name);
                        }

                        ServicePointManager.SecurityProtocol = SecurityProtocolType.Tls12;
                        var response = client.PostAsync(fullUrl, form).Result;

                        return response.Content.ReadAsStringAsync().Result;
                    }
                }
            }
            catch (Exception ex)
            {
                return JsonConvert.SerializeObject(new { error = ex.ToString() });
            }
        }

