        //Function created to get the JobId for selected orders using files 
        [AuthLog(Roles = "Firm,User")]
        [HttpPost]
        public string UploadOrderFilesChronology()
        {
            string ApiBaseUrlForAIChronology =
                ConfigurationManager.AppSettings["ApiBaseUrlForAIChronology"];

            try
            {
                using (var reader = new StreamReader(Request.InputStream))
                {
                    var json = reader.ReadToEnd();
                    var jsonObj = JsonConvert.DeserializeObject<JObject>(json);
                    var urls = jsonObj["urls"]?.ToObject<string[]>();

                    if (urls == null || urls.Length == 0)
                        return JsonConvert.SerializeObject(new { error = "No URLs provided." });
                    var htmlToPdf = new NReco.PdfGenerator.HtmlToPdfConverter
                    {
                        Orientation = NReco.PdfGenerator.PageOrientation.Landscape
                    };

                    using (var httpClient = new HttpClient())
                    using (var form = new MultipartFormDataContent())
                    {
                        foreach (var url in urls)
                        {
                            if (string.IsNullOrWhiteSpace(url))
                                continue;
                            if (url.EndsWith(".html", StringComparison.OrdinalIgnoreCase))
                            {
                                byte[] pdfBytes = htmlToPdf.GeneratePdfFromFile(url, null);

                                var pdfContent = new ByteArrayContent(pdfBytes);
                                pdfContent.Headers.ContentType =
                                    new System.Net.Http.Headers.MediaTypeHeaderValue("application/pdf");

                                string fileName = Guid.NewGuid().ToString() + ".pdf";
                                form.Add(pdfContent, "files", fileName);
                            }
                        }

                        if (!form.Any())
                            return JsonConvert.SerializeObject(new { error = "No HTML files to convert." });

                        string fullUrl = ApiBaseUrlForAIChronology.TrimEnd('/') + "/upload-files";

                        ServicePointManager.SecurityProtocol = SecurityProtocolType.Tls12;

                        var response = httpClient.PostAsync(fullUrl, form).Result;
                        var responseText = response.Content.ReadAsStringAsync().Result;

                        return responseText;
                    }
                }
            }
            catch (Exception ex)
            {
                return JsonConvert.SerializeObject(new { error = ex.ToString() });
            }
        }

