        //Function to save Manual Hearing Date in CWCaseDetails
        [AuthLog(Roles = "Firm,User,Client")]
        public JsonResult SaveManualNextHearingDateNew()
        {
            try
            {
                var db = new LawPracticeEntities();
                string result = "";

                var userCaseId = QueryAES.UrlDecode(Request.Form["userCaseId"]);
                var nhdate = QueryAES.UrlDecode(Request.Form["nhdate"]);

                try
                {
                    userCaseId = userCaseId.Replace(" ", "+");
                    userCaseId = QueryAES.DecryptAes(QueryAES.FromBase64StringWithReplace(userCaseId));
                }
                catch { }

                if (!DateTime.TryParse(nhdate, out DateTime manualDate))
                    return Json("Invalid date", JsonRequestBehavior.AllowGet);

                db.Database.ExecuteSqlCommand(
                    "EXEC usp_InsertManualNextHearingNew @UserCaseId, @ManualNextHearing",
                    new SqlParameter("@UserCaseId", userCaseId),
                    new SqlParameter("@ManualNextHearing", manualDate)
                );

                result = "Updated Successfully";
                return Json(result, JsonRequestBehavior.AllowGet);
            }
            catch (Exception ex)
            {
                return Json("Error: " + ex.Message, JsonRequestBehavior.AllowGet);
            }
        }

        //Function to convert to OCR
        [HttpPost]
        public async Task<ActionResult> ConvertToOCR()
        {
            string ocrApiUrl = ConfigurationManager.AppSettings["OCRUrl"] + "jobs";

            try
            {
                if (Request.Files.Count == 0)
                {
                    return Json(new { Status = false, Message = "No files uploaded" });
                }

                using (var client = new HttpClient() { Timeout = TimeSpan.FromMinutes(10) })
                using (var form = new MultipartFormDataContent())
                {
                    for (int i = 0; i < Request.Files.Count; i++)
                    {
                        var file = Request.Files[i];
                        var extension = Path.GetExtension(file.FileName)?.ToLower();
                        int pageCount = 1; // Default for non-PDF

                        if (extension == ".pdf")
                        {
                            try
                            {
                                using (var reader = new StreamReader(file.InputStream, Encoding.UTF8, true, 1024, leaveOpen: true))
                                {
                                    string content = reader.ReadToEnd();

                                    int count = Regex.Matches(content, @"/Type\s*/Page").Count;
                                    if (count > 0)
                                    {
                                        pageCount = count;
                                    }
                                }

                                file.InputStream.Position = 0;
                            }
                            catch
                            {
                                pageCount = 1;
                            }
                        }

                        var streamContent = new StreamContent(file.InputStream);
                        streamContent.Headers.ContentType = new MediaTypeHeaderValue(file.ContentType ?? "application/octet-stream");

                        // Add to form with the field name expected by OCR API
                        form.Add(streamContent, "files", file.FileName);
                    }

                    ServicePointManager.SecurityProtocol = SecurityProtocolType.Tls12;

                    var response = await client.PostAsync(ocrApiUrl, form);

                    if (!response.IsSuccessStatusCode)
                    {
                        var errorContent = await response.Content.ReadAsStringAsync();
                        return Json(new
                        {
                            Status = false,
                            Message = $"An error occurred while sending the request: {errorContent}"
                        });
                    }

                    var result = await response.Content.ReadAsStringAsync();
                    return Content(result, "application/json");
                }
            }
            catch (Exception ex)
            {
                return Json(new { Status = false, Message = ex.Message });
            }
        }


