                string firmId = LoggedInUser.FirmId.ToString();
                string userId = LoggedInUser.UserId.ToString();
                string jobId = input.jobId;
                string files = input.fileNames;
                var ocrResults = ((IEnumerable<dynamic>)input.ocrResults).ToList();
                var originalPaths = ((string)input.originalPath ?? "").Split(',')
                                    .Select(p => p.Trim())
                                    .Where(p => !string.IsNullOrEmpty(p))
                                    .ToList();

                var fileList = files.Split(',')
                                    .Select(f => f.Trim())
                                    .Where(f => !string.IsNullOrEmpty(f))
                                    .ToList();

                if (fileList.Count != ocrResults.Count)
                {
                    return Json(new { success = false, message = "Mismatch between file count and OCR results count." });
                }

                for (int i = 0; i < fileList.Count; i++)
                {
                    string fileName = fileList[i];
                    string generatedOCR = ocrResults[i]?.ToString() ?? string.Empty;
                    generatedOCR = Regex.Unescape(generatedOCR);
                    generatedOCR = HttpUtility.HtmlDecode(generatedOCR);
                    string originalFilePath = originalPaths[i];

                    DataAccessADO.SaveOCRFileDetails(firmId, userId, jobId, fileName, generatedOCR, originalFilePath);
                }

                return Json(new { success = true });
            }
            catch (Exception ex)
            {
                return Json(new { success = false, message = ex.Message });
            }
        }



