        [HttpPost]
        [AuthLog(Roles = "Firm,User")]
        public JsonResult SendOcrEmail()
        {
            try
            {
                var json = new System.IO.StreamReader(Request.InputStream).ReadToEnd();
                dynamic data = Newtonsoft.Json.JsonConvert.DeserializeObject(json);

                string email = data?.To;
                string subjectline = data?.Subject;
                string userMessage = data?.Message;
                string base64Pdf = data?.AttachmentBase64;
                string attachmentFileName = data?.AttachmentFileName;

                if (string.IsNullOrEmpty(email) || string.IsNullOrEmpty(base64Pdf))
                    return Json(new { success = false, message = "Email or attachment missing." });

                string EmailId = WebConfigurationManager.AppSettings["OCRSenderEmail"];
                string regMailFromPassword = "";
                string server = WebConfigurationManager.AppSettings["EmailSMTP"];
                int port = Convert.ToInt32(WebConfigurationManager.AppSettings["EmailPort"]);

                string templateEncoded = WebConfigurationManager.AppSettings["OCREmailTemplate"].ToString();
                string template = System.Net.WebUtility.HtmlDecode(templateEncoded);

                string injectedMessage = $@"Greetings from Mykase!<br /><br />
                                            Please find the AI File Generated in PDF format with attachment.<br /><br />
                                            <strong>User Message:</strong><br />{System.Web.HttpUtility.HtmlEncode(userMessage)}<br /><br />";

                string targetToReplace = "Greetings from Mykase!<br /><br />Please find the OCR Generated in PDF format with attachment.<br /><br />";
                string finalMessage = template.Replace(targetToReplace, injectedMessage);

                System.Net.Mail.MailMessage mm = new System.Net.Mail.MailMessage();
                System.Net.Mail.MailAddress mailFromAddress = new System.Net.Mail.MailAddress(EmailId, EmailId);

                mm.To.Add(new System.Net.Mail.MailAddress(email));
                mm.From = mailFromAddress;
                mm.Subject = subjectline;
                mm.Body = finalMessage;
                mm.IsBodyHtml = true;

                byte[] pdfBytes = Convert.FromBase64String(base64Pdf);
                var pdfStream = new System.IO.MemoryStream(pdfBytes);
                System.Net.Mail.Attachment attachment = new System.Net.Mail.Attachment(pdfStream, attachmentFileName, "application/pdf");
                mm.Attachments.Add(attachment);

                System.Net.Mail.SmtpClient smtp = new System.Net.Mail.SmtpClient
                {
                    Host = server,
                    EnableSsl = false,
                    UseDefaultCredentials = false,
                    Credentials = new System.Net.NetworkCredential(EmailId, regMailFromPassword),
                    Port = port
                };

                smtp.Send(mm);
                pdfStream.Close();
                mm.Dispose();
                smtp.Dispose();

                return Json(new { success = true, message = "Email sent successfully." });
            }
            catch (Exception ex)
            {
                return Json(new { success = false, message = ex.Message });
            }
        }

