        //Insert OTP for Email change
        [HttpPost]
        [AuthLog(Roles = "Firm,User")]
        public JsonResult InsertOTPEmailVerify()
        {
            try
            {
                var json = new System.IO.StreamReader(Request.InputStream).ReadToEnd();
                dynamic data = Newtonsoft.Json.JsonConvert.DeserializeObject(json);

                var UserId = LoggedInUser.UserId.ToString();
                string otp = GenerateSafeOtp();
                int ValidMinutes = 15;
                string email = data?.To;
                string subjectline = "OTP For Email Change";
                string EmailId = WebConfigurationManager.AppSettings["OCRSenderEmail"];
                string regMailFromPassword = "";
                string server = WebConfigurationManager.AppSettings["EmailSMTP"];
                int port = Convert.ToInt32(WebConfigurationManager.AppSettings["EmailPort"]);

                string templateEncoded = WebConfigurationManager.AppSettings["EmailOTPTemplate"].ToString();
                templateEncoded = templateEncoded.Replace("{OTP}", otp).Replace("{ValidMinutes}", Convert.ToString(ValidMinutes));
                string template = System.Net.WebUtility.HtmlDecode(templateEncoded) ?? $"Your OTP is {otp}. It is valid for {ValidMinutes} minutes.";


                System.Net.Mail.MailMessage mm = new System.Net.Mail.MailMessage();
                System.Net.Mail.MailAddress mailFromAddress = new System.Net.Mail.MailAddress(EmailId, EmailId);

                mm.To.Add(new System.Net.Mail.MailAddress(email));
                mm.From = mailFromAddress;
                mm.Subject = subjectline;
                mm.Body = template;
                mm.IsBodyHtml = true;

                System.Net.Mail.SmtpClient smtp = new System.Net.Mail.SmtpClient
                {
                    Host = server,
                    EnableSsl = false,
                    UseDefaultCredentials = false,
                    Credentials = new System.Net.NetworkCredential(EmailId, regMailFromPassword),
                    Port = port
                };

                smtp.Send(mm);
                mm.Dispose();
                smtp.Dispose();

                DataAccessADO.usp_InsertPasswordResetToken(otp, UserId);

                return Json(new { success = true, message = "Email sent successfully." });
            }
            catch (Exception ex)
            {
                return Json(new { success = false, message = ex.Message });
            }
        }

        //Update isUsed Flag for Email OTP
        [HttpPost]
        [AuthLog(Roles = "Firm,User")]
        public JsonResult UpdateIsUsedOnOTPVerification()
        {
            try
            {
                var json = new System.IO.StreamReader(Request.InputStream).ReadToEnd();
                dynamic data = Newtonsoft.Json.JsonConvert.DeserializeObject(json);
                string otpByUser = data?.OTP;
                var UserId = LoggedInUser.UserId.ToString();
                var result = DataAccessADO.getOTPFromDB(UserId);

                DateTime resetMailTime = Convert.ToDateTime(result.ExpireTime);
                DateTime currentTime = DateTime.Now;

                double minutesDifference = (resetMailTime - currentTime).TotalMinutes;

                if (otpByUser == result.Token && minutesDifference < 15)
                {
                    DataAccessADO.sp_UpdateIsUsedFlag(UserId);
                    return Json(new { success = true, message = "OTP verified successfully." });
                }
                else
                {
                    return Json(new { success = false, message = "Incorrect OTP or OTP Expired." });
                }
            }
            catch (Exception ex)
            {
                return Json(new { success = false, message = ex.Message });
            }
        }

        //make private helper method for generate otp
        private static string GenerateSafeOtp()
        {
            // 6-digit, avoid trivial patterns
            string[] banned = { "000000", "111111", "222222", "333333", "444444", "555555", "666666", "777777", "888888", "999999", "123456", "654321" };

            using (var rng = new RNGCryptoServiceProvider())
            {
                while (true)
                {
                    byte[] bytes = new byte[4];
                    rng.GetBytes(bytes);
                    int randomNumber = Math.Abs(BitConverter.ToInt32(bytes, 0));
                    int otpInt = (randomNumber % 900000) + 100000; // ensures 6-digit number between 100000-999999
                    string otp = otpInt.ToString();

                    if (!banned.Contains(otp))
                        return otp;
                }
            }
        }
