        [AuthLog(Roles = "Firm,User")]
        [HttpPost]
        public async Task<string> UploadOrderFilesTranslation()
        {
            string apiUrl = "https://ordertranslation.mykase.in/api/translate";

            try
            {
                string fileUrl = Request.Form["filePath"];
                string lang = Request.Form["lang"] ?? "en";

                if (string.IsNullOrWhiteSpace(fileUrl))
                    return JsonConvert.SerializeObject(new { error = "File path missing." });

                ServicePointManager.SecurityProtocol = SecurityProtocolType.Tls12;

                using (var httpClient = new HttpClient())
                {
                    // ⏱ API takes ~120+ seconds
                    httpClient.Timeout = TimeSpan.FromMinutes(5);

                    // Download file from blob URL
                    var fileBytes = await httpClient.GetByteArrayAsync(fileUrl);

                    using (var form = new MultipartFormDataContent())
                    {
                        var fileContent = new ByteArrayContent(fileBytes);
                        fileContent.Headers.ContentType =
                            new System.Net.Http.Headers.MediaTypeHeaderValue("application/pdf");

                        string fileName = Path.GetFileName(fileUrl);
                        form.Add(fileContent, "file", fileName);

                        // language param
                        form.Add(new StringContent(lang), "sourceLang");

                        var response = await httpClient.PostAsync(apiUrl, form);
                        var responseText = await response.Content.ReadAsStringAsync();

                        if (string.IsNullOrWhiteSpace(responseText))
                        {
                            return JsonConvert.SerializeObject(new
                            {
                                error = "Empty response from translation API."
                            });
                        }

                        return responseText; // directly return API result JSON
                    }
                }
            }
            catch (TaskCanceledException)
            {
                return JsonConvert.SerializeObject(new
                {
                    error = "Translation request timed out. Please try again."
                });
            }
            catch (Exception ex)
            {
                return JsonConvert.SerializeObject(new
                {
                    error = ex.Message
                });
            }
        }


