        [HttpPost]
        [AuthLog(Roles = "Firm,User")]
        public async Task<string> AskQuestionFromFile()
        {
            string apiUrl = "https://testaskquestion.mykase.in/answer";

            try
            {
                // Read raw JSON body
                Request.InputStream.Position = 0;
                using (var reader = new StreamReader(Request.InputStream))
                {
                    var body = await reader.ReadToEndAsync();
                    var requestData = JsonConvert.DeserializeObject<JObject>(body);

                    string query = requestData?["query"]?.ToString() ?? "Summarize in 2 points?";
                    string sessionId = requestData?["session_id"]?.ToString() ?? "";

                    var fileUrlsToken = requestData?["file_urls"];
                    var fileUrls = fileUrlsToken != null
                        ? fileUrlsToken.ToObject<List<string>>()
                        : new List<string>();

                    if (fileUrls == null || fileUrls.Count == 0)
                        return JsonConvert.SerializeObject(new { error = "File URLs missing." });

                    ServicePointManager.SecurityProtocol = SecurityProtocolType.Tls12;

                    using (var httpClient = new HttpClient())
                    {
                        httpClient.Timeout = TimeSpan.FromMinutes(5);

                        var payload = new
                        {
                            query = query,
                            session_id = sessionId,
                            file_urls = fileUrls
                        };

                        var jsonContent = new StringContent(
                            JsonConvert.SerializeObject(payload),
                            Encoding.UTF8,
                            "application/json"
                        );

                        var response = await httpClient.PostAsync(apiUrl, jsonContent);
                        var responseText = await response.Content.ReadAsStringAsync();

                        if (string.IsNullOrWhiteSpace(responseText))
                        {
                            return JsonConvert.SerializeObject(new
                            {
                                error = "Empty response from API."
                            });
                        }

                        var jsonObj = JsonConvert.DeserializeObject<JObject>(responseText);
                        var answer = jsonObj?["answer"]?.ToString();

                        return JsonConvert.SerializeObject(new
                        {
                            answer = answer ?? "No answer returned."
                        });
                    }
                }
            }
            catch (TaskCanceledException)
            {
                return JsonConvert.SerializeObject(new
                {
                    error = "Request timed out. Please try again."
                });
            }
            catch (Exception ex)
            {
                return JsonConvert.SerializeObject(new
                {
                    error = ex.Message
                });
            }
        }

        public class DraftApiResponse
        {
            public string draft { get; set; }
            public string job_id { get; set; }
            public string parent_job_id { get; set; }
            public object[] templates_used { get; set; }
        }

        [HttpPost]
        [AuthLog(Roles = "Firm,User")]
        public async Task<ActionResult> GenerateDraft()
        {
            string apiUrl = System.Configuration.ConfigurationManager.AppSettings["DrafterAPIURL"];

            try
            {
                string apiKeys = System.Configuration.ConfigurationManager.AppSettings["DrafterAPIKeys"];
                string query = Request.Form["query"];
                string context = Request.Form["context"] ?? "";
                string job_id = Request.Form["job_id"] ?? "";
                string[] files = Request.Form.GetValues("files");

                if (string.IsNullOrWhiteSpace(query))
                {
                    return Json(new { success = false, message = "Query is required." }, JsonRequestBehavior.AllowGet);
                }

                // Determine type
                string type = "normal";
                if (!string.IsNullOrWhiteSpace(job_id))
                    type = "refine";
                else if (files != null && files.Length > 0)
                    type = "with_files";

                using (var client = new HttpClient())
                {
                    client.Timeout = TimeSpan.FromMinutes(5);

                    if (!string.IsNullOrWhiteSpace(apiKeys))
                    {
                        client.DefaultRequestHeaders.TryAddWithoutValidation("x-api-key", apiKeys);
                    }

                    using (var formData = new MultipartFormDataContent())
                    {
                        formData.Add(new StringContent(query), "query");
                        formData.Add(new StringContent(type), "type");
                        formData.Add(new StringContent(job_id ?? ""), "job_id");
                        formData.Add(new StringContent("5"), "top_k");
                        formData.Add(new StringContent("hybrid"), "search_mode");
                        formData.Add(new StringContent("0.5"), "alpha");
                        formData.Add(new StringContent(context), "context");

                        if (files != null && files.Length > 0)
                        {
                            foreach (var file in files)
                            {
                                formData.Add(new StringContent(file), "files");
                            }
                        }

                        var response = await client.PostAsync(apiUrl, formData);
                        var responseString = await response.Content.ReadAsStringAsync();

                        if (!response.IsSuccessStatusCode)
                        {
                            return Json(new
                            {
                                success = false,
                                message = "API Error",
                                details = responseString
                            }, JsonRequestBehavior.AllowGet);
                        }

                        // Deserialize response
                        var apiResult = Newtonsoft.Json.JsonConvert.DeserializeObject<DraftApiResponse>(responseString);

                        return Json(new
                        {
                            success = true,
                            draft = apiResult?.draft,
                            job_id = apiResult?.job_id,
                            parent_job_id = apiResult?.parent_job_id
                        }, JsonRequestBehavior.AllowGet);
                    }
                }
            }
            catch (TaskCanceledException)
            {
                return Json(new { success = false, message = "Request timed out." }, JsonRequestBehavior.AllowGet);
            }
            catch (Exception ex)
            {
                return Json(new { success = false, message = ex.Message }, JsonRequestBehavior.AllowGet);
            }
        }

