            }
            catch (Exception ex)
            {
                return Json(new { success = false, message = ex.Message }, JsonRequestBehavior.AllowGet);
            }
        }

        //Calculate no of pages in a pdf 
        [HttpPost]
        [AuthLog(Roles = "Firm,User")]
        public async Task<JsonResult> GetTotalPdfPages(List<string> urls)
        {
            try
            {
                if (urls == null || urls.Count == 0)
                {
                    return Json(new { success = true, totalPages = 0 }, JsonRequestBehavior.AllowGet);
                }

                var tasks = urls.Select(url => GetPageCountFromUrl(url));
                var results = await Task.WhenAll(tasks);

                int totalPages = results.Sum();

                return Json(new
                {
                    success = true,
                    totalPages = totalPages
                }, JsonRequestBehavior.AllowGet);
            }
            catch (Exception ex)
            {
                return Json(new
                {
                    success = false,
                    message = ex.Message
                }, JsonRequestBehavior.AllowGet);
            }
        }


        private static readonly HttpClient client = new HttpClient
        {
            Timeout = TimeSpan.FromSeconds(30)
        };

        private async Task<int> GetPageCountFromUrl(string url)
        {
            try
            {
                var bytes = await client.GetByteArrayAsync(url);

                using (var stream = new MemoryStream(bytes))
                using (var reader = new iTextSharp.text.pdf.PdfReader(stream))
                {
                    return reader.NumberOfPages;
                }
            }
            catch
            {
                return 0; // fail-safe
            }
        }

        public class OtherPartyWrapper
        {
            public bool Status { get; set; }
            public string Message { get; set; }
            public List<OtherParty> data { get; set; }
        }

        public class OtherParty
        {
            public int usercaseId { get; set; }
            public string Applicant { get; set; }
            public string Respondent { get; set; }
        }

        [HttpPost]
        [AuthLog(Roles = "Firm,User")]
        public JsonResult OtherPartyDetails(string caseid)
        {
            try
            {
                var apiUrl = ConfigurationManager.AppSettings["savetocasewatchurl"];
                var client = new WebClient();
                try
                {
                    caseid = QueryAES.DecryptAes(QueryAES.FromBase64StringWithReplace(caseid));
                }
                catch { }
                var payload = new
                {
                    Accesstoken = "internal",
                    UserId = LoggedInUser.UserName.ToString(),
                    CaseId = caseid
                };

                client.Headers.Add(HttpRequestHeader.ContentType, "application/json");

                string requestJson = JsonConvert.SerializeObject(payload);

                ServicePointManager.SecurityProtocol = SecurityProtocolType.Tls12;

                string resid = client.UploadString(
                    new Uri(apiUrl + "/API/Search/OtherPartyDetails"),
                    "POST",
                    requestJson
                );

                var parsed = JsonConvert.DeserializeObject<OtherPartyWrapper>(resid);

                var firstRecord = parsed?.data?.FirstOrDefault();
                try
                {
                    var db1 = new LawPracticeEntities();
                    var param = apiUrl + "FirmController=>OtherPartyDetails=>" + requestJson;

                    db1.usp_AddAudit(
                        Convert.ToInt32(EventType.Case),
                        Convert.ToInt32(Severity.High),
                        Convert.ToInt32(REQUEST_TYPE.API),
                        Convert.ToString(EventType.Case),
                        Convert.ToString(Severity.High),
                        Convert.ToString(REQUEST_TYPE.API),
                        Guid.Parse(Session["sessionuserid"].ToString()),
                        param,
                        myIP(),
                        GetMacAddress().ToString(),
                        0,
                        ""
                    );
                }
                catch
                {
                }
                return Json(new
                {
                    success = true,
                    data = new
                    {
                        usercaseId = firstRecord?.usercaseId,
                        applicant = firstRecord?.Applicant,
                        respondent = firstRecord?.Respondent
                    }
                }, JsonRequestBehavior.AllowGet);
            }
            catch (Exception ex)
            {
                return Json(new
                {
                    success = false,
                    message = ex.Message
                }, JsonRequestBehavior.AllowGet);
            }
        }

        /// <summary>
        /// Batch version of CaseDataCaseWatch - accepts multiple tokens and returns all ManualNextHearing values in one call
        /// </summary>
        [AuthLog(Roles = "Firm,User")]
        public JsonResult CaseDataCaseWatchBatch()
        {
            var results = new Dictionary<string, string>();
            var tokensJson = Request.Form["tokens"];
            if (string.IsNullOrEmpty(tokensJson))
                return Json(new { Results = results }, JsonRequestBehavior.AllowGet);

            var tokens = JsonConvert.DeserializeObject<List<string>>(tokensJson);
            if (tokens == null || tokens.Count == 0)
                return Json(new { Results = results }, JsonRequestBehavior.AllowGet);

            var apiUrl = ConfigurationManager.AppSettings["savetocasewatchurl"];
            var firmId = LoggedInUser.FirmId.ToString();
            var strusername = WebConfigurationManager.AppSettings["matteridname"];
            var isCaseWatchUser = LoggedInUser.IsCaseWatchUser.ToString();

            foreach (string token in tokens)
            {
                try
                {
                    string caseid = QueryAES.UrlDecode(token);
                    try { caseid = QueryAES.DecryptAes(QueryAES.FromBase64StringWithReplace(caseid)); } catch { }

                    string username = "";
                    using (var db = new LawPracticeEntities())
                    {
                        var userList = db.FindCaseUsername(Convert.ToInt32(caseid), firmId).ToList();
                        foreach (var u in userList) { username = strusername + u; }
                        var caseMap = db.Usp_GetCasewatchCaseMapDetails(firmId, caseid).FirstOrDefault();
                        if (caseMap != null && !string.IsNullOrEmpty(caseMap.UserId))
                            username = strusername + caseMap.UserId;
                    }

                    string accessToken = "mykase123456789abcdef";
                    string userId = username;
                    if (isCaseWatchUser == "1")
                    {
                        userId = LoggedInUser.UserName;
                        accessToken = "internal";
                    }

                    using (var client = new WebClient())
                    {
                        client.Headers.Add(HttpRequestHeader.ContentType, "application/json");
                        client.Encoding = System.Text.Encoding.UTF8;
                        var rawfile = new
                        {
                            accesstoken = accessToken,
                            userid = userId,
                            caseid = caseid,
                            Userrefid = strusername + LoggedInUser.UserId.ToString()
                        };
                        string requestJson = JsonConvert.SerializeObject(rawfile);
                        ServicePointManager.SecurityProtocol = SecurityProtocolType.Tls12;
                        string responseJson = client.UploadString(new Uri(apiUrl + "/API/Search/MykaseDetails"), "POST", requestJson);
                        dynamic data = JObject.Parse(responseJson);
                        results[token] = Convert.ToString(data.data[0].Manualnexthearing);
                    }
                }
                catch (Exception)
                {
                    results[token] = "";
                }
            }

            return Json(new { Results = results }, JsonRequestBehavior.AllowGet);
        }

        private CaseBenchDetails GetCaseBenchDetailFromApi(string caseid, string userId)
        {
            try
            {
                var apiUrl = ConfigurationManager
                    .AppSettings["savetocasewatchurl"];


                string username =
                    WebConfigurationManager.AppSettings["matteridname"]
                    + userId;


                object rawfile = new
                {
                    accesstoken = "mykase123456789abcdef",
                    userid = username,
                    caseid = caseid,
                    Userrefid =
                      WebConfigurationManager.AppSettings["matteridname"]
                      + LoggedInUser.UserId.ToString()
                };


                using (WebClient client = new WebClient())
                {

                    client.Headers.Add(
                        HttpRequestHeader.ContentType,
                        "application/json"
                    );


                    string json =
                        JsonConvert.SerializeObject(rawfile);


                    ServicePointManager.SecurityProtocol =
                        SecurityProtocolType.Tls12;


                    string response =
                        client.UploadString(
                            new Uri(apiUrl + "/API/Search/MykaseDetails"),
                            "POST",
                            json
                        );


                    dynamic data = JObject.Parse(response);


                    return new CaseBenchDetails
                    {
                        UserCaseId = caseid,

                        Bench_Name =
                            Convert.ToString(
                                data.data[0].Bench_Name
                            ),

                        Next_Hearing =
                            Convert.ToString(
                                data.data[0].Next_Hearing
                            ),

                        Manualnexthearing =
                            Convert.ToString(
                                data.data[0].Manualnexthearing
                            )
                    };
                }

            }
            catch (Exception ex)
            {
                return null;
            }
        }
    }

